-- ====================================================================
-- SMU PRO — Fix iPad: atualiza SÓ o HTML dos simuladores de mesa.
-- Coalescência de redraw (drawScreen/drawEQ = dirty-flag + rAF) para o fader/gate/
-- compressor não travarem no toque. NÃO altera curso/aula/quiz nem o campo `ativo`.
-- Idempotente: reaplicar apenas reescreve urls[].html. Aplicar via SQL Editor ou db push.
-- ====================================================================
begin;

-- som-formacao-completa (Yamaha CL5)  <-  simuladores/som/yamaha-cl5.html  (84.5 KB)
update public.ai_animations set urls = '[{"html":"<!doctype html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1, maximum-scale=1\">\n<title>Simulador — Console Digital CL5 (SMU)</title>\n<style>\n  :root{\n    --bg:#0b0f17; --panel:#121826; --panel2:#0e131f; --line:#223049;\n    --ink:#e7ecf5; --muted:#8ea0bd; --amber:#F59E0B; --amber2:#ffb638;\n    --green:#22c55e; --red:#ef4444; --blue:#3b82f6; --cyan:#22d3ee;\n    --track:#060a12; --strip:#0f1626;\n    --f:-inf;\n  }\n  *{box-sizing:border-box}\n  html,body{margin:0;height:100%}\n  body{\n    background:radial-gradient(1200px 600px at 50% -10%,#16203400,#0b0f17),var(--bg);\n    color:var(--ink);\n    font-family:\"Space Grotesk\",system-ui,-apple-system,\"Segoe UI\",Roboto,Inter,sans-serif;\n    -webkit-font-smoothing:antialiased; user-select:none; overflow:hidden;\n    display:flex; align-items:center; justify-content:center;\n  }\n  /* DESIGN FIXO + escala p/ caber (fit): o console inteiro cresce/encolhe proporcional */\n  .console{display:flex;flex-direction:column;width:1360px;height:672px;flex:0 0 auto;\n    padding:9px;gap:7px;transform-origin:top center}\n\n  /* ---------- HEADER ---------- */\n  .top{display:flex;align-items:center;flex-wrap:wrap;gap:8px 10px;background:linear-gradient(180deg,#141c2c,#0f1523);\n    border:1px solid var(--line);border-radius:10px;padding:8px 12px}\n  .brand{display:flex;align-items:baseline;gap:8px}\n  .brand b{font-size:16px;letter-spacing:.5px}\n  .brand .sub{font-size:10px;color:var(--muted);letter-spacing:1px;text-transform:uppercase}\n  .pill{display:flex;align-items:center;gap:6px;font-size:10.5px;color:var(--muted);\n    background:#0c1220;border:1px solid var(--line);border-radius:20px;padding:4px 9px;letter-spacing:.4px}\n  .dot{width:8px;height:8px;border-radius:50%;background:var(--green);box-shadow:0 0 8px var(--green)}\n  .dot.warn{background:var(--amber);box-shadow:0 0 8px var(--amber)}\n  .spacer{flex:1}\n  .mission{display:flex;align-items:center;gap:9px;background:#0c1220;border:1px solid var(--line);\n    border-radius:9px;padding:6px 11px;flex:1 1 260px;min-width:0;max-width:100%}\n  .mission .idx{font-size:10px;color:var(--amber);font-weight:700;letter-spacing:1px;white-space:nowrap}\n  .mission .txt{font-size:11.5px;color:var(--ink);line-height:1.25}\n  .mission .txt small{color:var(--muted)}\n  .mbtn{font:inherit;font-size:11px;color:#0b0f17;background:var(--amber);border:0;border-radius:7px;\n    padding:6px 10px;font-weight:700;cursor:pointer}\n  .mbtn.ghost{background:transparent;color:var(--muted);border:1px solid var(--line);font-weight:600}\n\n  /* ---------- MAIN ---------- */\n  .main{flex:1;display:grid;grid-template-columns:210px 1fr;gap:8px;min-height:0}\n  .card{background:linear-gradient(180deg,var(--panel),var(--panel2));border:1px solid var(--line);\n    border-radius:12px;padding:10px;min-height:0}\n  .card h3{margin:0 0 8px;font-size:10.5px;letter-spacing:1.4px;color:var(--muted);text-transform:uppercase;font-weight:700}\n  .card.selcol{overflow-y:auto}\n\n  /* Selected channel column */\n  .sel-head{display:flex;align-items:center;gap:8px;margin-bottom:4px}\n  .sel-chip{width:8px;height:26px;border-radius:3px;background:var(--amber)}\n  .sel-name{font-size:14px;font-weight:700;line-height:1}\n  .sel-num{font-size:10px;color:var(--muted)}\n  .knobs{display:grid;grid-template-columns:repeat(3,1fr);gap:3px 5px}\n  .knob{display:flex;flex-direction:column;align-items:center;gap:2px}\n  .knob .k-lbl{font-size:8.5px}.knob .k-val{font-size:10px}\n  .knob .dial{width:34px;height:34px;border-radius:50%;position:relative;cursor:ns-resize;touch-action:none;\n    background:radial-gradient(circle at 50% 35%,#2a3550,#141c2c 70%);border:1px solid #33456a;\n    box-shadow:inset 0 2px 6px #0008,0 1px 0 #ffffff0d}\n  .knob .dial::after{content:\"\";position:absolute;left:50%;top:5px;width:2.5px;height:14px;border-radius:2px;\n    background:var(--amber);transform-origin:50% 19px;transform:translateX(-50%) rotate(var(--rot,0deg))}\n  .knob .k-lbl{font-size:9px;color:var(--muted);letter-spacing:.5px;text-transform:uppercase}\n  .knob .k-val{font-size:10.5px;font-weight:700;color:var(--ink)}\n  .knob.small .dial{width:36px;height:36px}\n  .toggles{display:flex;gap:6px;margin-top:6px;flex-wrap:wrap}\n  .tg{flex:1;min-width:54px;font:inherit;font-size:10px;font-weight:700;letter-spacing:.5px;color:var(--muted);\n    background:#0c1220;border:1px solid var(--line);border-radius:7px;padding:7px 4px;cursor:pointer;text-align:center}\n  .tg.on{color:#0b0f17;background:var(--green);border-color:var(--green)}\n  .tg.on.amber{background:var(--amber);border-color:var(--amber)}\n\n  /* Screen column */\n  .screen-wrap{display:flex;flex-direction:column;min-height:0}\n  .screen-tabs{display:flex;gap:6px;margin-bottom:8px;flex-wrap:wrap}\n  .tab{font:inherit;font-size:11px;color:var(--muted);background:#0c1220;border:1px solid var(--line);\n    border-radius:7px;padding:6px 11px;cursor:pointer;letter-spacing:.4px}\n  .tab.active{color:#0b0f17;background:var(--amber);border-color:var(--amber);font-weight:700}\n  .screen-tabs .tab{padding:5px 8px;font-size:10.5px;letter-spacing:.2px}\n  .tab.sof.active{background:var(--cyan);border-color:var(--cyan)}\n  #screen{flex:1;width:100%;border-radius:10px;background:var(--track);border:1px solid #1b2740;display:block;min-height:150px;touch-action:none}\n\n  /* ---------- FADER BANK ---------- */\n  .bank{background:linear-gradient(180deg,#101725,#0b111c);border:1px solid var(--line);border-radius:12px;padding:8px}\n  .bank-top{display:flex;align-items:center;gap:6px;margin-bottom:7px;flex-wrap:wrap}\n  .bank-top .lbl{font-size:10px;color:var(--muted);letter-spacing:1.2px;text-transform:uppercase;margin-right:2px}\n  .strips{display:flex;gap:6px;align-items:stretch}\n  .strip{flex:1;background:var(--strip);border:1px solid #1b2740;border-radius:8px;padding:6px 5px;\n    display:flex;flex-direction:column;align-items:center;gap:5px;min-width:0}\n  .strip.sel{border-color:var(--amber);box-shadow:0 0 0 1px var(--amber) inset}\n  .cname{width:100%;border-radius:4px;color:#0b0f17;font-size:10px;font-weight:700;text-align:center;\n    padding:2px 0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;letter-spacing:.2px}\n  .cnum{font-size:8.5px;color:var(--muted);letter-spacing:.5px;margin-top:-2px}\n  .fader-area{display:flex;gap:5px;flex:1;width:100%;justify-content:center;min-height:92px}\n  .meter{width:7px;border-radius:3px;background:#05070d;position:relative;overflow:hidden;border:1px solid #1a2540}\n  .meter i{position:absolute;left:0;right:0;bottom:0;height:0%;background:linear-gradient(0deg,var(--green),var(--green) 60%,var(--amber) 82%,var(--red));transition:height .05s linear}\n  .fader{width:26px;flex:0 0 auto;position:relative;background:linear-gradient(90deg,#0a0e17,#0d1220,#0a0e17);\n    border-radius:5px;border:1px solid #1a2540;cursor:ns-resize;touch-action:none}\n  .fader .line{position:absolute;left:50%;top:6px;bottom:6px;width:2px;transform:translateX(-50%);\n    background:repeating-linear-gradient(#20304d,#20304d 2px,transparent 2px,transparent 8px)}\n  .fader .unity{position:absolute;left:0;right:0;height:1px;background:#33456a}\n  .cap{position:absolute;left:-3px;right:-3px;height:22px;border-radius:4px;cursor:grab;\n    background:linear-gradient(180deg,#e9edf5,#a7b3c9 46%,#59647e 54%,#8493ad);\n    border:1px solid #00000055;box-shadow:0 2px 5px #000a}\n  .cap::after{content:\"\";position:absolute;left:4px;right:4px;top:50%;height:2px;transform:translateY(-50%);\n    background:#0b0f17;border-radius:2px}\n  .db{font-size:9.5px;color:var(--ink);font-weight:700;letter-spacing:.3px}\n  .db small{color:var(--muted);font-weight:600}\n  .sbtns{display:flex;gap:4px;width:100%}\n  .sbtn{flex:1;font:inherit;font-size:9px;font-weight:700;letter-spacing:.4px;padding:4px 0;border-radius:5px;\n    cursor:pointer;background:#0c1220;border:1px solid var(--line);color:var(--muted);text-align:center}\n  .sbtn.sel.act{background:var(--amber);border-color:var(--amber);color:#0b0f17}\n  .sbtn.on.act{background:var(--green);border-color:var(--green);color:#0b0f17}\n  .sbtn.cue.act{background:var(--cyan);border-color:var(--cyan);color:#0b0f17}\n  .strip.master .cname{background:var(--amber)!important}\n  .divider{width:1px;background:var(--line);margin:0 2px}\n\n  .toast{position:fixed;left:50%;bottom:16px;transform:translateX(-50%) translateY(20px);\n    background:#0c1220;border:1px solid var(--amber);color:var(--ink);padding:10px 16px;border-radius:10px;\n    font-size:12.5px;opacity:0;transition:.25s;pointer-events:none;z-index:50;box-shadow:0 8px 30px #000a}\n  .toast.show{opacity:1;transform:translateX(-50%) translateY(0)}\n\n  /* iOS/iPad: trava o gesto de pan no console (menos no modo empilhado que rola) para o arraste\n     dos faders NÃO ser interpretado como \"deslizar para sair da tela cheia\". */\n  .console:not(.stacked){touch-action:none}\n  body:not(.stacked){touch-action:none}\n  /* ---------- FIT: escala p/ caber (tela cheia/tablet) e empilha (celular) ---------- */\n  .console.stacked{width:auto;min-width:0;height:auto;min-height:0;transform:none!important;max-width:680px;touch-action:auto}\n  .console.stacked .main{grid-template-columns:1fr;grid-auto-rows:auto}\n  .console.stacked .card.selcol{max-height:240px}\n  .console.stacked #screen{min-height:240px}\n  .console.stacked .knobs{grid-template-columns:repeat(4,1fr)}\n  .console.stacked .fader-area{min-height:150px}\n  body.stacked{align-items:flex-start;overflow:auto}\n  .toast b{color:var(--amber)}\n  .legend{font-size:9.5px;color:var(--muted);margin-top:6px;line-height:1.4}\n  @media (max-width:720px){\n    .main{grid-template-columns:1fr}\n    .card.selcol{display:none}\n  }\n</style>\n</head>\n<body>\n<div class=\"console\">\n\n  <!-- HEADER -->\n  <div class=\"top\">\n    <div class=\"brand\"><b>CL5</b><span class=\"sub\">Digital Console · Simulador SMU</span></div>\n    <div class=\"pill\"><span class=\"dot\" id=\"danteLed\"></span> DANTE <span id=\"danteTxt\">PRI</span></div>\n    <div class=\"pill\">48 kHz</div>\n    <div class=\"pill\" id=\"gcPill\" title=\"Gain Compensation\">GC <span style=\"color:var(--muted)\">off</span></div>\n    <button class=\"mbtn\" id=\"playBtn\" style=\"background:#22c55e;color:#04121a\">▶ Tocar base</button>\n    <select id=\"songSel\" class=\"pill\" style=\"cursor:pointer;background:#0c1220;color:var(--ink);border:1px solid var(--line);font:inherit;font-size:11px;max-width:190px\"></select>\n    <span class=\"pill\" id=\"audioStatus\" style=\"color:var(--muted)\">áudio: —</span>\n    <div class=\"spacer\"></div>\n    <div class=\"mission\">\n      <span class=\"idx\" id=\"mIdx\">MISSÃO 1/5</span>\n      <span class=\"txt\" id=\"mTxt\">—</span>\n      <button class=\"mbtn ghost\" id=\"mSkip\">Pular</button>\n    </div>\n  </div>\n\n  <!-- MAIN -->\n  <div class=\"main\">\n    <!-- SELECTED CHANNEL -->\n    <div class=\"card selcol\">\n      <h3>Selected Channel</h3>\n      <div class=\"sel-head\">\n        <div class=\"sel-chip\" id=\"selChip\"></div>\n        <div><div class=\"sel-name\" id=\"selName\">—</div><div class=\"sel-num\" id=\"selNum\">CH</div></div>\n      </div>\n      <div class=\"knobs\">\n        <div class=\"knob\" data-k=\"gain\"><div class=\"dial\"></div><div class=\"k-lbl\">Gain</div><div class=\"k-val\" id=\"vGain\">+0 dB</div></div>\n        <div class=\"knob\" data-k=\"hpf\"><div class=\"dial\"></div><div class=\"k-lbl\">HPF</div><div class=\"k-val\" id=\"vHpf\">80 Hz</div></div>\n        <div class=\"knob small\" data-k=\"eqLoG\"><div class=\"dial\"></div><div class=\"k-lbl\">LOW G</div><div class=\"k-val\" id=\"vLoG\">0.0</div></div>\n        <div class=\"knob small\" data-k=\"eqHiG\"><div class=\"dial\"></div><div class=\"k-lbl\">HIGH G</div><div class=\"k-val\" id=\"vHiG\">0.0</div></div>\n        <div class=\"knob small\" data-k=\"gate\"><div class=\"dial\"></div><div class=\"k-lbl\">Gate Thr</div><div class=\"k-val\" id=\"vGate\">-40</div></div>\n        <div class=\"knob small\" data-k=\"comp\"><div class=\"dial\"></div><div class=\"k-lbl\">Comp Thr</div><div class=\"k-val\" id=\"vComp\">-12</div></div>\n        <div class=\"knob small\" data-k=\"pan\"><div class=\"dial\"></div><div class=\"k-lbl\">Pan</div><div class=\"k-val\" id=\"vPan\">C</div></div>\n      </div>\n      <div class=\"toggles\">\n        <button class=\"tg\" id=\"tgHpf\">HPF</button>\n        <button class=\"tg\" id=\"tgGate\">GATE</button>\n        <button class=\"tg\" id=\"tgComp\">COMP</button>\n      </div>\n      <div class=\"legend\">Arraste os knobs (cima/baixo). No touchscreen, arraste as bolinhas do EQ.</div>\n    </div>\n\n    <!-- SCREEN -->\n    <div class=\"card screen-wrap\">\n      <div class=\"screen-tabs\">\n        <button class=\"tab active\" data-mode=\"overview\">Overview</button>\n        <button class=\"tab\" data-mode=\"selected\">Selected</button>\n        <button class=\"tab\" data-mode=\"eq\">EQ</button>\n        <button class=\"tab\" data-mode=\"gate\">Gate</button>\n        <button class=\"tab\" data-mode=\"comp\">Comp</button>\n        <button class=\"tab\" data-mode=\"sends\">Sends</button>\n        <button class=\"tab\" data-mode=\"dca\">DCA</button>\n        <button class=\"tab\" data-mode=\"fx\">FX</button>\n        <button class=\"tab\" data-mode=\"scenes\">Scenes</button>\n        <button class=\"tab\" data-mode=\"meter\">Meter</button>\n        <div class=\"spacer\"></div>\n        <button class=\"tab sof\" id=\"sofBtn\" title=\"Sends on Fader\">SENDS ON FADER: OFF</button>\n      </div>\n      <canvas id=\"screen\"></canvas>\n    </div>\n  </div>\n\n  <!-- FADER BANK -->\n  <div class=\"bank\">\n    <div class=\"bank-top\">\n      <span class=\"lbl\">Bank</span>\n      <button class=\"tab active\" data-bank=\"0\">IN 1-8</button>\n      <button class=\"tab\" data-bank=\"1\">IN 9-16</button>\n      <button class=\"tab\" data-bank=\"2\">IN 17-24</button>\n      <div class=\"spacer\"></div>\n      <span class=\"lbl\" id=\"sofLbl\" style=\"color:var(--cyan);display:none\">Faders = envio p/ <b id=\"sofMix\"></b></span>\n    </div>\n    <div class=\"strips\" id=\"strips\"></div>\n  </div>\n</div>\n<div class=\"toast\" id=\"toast\"></div>\n\n<script>\n\"use strict\";\n(function(){\n  // ---------------- MODEL ----------------\n  // 24 MIX buses (CL5 real). Os 8 primeiros têm nomes didáticos; o resto é genérico.\n  const MIX_NAMES = [\"MIX 1 Mon\",\"MIX 2 Mon\",\"MIX 3 IEM\",\"MIX 4 IEM\",\"MIX 5 FX\",\"MIX 6 FX\",\"MIX 7 Sub\",\"MIX 8 FB\",\n    \"MIX 9\",\"MIX 10\",\"MIX 11\",\"MIX 12\",\"MIX 13\",\"MIX 14\",\"MIX 15\",\"MIX 16\",\n    \"MIX 17\",\"MIX 18\",\"MIX 19\",\"MIX 20\",\"MIX 21\",\"MIX 22\",\"MIX 23\",\"MIX 24\"];\n  const N_MIX=24, N_DCA=16, N_MUTE=8, N_SCENE=10; // contagens reais (scenes: 300 no console, 10 slots no sim)\n  const COLORS = [\"#ef4444\",\"#f97316\",\"#f59e0b\",\"#eab308\",\"#22c55e\",\"#14b8a6\",\"#06b6d4\",\"#3b82f6\",\"#6366f1\",\"#a855f7\",\"#ec4899\",\"#f43f5e\"];\n  const NAMES = [\"Kick In\",\"Snare\",\"Hat\",\"Tom 1\",\"Tom 2\",\"OH L\",\"OH R\",\"Bass DI\",\n                 \"Gtr L\",\"Gtr R\",\"Keys L\",\"Keys R\",\"Lead Voc\",\"Voc 2\",\"Voc 3\",\"Coro\",\n                 \"Sax\",\"Trumpet\",\"Perc\",\"Playback L\",\"Playback R\",\"Amb L\",\"Amb R\",\"Talk\"];\n  // \"fonte\" bruta de cada canal em dBFS (o que chega no pré-amp antes do gain)\n  const RAWSRC = [-42,-40,-48,-44,-45,-47,-47,-38, -41,-41,-39,-39,-34,-40,-41,-43, -43,-44,-46,-36,-36,-52,-52,-30];\n\n  function mkChannel(i){\n    return {\n      i, name:NAMES[i]||(\"CH \"+(i+1)), color:COLORS[i%COLORS.length],\n      gain: 20 + ((i*7)%10) - 4,        // dB no head-amp (-62..+10 na régua; usável ~ -6..+40 didático)\n      hpfOn:false, hpf:80,\n      lpfOn:false, lpf:18000,\n      // EQ 4 bandas totalmente paramétrica: LOW / LO-MID / HI-MID / HIGH\n      // type: ''lowshelf''|''peaking''|''highshelf''  (LOW e HIGH podem virar shelf; mids sempre peaking)\n      eq:[ {type:''lowshelf'', f:120,  g:0, q:0.7},\n           {type:''peaking'',  f:500,  g:0, q:1.0},\n           {type:''peaking'',  f:2500, g:0, q:1.0},\n           {type:''highshelf'',f:8000, g:0, q:0.7} ],\n      eqType:''PRECISE'',                 // PRECISE/AGGRESSIVE/SMOOTH/LEGACY (afeta levemente a inclinação)\n      // Dynamics 1 = GATE\n      gateOn:false, gateThr:-40, gateRange:-60, gateAtk:1, gateHold:20, gateDecay:200,\n      // Dynamics 2 = COMPRESSOR\n      compOn:false, compThr:-12, compRatio:3, compAtk:20, compRel:150, compKnee:2, compGain:0,\n      pan:0,                            // -63..+63\n      fader:-4 - ((i*5)%8), on:true,    // fader dB perto do unity; on=unmuted\n      sends:new Array(N_MIX).fill(-90), sendOn:new Array(N_MIX).fill(false), sendPre:new Array(N_MIX).fill(false),\n      dca:new Array(N_DCA).fill(false), mute:new Array(N_MUTE).fill(false), // pertinência a grupos\n      fxRev:-90, fxDly:-90,             // envios para os racks de efeito (dB)\n      env:Math.random(), src:RAWSRC[i]||-42\n    };\n  }\n  const CH = Array.from({length:24}, (_,i)=>mkChannel(i));\n  const state = { sel:12, bank:0, mode:\"overview\", sof:-1, sofMix:0, master:-3, eqBand:3,\n    dcaGain:new Array(N_DCA).fill(0), dcaOn:new Array(N_DCA).fill(true),\n    muteActive:new Array(N_MUTE).fill(false),\n    fx:{ revMix:0.35, revSize:2.2, dlyTime:0.38, dlyFb:0.35, dlyMix:0.3 } };\n  const scenes = new Array(N_SCENE).fill(null); // snapshots de cena\n\n  // ---------------- HELPERS ----------------\n  const $ = s=>document.querySelector(s);\n  const clamp=(v,a,b)=>Math.max(a,Math.min(b,v));\n  const FMIN=-90, FMAX=10; // fader range (dB); -90 = -inf\n  function faderTxt(db){ return db<=FMIN? \"−∞\" : (db>0?\"+\":\"\")+db.toFixed(1); }\n  function panTxt(p){ if(Math.abs(p)<2) return \"C\"; return (p<0? \"L\"+Math.round(-p): \"R\"+Math.round(p)); }\n  // posição vertical 0..1 (baixo..cima) <-> dB\n  function pos2db(p){ if(p<=0.01) return FMIN; const d=-60+p*70; return clamp(d,FMIN,FMAX); }\n  function db2pos(db){ if(db<=FMIN) return 0; return clamp((db+60)/70,0,1); }\n\n  // ---------------- BUILD FADER STRIPS ----------------\n  const stripsEl = $(\"#strips\");\n  const stripEls = [];\n  function buildStrips(){\n    stripsEl.innerHTML=\"\";\n    stripEls.length=0;\n    for(let s=0;s<8;s++){\n      const st=document.createElement(\"div\"); st.className=\"strip\";\n      st.innerHTML=`\n        <div class=\"cname\"></div>\n        <div class=\"fader-area\">\n          <div class=\"meter\"><i></i></div>\n          <div class=\"fader\"><div class=\"line\"></div><div class=\"unity\"></div><div class=\"cap\"></div></div>\n        </div>\n        <div class=\"db\"></div>\n        <div class=\"sbtns\">\n          <button class=\"sbtn sel\">SEL</button>\n          <button class=\"sbtn cue\">CUE</button>\n          <button class=\"sbtn on\">ON</button>\n        </div>`;\n      stripsEl.appendChild(st);\n      const o={ root:st, name:st.querySelector(\".cname\"), meter:st.querySelector(\".meter i\"),\n        fader:st.querySelector(\".fader\"), cap:st.querySelector(\".cap\"), db:st.querySelector(\".db\"),\n        sel:st.querySelector(\".sbtn.sel\"), cue:st.querySelector(\".sbtn.cue\"), on:st.querySelector(\".sbtn.on\") };\n      stripEls.push(o);\n      wireFader(o,s);\n      o.sel.onclick=()=>{ selectChannel(state.bank*8+s); };\n      o.on.onclick=()=>{ const ch=chOf(s); if(state.sof>=0){ ch.sendOn[state.sofMix]=!ch.sendOn[state.sofMix]; } else { ch.on=!ch.on; } applyChanAudio(ch.i); paintStrips(); checkMissions(); };\n      o.cue.onclick=()=>{ o.cue.classList.toggle(\"act\"); };\n    }\n    // master strip\n    const divider=document.createElement(\"div\"); divider.className=\"divider\"; stripsEl.appendChild(divider);\n    const m=document.createElement(\"div\"); m.className=\"strip master\";\n    m.innerHTML=`<div class=\"cname\">ST MASTER</div>\n      <div class=\"fader-area\"><div class=\"meter\"><i></i></div><div class=\"meter\"><i></i></div>\n        <div class=\"fader\"><div class=\"line\"></div><div class=\"unity\"></div><div class=\"cap\"></div></div></div>\n      <div class=\"db\"></div><div class=\"sbtns\"><button class=\"sbtn on act\">ON</button></div>`;\n    stripsEl.appendChild(m);\n    masterEl={ root:m, cap:m.querySelector(\".cap\"), fader:m.querySelector(\".fader\"),\n      db:m.querySelector(\".db\"), meters:m.querySelectorAll(\".meter i\") };\n    wireMasterFader(masterEl);\n  }\n  let masterEl;\n  function chOf(slot){ return CH[state.bank*8+slot]; }\n\n  // fader drag — Pointer Events (mouse + toque unificados, com pointer capture)\n  function wireFader(o,slot){\n    let drag=false;\n    const rectDb=(clientY)=>{ const r=o.fader.getBoundingClientRect(); const p=1-(clientY-r.top)/r.height; return pos2db(p); };\n    const move=e=>{ if(!drag) return; const db=rectDb(e.clientY);\n      const ch=chOf(slot);\n      if(state.sof>=0){ ch.sends[state.sofMix]=db; if(db>FMIN) ch.sendOn[state.sofMix]=true; }\n      else { ch.fader=db; applyChanAudio(ch.i); }\n      paintStrips(); if(state.mode!==\"overview\") drawScreen(); checkMissions(); e.preventDefault(); };\n    o.fader.addEventListener(\"pointerdown\",e=>{ drag=true; o.cap.style.cursor=\"grabbing\"; o.fader.setPointerCapture(e.pointerId); move(e); e.preventDefault(); });\n    o.fader.addEventListener(\"pointermove\",move);\n    const up=()=>{ drag=false; o.cap.style.cursor=\"grab\"; };\n    o.fader.addEventListener(\"pointerup\",up); o.fader.addEventListener(\"pointercancel\",up);\n  }\n  function wireMasterFader(o){\n    let drag=false;\n    const move=e=>{ if(!drag)return; const r=o.fader.getBoundingClientRect(); state.master=pos2db(1-(e.clientY-r.top)/r.height); paintMaster(); applyMasterAudio(); e.preventDefault(); };\n    o.fader.addEventListener(\"pointerdown\",e=>{drag=true;o.fader.setPointerCapture(e.pointerId);move(e);e.preventDefault();});\n    o.fader.addEventListener(\"pointermove\",move);\n    const up=()=>drag=false;\n    o.fader.addEventListener(\"pointerup\",up); o.fader.addEventListener(\"pointercancel\",up);\n  }\n\n  function paintStrips(){\n    for(let s=0;s<8;s++){\n      const ch=chOf(s), o=stripEls[s];\n      o.name.textContent=ch.name; o.name.style.background=ch.color;\n      o.root.classList.toggle(\"sel\", state.sel===ch.i);\n      const inSof = state.sof>=0;\n      const val = inSof? ch.sends[state.sofMix] : ch.fader;\n      o.cap.style.bottom = \"calc(\"+(db2pos(val)*100)+\"% - 11px)\";\n      o.db.innerHTML = inSof\n        ? ''<small>→</small> ''+faderTxt(ch.sends[state.sofMix])\n        : faderTxt(ch.fader)+'' <small>dB</small>'';\n      o.sel.classList.toggle(\"act\", state.sel===ch.i);\n      const onState = inSof? ch.sendOn[state.sofMix] : ch.on;\n      o.on.classList.toggle(\"act\", onState);\n      o.on.textContent = inSof? \"SEND\":\"ON\";\n      o.fader.style.filter = inSof? \"hue-rotate(150deg) saturate(1.3)\":\"none\";\n    }\n    paintMaster();\n  }\n  function paintMaster(){ if(!masterEl) return; masterEl.cap.style.bottom=\"calc(\"+(db2pos(state.master)*100)+\"% - 11px)\";\n    masterEl.db.innerHTML=faderTxt(state.master)+'' <small>dB</small>''; }\n\n  // ---------------- SELECTED CHANNEL KNOBS ----------------\n  const KDEF={ gain:{min:-6,max:45}, hpf:{min:20,max:600,log:true}, eqLoG:{min:-18,max:18},\n    eqHiG:{min:-18,max:18}, gate:{min:-72,max:0}, comp:{min:-54,max:0}, pan:{min:-63,max:63} };\n  function knobVal(ch,k){ return {gain:ch.gain,hpf:ch.hpf,eqLoG:ch.eq[0].g,eqHiG:ch.eq[3].g,gate:ch.gateThr,comp:ch.compThr,pan:ch.pan}[k]; }\n  function knobSet(ch,k,v){ const d=KDEF[k]; v=clamp(v,d.min,d.max);\n    if(k===\"gain\")ch.gain=v; else if(k===\"hpf\")ch.hpf=Math.round(v); else if(k===\"eqLoG\")ch.eq[0].g=v;\n    else if(k===\"eqHiG\")ch.eq[3].g=v; else if(k===\"gate\")ch.gateThr=Math.round(v); else if(k===\"comp\")ch.compThr=Math.round(v);\n    else if(k===\"pan\")ch.pan=Math.round(v); }\n  function wireKnobs(){\n    document.querySelectorAll(\".knob\").forEach(el=>{\n      const k=el.dataset.k, dial=el.querySelector(\".dial\"); let drag=false,lastY=0;\n      dial.addEventListener(\"pointerdown\",e=>{drag=true;lastY=e.clientY;dial.setPointerCapture(e.pointerId);e.preventDefault();});\n      dial.addEventListener(\"pointermove\",e=>{ if(!drag)return; const dy=lastY-e.clientY; lastY=e.clientY;\n        const ch=CH[state.sel]; const d=KDEF[k]; const span=d.max-d.min; knobSet(ch,k,knobVal(ch,k)+dy*span/160);\n        applyChanAudio(state.sel); paintSelected(); drawScreen(); checkMissions(); e.preventDefault(); });\n      const up=()=>drag=false;\n      dial.addEventListener(\"pointerup\",up); dial.addEventListener(\"pointercancel\",up);\n    });\n    $(\"#tgHpf\").onclick=()=>{CH[state.sel].hpfOn=!CH[state.sel].hpfOn;applyChanAudio(state.sel);paintSelected();drawScreen();checkMissions();};\n    $(\"#tgGate\").onclick=()=>{CH[state.sel].gateOn=!CH[state.sel].gateOn;applyChanAudio(state.sel);paintSelected();drawScreen();checkMissions();};\n    $(\"#tgComp\").onclick=()=>{CH[state.sel].compOn=!CH[state.sel].compOn;applyChanAudio(state.sel);paintSelected();drawScreen();checkMissions();};\n  }\n  function rot(k,v){ const d=KDEF[k]; let t; if(d.log){ t=(Math.log(v)-Math.log(d.min))/(Math.log(d.max)-Math.log(d.min)); }\n    else t=(v-d.min)/(d.max-d.min); return (-140+ t*280); }\n  function paintSelected(){\n    const ch=CH[state.sel];\n    $(\"#selChip\").style.background=ch.color; $(\"#selName\").textContent=ch.name;\n    $(\"#selNum\").textContent=\"CH \"+(ch.i+1);\n    $(\"#vGain\").textContent=(ch.gain>0?\"+\":\"\")+ch.gain.toFixed(0)+\" dB\";\n    $(\"#vHpf\").textContent=ch.hpf+\" Hz\";\n    $(\"#vLoG\").textContent=(ch.eq[0].g>0?\"+\":\"\")+ch.eq[0].g.toFixed(1);\n    $(\"#vHiG\").textContent=(ch.eq[3].g>0?\"+\":\"\")+ch.eq[3].g.toFixed(1);\n    $(\"#vGate\").textContent=ch.gateThr; $(\"#vComp\").textContent=ch.compThr; $(\"#vPan\").textContent=panTxt(ch.pan);\n    const setRot=(k,v)=>{ const el=document.querySelector(''.knob[data-k=\"''+k+''\"] .dial''); if(el)el.style.setProperty(\"--rot\",rot(k,v)+\"deg\"); };\n    setRot(\"gain\",ch.gain);setRot(\"hpf\",ch.hpf);setRot(\"eqLoG\",ch.eq[0].g);setRot(\"eqHiG\",ch.eq[3].g);\n    setRot(\"gate\",ch.gateThr);setRot(\"comp\",ch.compThr);setRot(\"pan\",ch.pan);\n    $(\"#tgHpf\").classList.toggle(\"on\",ch.hpfOn); $(\"#tgHpf\").classList.toggle(\"amber\",ch.hpfOn);\n    $(\"#tgGate\").classList.toggle(\"on\",ch.gateOn); $(\"#tgComp\").classList.toggle(\"on\",ch.compOn);\n  }\n  function selectChannel(i){ state.sel=i; if(Math.floor(i/8)!==state.bank){} paintStrips(); paintSelected(); drawScreen(); checkMissions(); }\n\n  // ---------------- SCREEN (canvas) ----------------\n  const cv=$(\"#screen\"), ctx=cv.getContext(\"2d\");\n  let W=0,H=0,DPR=1;\n  function sizeCanvas(){ DPR=Math.min(2,window.devicePixelRatio||1); const r=cv.getBoundingClientRect();\n    W=r.width; H=r.height; cv.width=W*DPR; cv.height=H*DPR; ctx.setTransform(DPR,0,0,DPR,0,0); drawScreen(); }\n  // ---- Resposta de magnitude REAL de um biquad (RBJ cookbook) em dB ----\n  // Idêntica à curva que os BiquadFilterNode do Web Audio produzem -> gráfico = som.\n  const FS=48000;\n  function biquadDb(type,f0,gainDb,Q,f){\n    f0=clamp(f0,10,FS/2-10); Q=Math.max(0.05,Q);\n    const w0=2*Math.PI*f0/FS, cw=Math.cos(w0), sw=Math.sin(w0);\n    const A=Math.pow(10,gainDb/40), alpha=sw/(2*Q);\n    let b0,b1,b2,a0,a1,a2;\n    if(type===''peaking''){\n      b0=1+alpha*A; b1=-2*cw; b2=1-alpha*A; a0=1+alpha/A; a1=-2*cw; a2=1-alpha/A;\n    } else if(type===''lowshelf''){\n      const s2=2*Math.sqrt(A)*alpha;\n      b0=A*((A+1)-(A-1)*cw+s2); b1=2*A*((A-1)-(A+1)*cw); b2=A*((A+1)-(A-1)*cw-s2);\n      a0=(A+1)+(A-1)*cw+s2; a1=-2*((A-1)+(A+1)*cw); a2=(A+1)+(A-1)*cw-s2;\n    } else if(type===''highshelf''){\n      const s2=2*Math.sqrt(A)*alpha;\n      b0=A*((A+1)+(A-1)*cw+s2); b1=-2*A*((A-1)+(A+1)*cw); b2=A*((A+1)+(A-1)*cw-s2);\n      a0=(A+1)-(A-1)*cw+s2; a1=2*((A-1)-(A+1)*cw); a2=(A+1)-(A-1)*cw-s2;\n    } else if(type===''highpass''){\n      b0=(1+cw)/2; b1=-(1+cw); b2=(1+cw)/2; a0=1+alpha; a1=-2*cw; a2=1-alpha;\n    } else { // lowpass\n      b0=(1-cw)/2; b1=1-cw; b2=(1-cw)/2; a0=1+alpha; a1=-2*cw; a2=1-alpha;\n    }\n    const w=2*Math.PI*f/FS, phi=Math.pow(Math.sin(w/2),2);\n    const num=Math.pow(b0+b1+b2,2)-4*(b0*b1+4*b0*b2+b1*b2)*phi+16*b0*b2*phi*phi;\n    const den=Math.pow(a0+a1+a2,2)-4*(a0*a1+4*a0*a2+a1*a2)*phi+16*a0*a2*phi*phi;\n    return 10*Math.log10(Math.max(1e-9,num)/Math.max(1e-9,den));\n  }\n  // Fatores de \"caráter\" do tipo de EQ (afetam levemente a inclinação/Q)\n  function eqTypeFactor(t){ return t===''AGGRESSIVE''?1.55 : t===''SMOOTH''?0.6 : t===''LEGACY''?0.82 : 1; }\n  // EQ magnitude somada das 4 bandas + HPF + LPF\n  function eqMag(ch,f){\n    let g=0; const kf=eqTypeFactor(ch.eqType||''PRECISE'');\n    for(const b of ch.eq){ if(b.g!==0) g += biquadDb(b.type, b.f, b.g, b.q*kf, f); }\n    if(ch.hpfOn) g += biquadDb(''highpass'', ch.hpf, 0, 0.707, f);\n    if(ch.lpfOn) g += biquadDb(''lowpass'', ch.lpf, 0, 0.707, f);\n    return clamp(g,-30,20);\n  }\n  // Sistema de regiões clicáveis/arrastáveis desenhadas no canvas (touch + mouse)\n  let hitRegions=[], activeRegion=null;\n  function reg(o){ hitRegions.push(o); return o; }\n  function inRegion(r,p){ if(r.hit===''circle'') return Math.hypot(p.x-r.cx,p.y-r.cy)<=(r.rr||12);\n    return p.x>=r.x&&p.x<=r.x+r.w&&p.y>=r.y&&p.y<=r.y+r.h; }\n  const eqHandles=[]; // hit-test de EQ na aba Selected (compat)\n  // Redraw coalescing (iPad): a fader/knob drag fires many pointermove events; each must NOT\n  // trigger a synchronous full-canvas repaint (that starves the main thread on iPad, making\n  // faders lag and jump so the sound seems to cut instead of ride smoothly). drawScreen() now\n  // just flags \"dirty\" and repaints at most once per animation frame; a setTimeout safety-net\n  // guarantees a repaint even if requestAnimationFrame is throttled.\n  let _drawReq=0,_drawTo=0;\n  function _flushDraw(){ if(_drawReq){cancelAnimationFrame(_drawReq);_drawReq=0;} if(_drawTo){clearTimeout(_drawTo);_drawTo=0;} renderScreen(); }\n  function drawScreen(){ if(_drawReq||_drawTo)return; _drawReq=requestAnimationFrame(_flushDraw); _drawTo=setTimeout(_flushDraw,60); }\n  function renderScreen(){\n    if(!W) return;\n    hitRegions=[]; eqHandles.length=0;\n    ctx.clearRect(0,0,W,H);\n    switch(state.mode){\n      case \"overview\": drawOverview(); break;\n      case \"selected\": drawSelected(); break;\n      case \"eq\":     drawEQ(); break;\n      case \"gate\":   drawGate(); break;\n      case \"comp\":   drawComp(); break;\n      case \"sends\":  drawSends(); break;\n      case \"dca\":    drawDCA(); break;\n      case \"fx\":     drawFX(); break;\n      case \"scenes\": drawScenes(); break;\n      case \"meter\":  drawMeter(); break;\n      default: drawOverview();\n    }\n  }\n  function fx(f){ // freq (20..20k log) -> x (0..1)\n    const min=Math.log10(20),max=Math.log10(20000);\n    return (Math.log10(f)-min)/(max-min);\n  }\n  function fInv(t){ // x (0..1) -> freq (20..20k log)\n    const min=Math.log10(20),max=Math.log10(20000);\n    return Math.pow(10, min+clamp(t,0,1)*(max-min));\n  }\n  function drawOverview(){\n    const n=8, pad=8, gw=(W-pad*2)/n;\n    for(let s=0;s<n;s++){\n      const ch=chOf(s), x=pad+s*gw, y=6, w=gw-6, h=H-12;\n      const cx=x+6, cw=w-12;\n      const inDb=(playing&&ch.hasAudio)? chLevelDb(ch.i) : ch.src+ch.gain;\n      // corpo do strip\n      ctx.fillStyle=\"#0e1626\"; roundRect(x,y,w,h,8); ctx.fill();\n      ctx.strokeStyle=\"#1b2740\"; ctx.lineWidth=1; roundRect(x,y,w,h,8); ctx.stroke();\n      // cabeçalho colorido (nome + nº do canal)\n      ctx.fillStyle=ch.color; roundRect(x,y,w,18,8); ctx.fill(); ctx.fillRect(x,y+10,w,8);\n      ctx.fillStyle=\"#07101d\"; ctx.font=\"800 10px system-ui\"; ctx.textAlign=\"center\";\n      ctx.fillText(ch.name.slice(0,12), x+w/2, y+13);\n      ctx.textAlign=\"left\"; ctx.font=\"800 7.5px system-ui\"; ctx.fillText(\"CH\"+(ch.i+1), x+5, y+12.5);\n\n      // --- MINIATURA DE EQ (curva real) ---\n      const eqY0=y+24, eqH=52;\n      ctx.fillStyle=\"#08101d\"; roundRect(cx,eqY0,cw,eqH,5); ctx.fill();\n      ctx.strokeStyle=\"#1a2842\"; roundRect(cx,eqY0,cw,eqH,5); ctx.stroke();\n      const midE=eqY0+eqH*0.5;\n      ctx.strokeStyle=\"#213050\"; ctx.lineWidth=1; ctx.beginPath();ctx.moveTo(cx,midE);ctx.lineTo(cx+cw,midE);ctx.stroke();\n      const eqPy=px=>{const t=px/cw,f=Math.pow(10,Math.log10(20)+t*(Math.log10(20000)-Math.log10(20)));return clamp(midE - clamp(eqMag(ch,f)/18,-1,1)*(eqH*0.40), eqY0+3, eqY0+eqH-3);};\n      ctx.beginPath();ctx.moveTo(cx,eqY0+eqH);\n      for(let px=0;px<=cw;px+=2)ctx.lineTo(cx+px,eqPy(px));\n      ctx.lineTo(cx+cw,eqY0+eqH);ctx.closePath();\n      ctx.fillStyle=ch.color+\"2e\";ctx.fill();\n      ctx.beginPath();for(let px=0;px<=cw;px+=2){const yy=eqPy(px);px===0?ctx.moveTo(cx,yy):ctx.lineTo(cx+px,yy);}\n      ctx.strokeStyle=ch.color;ctx.lineWidth=1.6;ctx.stroke();\n      ctx.fillStyle=\"#5f6f8c\";ctx.font=\"700 7px system-ui\";ctx.textAlign=\"left\";ctx.fillText(\"EQ\",cx+4,eqY0+9);\n\n      // --- linha GATE / COMP ---\n      let dy=eqY0+eqH+9;\n      const gOpen = !ch.gateOn || inDb>ch.gateThr;\n      ctx.fillStyle=ch.gateOn?(gOpen?\"#22c55e\":\"#ef4444\"):\"#26344f\"; ctx.beginPath();ctx.arc(cx+5,dy,3.5,0,7);ctx.fill();\n      ctx.fillStyle=ch.gateOn?\"#c3cfe2\":\"#556685\";ctx.font=\"700 8px system-ui\";ctx.textAlign=\"left\";ctx.fillText(\"GATE\",cx+12,dy+3);\n      ctx.fillStyle=ch.compOn?\"#22d3ee\":\"#26344f\"; ctx.beginPath();ctx.arc(cx+cw*0.54,dy,3.5,0,7);ctx.fill();\n      ctx.fillStyle=ch.compOn?\"#c3cfe2\":\"#556685\";ctx.fillText(\"COMP\",cx+cw*0.54+7,dy+3);\n\n      // --- linha HPF + PAN ---\n      dy+=15;\n      ctx.fillStyle=ch.hpfOn?\"#f59e0b\":\"#41527a\";ctx.font=\"700 8px system-ui\";ctx.textAlign=\"left\";ctx.fillText(ch.hpfOn?(\"HPF \"+ch.hpf):\"HPF —\",cx,dy+3);\n      const pbw=cw*0.46, pbx=cx+cw-pbw, pby=dy;\n      ctx.fillStyle=\"#0c1626\";ctx.fillRect(pbx,pby-2,pbw,4);\n      ctx.fillStyle=\"#33456a\";ctx.fillRect(pbx+pbw/2-0.5,pby-4,1,8);\n      const pnorm=clamp((ch.pan+63)/126,0,1);\n      ctx.fillStyle=ch.color;ctx.beginPath();ctx.arc(pbx+pnorm*pbw,pby,3,0,7);ctx.fill();\n\n      // --- ZONA FADER + VU (dominante) ---\n      const fzTop=dy+14, fzBot=y+h-30;\n      const railX=cx+cw*0.32;\n      // trilho\n      ctx.fillStyle=\"#0a1220\";roundRect(railX-4,fzTop,8,fzBot-fzTop,4);ctx.fill();\n      ctx.strokeStyle=\"#22314d\";roundRect(railX-4,fzTop,8,fzBot-fzTop,4);ctx.stroke();\n      // escala em dB\n      [[10,\"+10\"],[0,\"0\"],[-10,\"-10\"],[-20,\"-20\"],[-40,\"-40\"],[-90,\"-∞\"]].forEach(m=>{\n        const yy=fzBot-db2pos(m[0])*(fzBot-fzTop);\n        ctx.strokeStyle=\"#2a3a58\";ctx.beginPath();ctx.moveTo(railX-8,yy);ctx.lineTo(railX-5,yy);ctx.stroke();\n        ctx.fillStyle=\"#54658a\";ctx.font=\"7px system-ui\";ctx.textAlign=\"right\";ctx.fillText(m[1],railX-9,yy+2.4);\n      });\n      // linha de unity (0 dB) destacada\n      const uY=fzBot-db2pos(0)*(fzBot-fzTop);\n      ctx.strokeStyle=\"#3a4a66\";ctx.setLineDash([3,3]);ctx.beginPath();ctx.moveTo(railX-4,uY);ctx.lineTo(railX+cw*0.30+9,uY);ctx.stroke();ctx.setLineDash([]);\n      // cursor do fader\n      const fp=db2pos(ch.fader), capY=fzBot-fp*(fzBot-fzTop), capW=cw*0.50, capX=railX-capW/2;\n      ctx.fillStyle=ch.on?\"#1f2c46\":\"#161d2c\";roundRect(capX,capY-9,capW,18,3);ctx.fill();\n      ctx.strokeStyle=ch.on?ch.color:\"#3a465e\";ctx.lineWidth=1.5;roundRect(capX,capY-9,capW,18,3);ctx.stroke();\n      ctx.fillStyle=ch.on?\"#e7ecf5\":\"#5a6b88\";ctx.fillRect(capX+2,capY-1,capW-4,2);\n      // VU meter à direita do fader\n      const mX=railX+cw*0.30, mW=9;\n      drawVMeter(mX,fzTop,mW,fzBot-fzTop,inDb);\n      ctx.fillStyle=\"#6b7a95\";ctx.font=\"700 7px system-ui\";ctx.textAlign=\"center\";ctx.fillText(\"IN\",mX+mW/2,fzBot+9);\n\n      // --- rodapé: valor do fader + gain ---\n      ctx.textAlign=\"left\";ctx.fillStyle=\"#dbe4f2\";ctx.font=\"800 11px system-ui\";\n      ctx.fillText(faderTxt(ch.fader), cx, y+h-9);\n      ctx.fillStyle=\"#7c8cab\";ctx.font=\"700 8px system-ui\";ctx.fillText(\"dB\", cx+ctx.measureText(faderTxt(ch.fader)).width+15, y+h-9);\n      ctx.textAlign=\"right\";ctx.fillStyle=ch.gain>=0?\"#8ea0bd\":\"#8ea0bd\";ctx.font=\"700 9px system-ui\";\n      ctx.fillText(\"G\"+(ch.gain>0?\"+\":\"\")+ch.gain, cx+cw, y+h-9);\n      // mute overlay\n      if(!ch.on){ ctx.fillStyle=\"rgba(20,6,10,0.55)\"; roundRect(x,y,w,h,8); ctx.fill();\n        ctx.fillStyle=\"#ef4444\";ctx.font=\"800 12px system-ui\";ctx.textAlign=\"center\";ctx.fillText(\"MUTE\",x+w/2,y+h/2); }\n      // seleção\n      if(ch.i===state.sel){ ctx.strokeStyle=\"#f59e0b\"; ctx.lineWidth=2.5; roundRect(x,y,w,h,8); ctx.stroke(); }\n    }\n  }\n  function drawVMeter(x,y,w,h,dbfs){\n    ctx.fillStyle=\"#05070d\"; ctx.fillRect(x,y,w,h);\n    const t=clamp((dbfs+60)/60,0,1); const hh=h*t;\n    const grad=ctx.createLinearGradient(0,y+h,0,y);\n    grad.addColorStop(0,\"#22c55e\");grad.addColorStop(0.7,\"#22c55e\");grad.addColorStop(0.86,\"#f59e0b\");grad.addColorStop(1,\"#ef4444\");\n    ctx.fillStyle=grad; ctx.fillRect(x,y+h-hh,w,hh);\n    // -18 target line\n    const ty=y+h-h*((-18+60)/60); ctx.strokeStyle=\"#ffffff55\"; ctx.beginPath();ctx.moveTo(x,ty);ctx.lineTo(x+w,ty);ctx.stroke();\n  }\n  function drawSelected(){\n    const ch=CH[state.sel];\n    // EQ graph\n    const gx=10, gy=10, gw=W*0.62-20, gh=H*0.62;\n    ctx.fillStyle=\"#0a1018\"; roundRect(gx,gy,gw,gh,8); ctx.fill();\n    // grid\n    ctx.strokeStyle=\"#182339\"; ctx.lineWidth=1; ctx.font=\"9px system-ui\"; ctx.fillStyle=\"#4a5a78\"; ctx.textAlign=\"center\";\n    [30,100,300,1000,3000,10000].forEach(f=>{ const x=gx+fx(f)*gw; ctx.beginPath();ctx.moveTo(x,gy);ctx.lineTo(x,gy+gh);ctx.stroke();\n      ctx.fillText(f>=1000?(f/1000)+\"k\":f, x, gy+gh+11); });\n    for(let d=-18;d<=18;d+=6){ const y=gy+gh/2-d/24*gh/2; ctx.strokeStyle=d===0?\"#2a3a58\":\"#141e30\"; ctx.beginPath();ctx.moveTo(gx,y);ctx.lineTo(gx+gw,y);ctx.stroke();\n      ctx.fillStyle=\"#4a5a78\";ctx.textAlign=\"left\";ctx.fillText((d>0?\"+\":\"\")+d,gx+2,y-2);}\n    // curve\n    ctx.beginPath();\n    for(let px=0;px<=gw;px+=2){ const t=px/gw; const f=Math.pow(10,Math.log10(20)+t*(Math.log10(20000)-Math.log10(20)));\n      const g=eqMag(ch,f); const y=gy+gh/2-g/24*gh/2; if(px===0)ctx.moveTo(gx+px,y);else ctx.lineTo(gx+px,y); }\n    ctx.strokeStyle=ch.color; ctx.lineWidth=2.4; ctx.stroke();\n    ctx.lineTo(gx+gw,gy+gh/2);ctx.lineTo(gx,gy+gh/2);ctx.closePath();\n    ctx.fillStyle=ch.color+\"18\"; ctx.fill();\n    // handles das 4 bandas (arrastáveis: X=freq, Y=gain) + HPF\n    const bandCols=[\"#22c55e\",\"#eab308\",\"#f97316\",\"#3b82f6\"], bandLbl=[\"L\",\"LM\",\"HM\",\"H\"];\n    ch.eq.forEach((b,bi)=>{ const x=gx+fx(b.f)*gw, y=gy+gh/2-b.g/24*gh/2;\n      ctx.fillStyle=bandCols[bi]; ctx.beginPath();ctx.arc(x,y,7,0,7); ctx.fill();\n      ctx.fillStyle=\"#0b0f17\";ctx.font=\"700 8px system-ui\";ctx.textAlign=\"center\";ctx.fillText(bandLbl[bi],x,y+3);\n      reg({hit:''circle'',cx:x,cy:y,rr:14,\n        onDown:()=>{ state.eqBand=bi; },\n        onDrag:p=>{ const t=clamp((p.x-gx)/gw,0,1); b.f=clamp(Math.round(fInv(t)),20,20000);\n          b.g=clamp(-(p.y-gy-gh/2)/(gh/2)*24,-18,18); applyChanAudio(ch.i); paintSelected(); checkMissions(); } });\n    });\n    if(ch.hpfOn){ const x=gx+fx(ch.hpf)*gw, y=gy+gh/2;\n      ctx.fillStyle=\"#f59e0b\"; ctx.beginPath();ctx.arc(x,y,7,0,7); ctx.fill();\n      ctx.fillStyle=\"#0b0f17\";ctx.font=\"700 8px system-ui\";ctx.textAlign=\"center\";ctx.fillText(\"H\",x,y+3);\n      reg({hit:''circle'',cx:x,cy:y,rr:14,onDrag:p=>{ const t=clamp((p.x-gx)/gw,0,1);\n        ch.hpf=clamp(Math.round(fInv(t)),20,600); applyChanAudio(ch.i); paintSelected(); checkMissions(); } }); }\n\n    // right column: gate/comp + sends\n    const rx=W*0.64, rw=W-rx-10;\n    // dynamics\n    ctx.fillStyle=\"#0a1018\"; roundRect(rx,10,rw,gh*0.5,8); ctx.fill();\n    ctx.fillStyle=\"#8ea0bd\";ctx.font=\"700 10px system-ui\";ctx.textAlign=\"left\";ctx.fillText(\"DYNAMICS\",rx+8,26);\n    const inDb=ch.src+ch.gain+ (Math.sin(perf()/300+ch.i)*4);\n    let gr=0; if(ch.compOn && inDb>ch.compThr){ gr=(inDb-ch.compThr)*(1-1/ch.compRatio); }\n    ctx.fillStyle=\"#4a5a78\";ctx.font=\"9px system-ui\";\n    ctx.fillText(\"GR (comp)\",rx+8,44); ctx.fillText(\"Gate\",rx+8,44+30);\n    // GR bar\n    ctx.fillStyle=\"#05070d\";ctx.fillRect(rx+70,36,rw-80,10);\n    ctx.fillStyle=\"#22d3ee\";ctx.fillRect(rx+70,36,clamp(gr/18,0,1)*(rw-80),10);\n    // gate led\n    const open = !ch.gateOn || inDb>ch.gateThr;\n    ctx.fillStyle=open?\"#22c55e\":\"#ef4444\"; ctx.beginPath();ctx.arc(rx+80,44+26,6,0,7);ctx.fill();\n    ctx.fillStyle=\"#8ea0bd\";ctx.fillText(open?\"OPEN\":\"CLOSED\",rx+94,44+30);\n    // sends grid\n    const sy=10+gh*0.5+10;\n    ctx.fillStyle=\"#0a1018\"; roundRect(rx,sy,rw,gh-gh*0.5-10,8); ctx.fill();\n    ctx.fillStyle=\"#8ea0bd\";ctx.font=\"700 10px system-ui\";ctx.fillText(\"SENDS → MIX\",rx+8,sy+16);\n    for(let m=0;m<8;m++){ const yy=sy+24+m*Math.max(14,(gh-gh*0.5-44)/8);\n      const on=ch.sendOn[m]; ctx.fillStyle=on?\"#22d3ee\":\"#2a3a58\"; ctx.beginPath();ctx.arc(rx+14,yy,4,0,7);ctx.fill();\n      ctx.fillStyle=on?\"#e7ecf5\":\"#5a6b88\";ctx.font=\"9px system-ui\";ctx.textAlign=\"left\";\n      ctx.fillText(MIX_NAMES[m].split(\" \").slice(0,2).join(\" \"),rx+24,yy+3);\n      ctx.textAlign=\"right\";ctx.fillText(on?faderTxt(ch.sends[m]):\"—\",rx+rw-8,yy+3); }\n    // meter under EQ\n    drawVMeter(gx+gw+6,gy,10,gh, ch.src+ch.gain);\n    // fader value badge\n    ctx.textAlign=\"left\";ctx.fillStyle=\"#8ea0bd\";ctx.font=\"600 10px system-ui\";\n    ctx.fillText(\"Fader \"+faderTxt(ch.fader)+\" dB   ·   \"+(ch.on?\"ON\":\"MUTE\"), gx, gy+gh+26);\n  }\n  function roundRect(x,y,w,h,r){ ctx.beginPath();ctx.moveTo(x+r,y);ctx.arcTo(x+w,y,x+w,y+h,r);ctx.arcTo(x+w,y+h,x,y+h,r);\n    ctx.arcTo(x,y+h,x,y,r);ctx.arcTo(x,y,x+w,y,r);ctx.closePath(); }\n\n  // ================= PRIMITIVAS DE UI NO CANVAS (touch + mouse via reg()) =================\n  function uiPanel(x,y,w,h,title){\n    ctx.fillStyle=\"#0a1018\"; roundRect(x,y,w,h,8);ctx.fill();\n    ctx.strokeStyle=\"#182339\"; ctx.lineWidth=1; roundRect(x,y,w,h,8);ctx.stroke();\n    if(title){ ctx.fillStyle=\"#8ea0bd\"; ctx.font=\"700 10px system-ui\"; ctx.textAlign=\"left\"; ctx.fillText(title,x+10,y+15); }\n  }\n  function uiBtn(x,y,w,h,label,active,onClick,col){\n    col=col||\"#f59e0b\";\n    ctx.fillStyle=active?col:\"#0c1220\"; roundRect(x,y,w,h,6);ctx.fill();\n    ctx.strokeStyle=active?col:\"#22314d\"; ctx.lineWidth=1; roundRect(x,y,w,h,6);ctx.stroke();\n    ctx.fillStyle=active?\"#0b0f17\":\"#9fb0cd\"; ctx.font=\"700 10px system-ui\"; ctx.textAlign=\"center\"; ctx.textBaseline=\"middle\";\n    ctx.fillText(label,x+w/2,y+h/2+0.5); ctx.textBaseline=\"alphabetic\";\n    reg({x,y,w,h,onDown:()=>{ onClick(); }});\n  }\n  // Controle deslizante horizontal genérico (arrastável). opts:{log,step,col}\n  function uiParam(x,y,w,label,val,min,max,fmt,onSet,opts){\n    opts=opts||{};\n    if(label){ ctx.fillStyle=\"#8ea0bd\";ctx.font=\"700 10px system-ui\";ctx.textAlign=\"left\";ctx.fillText(label,x,y-4); }\n    ctx.textAlign=\"right\";ctx.fillStyle=\"#e7ecf5\";ctx.font=\"800 11px system-ui\";ctx.fillText(fmt(val),x+w,y-4);\n    const th=8;\n    ctx.fillStyle=\"#0a1220\";roundRect(x,y,w,th,4);ctx.fill();\n    ctx.strokeStyle=\"#22314d\";ctx.lineWidth=1;roundRect(x,y,w,th,4);ctx.stroke();\n    let t = opts.log? Math.log(Math.max(min,val)/min)/Math.log(max/min) : (val-min)/(max-min);\n    t=clamp(t,0,1); const hx=x+t*w;\n    ctx.fillStyle=opts.col||\"#f59e0b\";roundRect(x,y,t*w,th,4);ctx.fill();\n    ctx.fillStyle=\"#e7ecf5\";ctx.beginPath();ctx.arc(hx,y+th/2,6,0,7);ctx.fill();\n    reg({x:x-4,y:y-10,w:w+8,h:th+20, onDrag:p=>{ let tt=clamp((p.x-x)/w,0,1);\n      let v = opts.log? min*Math.pow(max/min,tt) : min+tt*(max-min);\n      if(opts.step) v=Math.round(v/opts.step)*opts.step;\n      onSet(clamp(v,min,max)); } });\n  }\n\n  // ================= PÁGINA: EQ (4 bandas paramétricas) =================\n  function drawEQ(){\n    const ch=CH[state.sel];\n    const gx=10, gy=10, gw=W*0.60-14, gh=H-20;\n    uiPanel(gx,gy,gw,gh,null);\n    ctx.save(); roundRect(gx,gy,gw,gh,8);ctx.clip();\n    ctx.font=\"9px system-ui\"; ctx.textAlign=\"center\";\n    [30,100,300,1000,3000,10000].forEach(f=>{ const x=gx+fx(f)*gw; ctx.strokeStyle=\"#152034\";ctx.beginPath();ctx.moveTo(x,gy);ctx.lineTo(x,gy+gh);ctx.stroke();\n      ctx.fillStyle=\"#4a5a78\";ctx.fillText(f>=1000?(f/1000)+\"k\":f,x,gy+gh-4); });\n    for(let d=-18;d<=18;d+=6){ const y=gy+gh/2-d/24*gh/2; ctx.strokeStyle=d===0?\"#2a3a58\":\"#141e30\";ctx.beginPath();ctx.moveTo(gx,y);ctx.lineTo(gx+gw,y);ctx.stroke();\n      ctx.fillStyle=\"#4a5a78\";ctx.textAlign=\"left\";ctx.fillText((d>0?\"+\":\"\")+d,gx+3,y-2);ctx.textAlign=\"center\"; }\n    const bandCols=[\"#22c55e\",\"#eab308\",\"#f97316\",\"#3b82f6\"];\n    ch.eq.forEach((b,bi)=>{ if(b.g===0)return; ctx.beginPath();\n      for(let px=0;px<=gw;px+=3){ const f=fInv(px/gw); const g=biquadDb(b.type,b.f,b.g,b.q*eqTypeFactor(ch.eqType),f); const y=gy+gh/2-g/24*gh/2; px===0?ctx.moveTo(gx+px,y):ctx.lineTo(gx+px,y); }\n      ctx.strokeStyle=bandCols[bi]+\"66\";ctx.lineWidth=1;ctx.stroke(); });\n    ctx.beginPath();\n    for(let px=0;px<=gw;px+=2){ const f=fInv(px/gw); const g=eqMag(ch,f); const y=gy+gh/2-g/24*gh/2; px===0?ctx.moveTo(gx+px,y):ctx.lineTo(gx+px,y); }\n    ctx.strokeStyle=ch.color;ctx.lineWidth=2.4;ctx.stroke();\n    ctx.lineTo(gx+gw,gy+gh/2);ctx.lineTo(gx,gy+gh/2);ctx.closePath();ctx.fillStyle=ch.color+\"14\";ctx.fill();\n    ctx.restore();\n    // HPF / LPF marcadores\n    if(ch.hpfOn){ const x=gx+fx(ch.hpf)*gw; ctx.strokeStyle=\"#f59e0b\";ctx.setLineDash([4,3]);ctx.beginPath();ctx.moveTo(x,gy);ctx.lineTo(x,gy+gh);ctx.stroke();ctx.setLineDash([]);\n      ctx.fillStyle=\"#f59e0b\";ctx.beginPath();ctx.arc(x,gy+gh-14,6,0,7);ctx.fill();\n      reg({hit:''circle'',cx:x,cy:gy+gh-14,rr:14,onDrag:p=>{ch.hpf=clamp(Math.round(fInv((p.x-gx)/gw)),20,600);applyChanAudio(ch.i);paintSelected();}}); }\n    if(ch.lpfOn){ const x=gx+fx(ch.lpf)*gw; ctx.strokeStyle=\"#a855f7\";ctx.setLineDash([4,3]);ctx.beginPath();ctx.moveTo(x,gy);ctx.lineTo(x,gy+gh);ctx.stroke();ctx.setLineDash([]);\n      ctx.fillStyle=\"#a855f7\";ctx.beginPath();ctx.arc(x,gy+14,6,0,7);ctx.fill();\n      reg({hit:''circle'',cx:x,cy:gy+14,rr:14,onDrag:p=>{ch.lpf=clamp(Math.round(fInv((p.x-gx)/gw)),1000,20000);applyChanAudio(ch.i);}}); }\n    // nós das 4 bandas (arrastáveis: X=freq, Y=gain)\n    ch.eq.forEach((b,bi)=>{ const x=gx+fx(b.f)*gw, y=gy+gh/2-b.g/24*gh/2, selb=state.eqBand===bi;\n      ctx.fillStyle=bandCols[bi]; ctx.beginPath();ctx.arc(x,y,selb?9:7,0,7);ctx.fill();\n      if(selb){ctx.strokeStyle=\"#fff\";ctx.lineWidth=2;ctx.stroke();}\n      ctx.fillStyle=\"#0b0f17\";ctx.font=\"700 9px system-ui\";ctx.textAlign=\"center\";ctx.textBaseline=\"middle\";ctx.fillText(bi+1,x,y);ctx.textBaseline=\"alphabetic\";\n      reg({hit:''circle'',cx:x,cy:y,rr:16,onDown:()=>{state.eqBand=bi;},\n        onDrag:p=>{ b.f=clamp(Math.round(fInv((p.x-gx)/gw)),20,20000); b.g=clamp(-(p.y-gy-gh/2)/(gh/2)*24,-18,18); applyChanAudio(ch.i); paintSelected(); checkMissions(); } }); });\n    // painel direito\n    const rx=gx+gw+10, rw=W-rx-10; let yy=gy+2;\n    ctx.fillStyle=ch.color;ctx.font=\"800 12px system-ui\";ctx.textAlign=\"left\";ctx.fillText(ch.name,rx,yy+10);\n    ctx.fillStyle=\"#8ea0bd\";ctx.font=\"700 9px system-ui\";ctx.fillText(\"EQ 4-BAND · CH\"+(ch.i+1),rx,yy+22); yy+=32;\n    const bw=(rw-9)/4, bn=[\"LOW\",\"LO-MID\",\"HI-MID\",\"HIGH\"];\n    bn.forEach((nm,bi)=>{ uiBtn(rx+bi*(bw+3),yy,bw,20,nm,state.eqBand===bi,()=>{state.eqBand=bi;},bandCols[bi]); }); yy+=28;\n    const b=ch.eq[state.eqBand];\n    uiParam(rx,yy+12,rw,\"FREQ\",b.f,20,20000,v=>Math.round(v)+\" Hz\",v=>{b.f=Math.round(v);applyChanAudio(ch.i);paintSelected();},{log:true}); yy+=30;\n    uiParam(rx,yy+12,rw,\"GAIN\",b.g,-18,18,v=>(v>0?\"+\":\"\")+v.toFixed(1)+\" dB\",v=>{b.g=v;applyChanAudio(ch.i);paintSelected();}); yy+=30;\n    uiParam(rx,yy+12,rw,\"Q\",b.q,0.10,10,v=>v.toFixed(2),v=>{b.q=v;applyChanAudio(ch.i);}); yy+=32;\n    if(state.eqBand===0){ uiBtn(rx,yy,rw/2-3,20,\"L.SHELF\",b.type===''lowshelf'',()=>{b.type=''lowshelf'';applyChanAudio(ch.i);}); uiBtn(rx+rw/2+3,yy,rw/2-3,20,\"BELL\",b.type===''peaking'',()=>{b.type=''peaking'';applyChanAudio(ch.i);}); yy+=26; }\n    else if(state.eqBand===3){ uiBtn(rx,yy,rw/2-3,20,\"H.SHELF\",b.type===''highshelf'',()=>{b.type=''highshelf'';applyChanAudio(ch.i);}); uiBtn(rx+rw/2+3,yy,rw/2-3,20,\"BELL\",b.type===''peaking'',()=>{b.type=''peaking'';applyChanAudio(ch.i);}); yy+=26; }\n    else { ctx.fillStyle=\"#556685\";ctx.font=\"9px system-ui\";ctx.textAlign=\"left\";ctx.fillText(\"Banda BELL (paramétrica)\",rx,yy+13); yy+=26; }\n    uiBtn(rx,yy,rw/2-3,20,\"HPF \"+(ch.hpfOn?ch.hpf+\"Hz\":\"OFF\"),ch.hpfOn,()=>{ch.hpfOn=!ch.hpfOn;applyChanAudio(ch.i);paintSelected();},\"#f59e0b\");\n    uiBtn(rx+rw/2+3,yy,rw/2-3,20,\"LPF \"+(ch.lpfOn?(ch.lpf>=1000?(ch.lpf/1000).toFixed(1)+\"k\":ch.lpf+\"Hz\"):\"OFF\"),ch.lpfOn,()=>{ch.lpfOn=!ch.lpfOn;applyChanAudio(ch.i);},\"#a855f7\"); yy+=28;\n    ctx.fillStyle=\"#8ea0bd\";ctx.font=\"700 9px system-ui\";ctx.textAlign=\"left\";ctx.fillText(\"EQ TYPE (caráter)\",rx,yy+2); yy+=6;\n    const tw=(rw-9)/4;\n    [\"PRECISE\",\"AGGRESSIVE\",\"SMOOTH\",\"LEGACY\"].forEach((tp,ti)=>{ uiBtn(rx+ti*(tw+3),yy,tw,20,tp.slice(0,4),ch.eqType===tp,()=>{ch.eqType=tp;applyChanAudio(ch.i);},\"#22d3ee\"); });\n  }\n\n  // ================= PÁGINA: GATE (Dynamics 1) =================\n  function drawGate(){\n    const ch=CH[state.sel];\n    const gx=10,gy=10,gw=W*0.50-14,gh=H-20;\n    uiPanel(gx,gy,gw,gh,\"DYN 1 · GATE — \"+ch.name);\n    const px0=gx+30,py0=gy+26,pw=gw-56,ph=gh-58;\n    const X=din=>px0+clamp((din+72)/72,0,1)*pw, Y=dout=>py0+ph-clamp((dout+72)/72,0,1)*ph;\n    ctx.strokeStyle=\"#182339\";ctx.strokeRect(px0,py0,pw,ph);\n    ctx.strokeStyle=\"#22314d\";ctx.setLineDash([3,3]);ctx.beginPath();ctx.moveTo(X(-72),Y(-72));ctx.lineTo(X(0),Y(0));ctx.stroke();ctx.setLineDash([]);\n    ctx.beginPath();\n    for(let d=-72;d<=0;d+=1){ const out= d>ch.gateThr? d : d+ch.gateRange; const x=X(d), y=Y(clamp(out,-90,0)); d===-72?ctx.moveTo(x,y):ctx.lineTo(x,y); }\n    ctx.strokeStyle=\"#22c55e\";ctx.lineWidth=2.2;ctx.stroke();\n    const tx=X(ch.gateThr); ctx.strokeStyle=\"#ef4444\";ctx.setLineDash([4,3]);ctx.beginPath();ctx.moveTo(tx,py0);ctx.lineTo(tx,py0+ph);ctx.stroke();ctx.setLineDash([]);\n    ctx.fillStyle=\"#ef4444\";ctx.font=\"700 9px system-ui\";ctx.textAlign=\"center\";ctx.fillText(\"THR\",tx,py0-2);\n    reg({x:tx-14,y:py0,w:28,h:ph,onDrag:p=>{ ch.gateThr=clamp(Math.round((p.x-px0)/pw*72-72),-72,0); applyChanAudio(ch.i); paintSelected(); checkMissions(); }});\n    ctx.fillStyle=\"#4a5a78\";ctx.font=\"8px system-ui\";ctx.textAlign=\"center\";ctx.fillText(\"ENTRADA (dB)\",px0+pw/2,py0+ph+13);\n    const rx=gx+gw+10, rw=W-rx-10; uiPanel(rx,gy,rw,gh,null); let yy=gy+8;\n    ctx.fillStyle=\"#8ea0bd\";ctx.font=\"700 11px system-ui\";ctx.textAlign=\"left\";ctx.fillText(\"GATE\",rx+12,yy+9);\n    uiBtn(rx+rw-60,yy,50,18,ch.gateOn?\"ON\":\"OFF\",ch.gateOn,()=>{ch.gateOn=!ch.gateOn;applyChanAudio(ch.i);paintSelected();checkMissions();},\"#22c55e\"); yy+=28;\n    const open=(ch._gr||0)<0.5;\n    ctx.fillStyle=ch.gateOn?(open?\"#22c55e\":\"#ef4444\"):\"#26344f\";ctx.beginPath();ctx.arc(rx+18,yy+5,6,0,7);ctx.fill();\n    ctx.fillStyle=\"#c3cfe2\";ctx.font=\"700 10px system-ui\";ctx.textAlign=\"left\";ctx.fillText(ch.gateOn?(open?\"OPEN\":\"CLOSED\"):\"—\",rx+30,yy+8);\n    const gr=ch._gr||0; ctx.fillStyle=\"#556685\";ctx.font=\"8px system-ui\";ctx.textAlign=\"left\";ctx.fillText(\"GR\",rx+rw-92,yy+8);\n    ctx.fillStyle=\"#05070d\";ctx.fillRect(rx+rw-74,yy,64,9); ctx.fillStyle=\"#ef4444\";ctx.fillRect(rx+rw-74,yy,clamp(gr/60,0,1)*64,9); yy+=26;\n    uiParam(rx+12,yy+12,rw-24,\"THRESHOLD\",ch.gateThr,-72,0,v=>v+\" dB\",v=>{ch.gateThr=Math.round(v);applyChanAudio(ch.i);paintSelected();}); yy+=30;\n    uiParam(rx+12,yy+12,rw-24,\"RANGE\",ch.gateRange,-70,0,v=>(v<=-70?\"-∞\":v)+\" dB\",v=>{ch.gateRange=Math.round(v);applyChanAudio(ch.i);}); yy+=30;\n    uiParam(rx+12,yy+12,rw-24,\"ATTACK\",ch.gateAtk,0,120,v=>v.toFixed(0)+\" ms\",v=>{ch.gateAtk=v;}); yy+=30;\n    uiParam(rx+12,yy+12,rw-24,\"HOLD\",ch.gateHold,0.02,1960,v=>(v>=1000?(v/1000).toFixed(2)+\"s\":v.toFixed(0)+\"ms\"),v=>{ch.gateHold=v;},{log:true}); yy+=30;\n    uiParam(rx+12,yy+12,rw-24,\"DECAY\",ch.gateDecay,5,42300,v=>(v>=1000?(v/1000).toFixed(1)+\"s\":v.toFixed(0)+\"ms\"),v=>{ch.gateDecay=v;},{log:true}); yy+=30;\n  }\n\n  // ================= PÁGINA: COMPRESSOR (Dynamics 2) =================\n  function drawComp(){\n    const ch=CH[state.sel];\n    const gx=10,gy=10,gw=W*0.50-14,gh=H-20;\n    uiPanel(gx,gy,gw,gh,\"DYN 2 · COMPRESSOR — \"+ch.name);\n    const px0=gx+30,py0=gy+26,pw=gw-56,ph=gh-58;\n    const X=din=>px0+clamp((din+60)/60,0,1)*pw, Y=dout=>py0+ph-clamp((dout+60)/60,0,1)*ph;\n    ctx.strokeStyle=\"#182339\";ctx.strokeRect(px0,py0,pw,ph);\n    ctx.strokeStyle=\"#22314d\";ctx.setLineDash([3,3]);ctx.beginPath();ctx.moveTo(X(-60),Y(-60));ctx.lineTo(X(0),Y(0));ctx.stroke();ctx.setLineDash([]);\n    const kneeDb=(ch.compKnee===''HARD''||ch.compKnee===0)?0:ch.compKnee*4;\n    const ratio=ch.compRatio>=40?40:ch.compRatio;\n    const compFn=din=>{ const t=ch.compThr; let out;\n      if(kneeDb>0 && din>t-kneeDb/2 && din<t+kneeDb/2){ const xk=din-(t-kneeDb/2); out=din+(1/ratio-1)*xk*xk/(2*kneeDb); }\n      else out= din>t? t+(din-t)/ratio : din; return out+ch.compGain; };\n    ctx.beginPath();\n    for(let d=-60;d<=0;d+=1){ const x=X(d), y=Y(clamp(compFn(d),-60,6)); d===-60?ctx.moveTo(x,y):ctx.lineTo(x,y); }\n    ctx.strokeStyle=\"#22d3ee\";ctx.lineWidth=2.2;ctx.stroke();\n    const tx=X(ch.compThr); ctx.strokeStyle=\"#ef4444\";ctx.setLineDash([4,3]);ctx.beginPath();ctx.moveTo(tx,py0);ctx.lineTo(tx,py0+ph);ctx.stroke();ctx.setLineDash([]);\n    ctx.fillStyle=\"#ef4444\";ctx.font=\"700 9px system-ui\";ctx.textAlign=\"center\";ctx.fillText(\"THR\",tx,py0-2);\n    reg({x:tx-14,y:py0,w:28,h:ph,onDrag:p=>{ ch.compThr=clamp(Math.round((p.x-px0)/pw*60-60),-54,0); applyChanAudio(ch.i); paintSelected(); checkMissions(); }});\n    ctx.fillStyle=\"#4a5a78\";ctx.font=\"8px system-ui\";ctx.textAlign=\"center\";ctx.fillText(\"ENTRADA (dB)\",px0+pw/2,py0+ph+13);\n    const rx=gx+gw+10, rw=W-rx-10; uiPanel(rx,gy,rw,gh,null); let yy=gy+8;\n    ctx.fillStyle=\"#8ea0bd\";ctx.font=\"700 11px system-ui\";ctx.textAlign=\"left\";ctx.fillText(\"COMP\",rx+12,yy+9);\n    uiBtn(rx+rw-60,yy,50,18,ch.compOn?\"ON\":\"OFF\",ch.compOn,()=>{ch.compOn=!ch.compOn;applyChanAudio(ch.i);paintSelected();checkMissions();},\"#22d3ee\"); yy+=26;\n    let gr=0; if(ac&&aNodes[ch.i]&&ch.compOn) gr=-aNodes[ch.i].comp.reduction;\n    ctx.fillStyle=\"#556685\";ctx.font=\"8px system-ui\";ctx.textAlign=\"left\";ctx.fillText(\"GR \"+gr.toFixed(1)+\" dB\",rx+12,yy+8);\n    ctx.fillStyle=\"#05070d\";ctx.fillRect(rx+78,yy,rw-90,9);ctx.fillStyle=\"#22d3ee\";ctx.fillRect(rx+78,yy,clamp(gr/24,0,1)*(rw-90),9); yy+=24;\n    uiParam(rx+12,yy+12,rw-24,\"THRESHOLD\",ch.compThr,-54,0,v=>v+\" dB\",v=>{ch.compThr=Math.round(v);applyChanAudio(ch.i);paintSelected();}); yy+=30;\n    uiParam(rx+12,yy+12,rw-24,\"RATIO\",ratio,1,40,v=>(v>=40?\"∞\":v.toFixed(1))+\":1\",v=>{ch.compRatio=v;applyChanAudio(ch.i);}); yy+=30;\n    uiParam(rx+12,yy+12,rw-24,\"ATTACK\",ch.compAtk,0,120,v=>v.toFixed(0)+\" ms\",v=>{ch.compAtk=v;applyChanAudio(ch.i);}); yy+=30;\n    uiParam(rx+12,yy+12,rw-24,\"RELEASE\",ch.compRel,5,42300,v=>(v>=1000?(v/1000).toFixed(1)+\"s\":v.toFixed(0)+\"ms\"),v=>{ch.compRel=v;applyChanAudio(ch.i);},{log:true}); yy+=30;\n    uiParam(rx+12,yy+12,rw-24,\"OUT GAIN\",ch.compGain,0,18,v=>\"+\"+v.toFixed(1)+\" dB\",v=>{ch.compGain=v;applyChanAudio(ch.i);}); yy+=30;\n    ctx.fillStyle=\"#8ea0bd\";ctx.font=\"700 9px system-ui\";ctx.textAlign=\"left\";ctx.fillText(\"KNEE\",rx+12,yy+2);\n    const kw=(rw-24-15)/6;\n    [\"HARD\",\"1\",\"2\",\"3\",\"4\",\"5\"].forEach((kn,ki)=>{ const val=ki===0?''HARD'':ki;\n      const act=(ch.compKnee===val)||(ki===0&&(ch.compKnee===''HARD''||ch.compKnee===0));\n      uiBtn(rx+12+ki*(kw+3),yy+6,kw,18,kn,act,()=>{ch.compKnee=val;applyChanAudio(ch.i);},\"#22d3ee\"); });\n  }\n\n  // ================= PÁGINA: SENDS (24 MIX do canal selecionado) =================\n  function drawSends(){\n    const ch=CH[state.sel];\n    ctx.fillStyle=ch.color;ctx.font=\"800 12px system-ui\";ctx.textAlign=\"left\";ctx.fillText(\"SENDS — \"+ch.name+\" (CH\"+(ch.i+1)+\")\",12,18);\n    ctx.fillStyle=\"#8ea0bd\";ctx.font=\"700 8.5px system-ui\";ctx.fillText(\"24 MIX · toque ON · arraste o nível · PRE/POST — ou use SENDS ON FADER p/ editar nos faders\",12,32);\n    const cols=2, rows=12, top=42;\n    const cw=(W-24-12)/cols, rh=(H-top-8)/rows;\n    for(let m=0;m<24;m++){ const col=Math.floor(m/rows), row=m%rows;\n      const x=12+col*(cw+12), y=top+row*rh, on=ch.sendOn[m];\n      ctx.fillStyle=on?\"#22d3ee\":\"#26344f\";ctx.beginPath();ctx.arc(x+8,y+rh/2,5,0,7);ctx.fill();\n      reg({hit:''circle'',cx:x+8,cy:y+rh/2,rr:10,onDown:()=>{ch.sendOn[m]=!ch.sendOn[m];checkMissions();}});\n      ctx.fillStyle=on?\"#e7ecf5\":\"#5a6b88\";ctx.font=\"700 9px system-ui\";ctx.textAlign=\"left\";ctx.fillText(MIX_NAMES[m],x+18,y+rh/2-3);\n      const bx=x+18, bw=cw-100, by=y+rh/2+2, bh=6;\n      ctx.fillStyle=\"#0a1220\";roundRect(bx,by,bw,bh,3);ctx.fill();\n      const t=clamp((ch.sends[m]-FMIN)/(FMAX-FMIN),0,1);\n      ctx.fillStyle=on?\"#22d3ee\":\"#33456a\";roundRect(bx,by,t*bw,bh,3);ctx.fill();\n      reg({x:bx-3,y:by-7,w:bw+6,h:bh+14,onDrag:p=>{ let tt=clamp((p.x-bx)/bw,0,1); ch.sends[m]=Math.round(FMIN+tt*(FMAX-FMIN)); if(ch.sends[m]>FMIN)ch.sendOn[m]=true; checkMissions(); }});\n      ctx.fillStyle=on?\"#cdd8ea\":\"#5a6b88\";ctx.font=\"700 9px system-ui\";ctx.textAlign=\"right\";ctx.fillText(faderTxt(ch.sends[m]),x+cw-40,y+rh/2+2);\n      uiBtn(x+cw-38,y+rh/2-8,34,16,ch.sendPre[m]?\"PRE\":\"POST\",ch.sendPre[m],()=>{ch.sendPre[m]=!ch.sendPre[m];},\"#f59e0b\");\n    }\n  }\n\n  // ================= PÁGINA: DCA (16) + MUTE (8) =================\n  function drawDCA(){\n    const ch=CH[state.sel];\n    ctx.fillStyle=\"#8ea0bd\";ctx.font=\"700 10px system-ui\";ctx.textAlign=\"left\";ctx.fillText(\"DCA 16 (masters VCA) — arraste o ganho, toque ON/MUTE\",12,15);\n    const n=16, top=22, gh=H*0.40, gapx=6, fw=(W-24-(n-1)*gapx)/n;\n    for(let g=0;g<n;g++){ const x=12+g*(fw+gapx), y=top, fh=gh-30, fcx=x+fw/2;\n      ctx.fillStyle=\"#0a1220\";roundRect(fcx-4,y,8,fh,3);ctx.fill();ctx.strokeStyle=\"#22314d\";ctx.lineWidth=1;roundRect(fcx-4,y,8,fh,3);ctx.stroke();\n      const t=db2pos(state.dcaGain[g]), capY=y+fh-t*fh;\n      ctx.fillStyle=\"#f59e0b\";ctx.fillRect(fcx-7,capY-3,14,6);\n      reg({x:x,y:y,w:fw,h:fh,onDrag:p=>{ const tt=clamp(1-(p.y-y)/fh,0,1); state.dcaGain[g]=pos2db(tt); for(let i=0;i<24;i++)if(CH[i].dca[g])applyChanAudio(i); }});\n      ctx.fillStyle=\"#8ea0bd\";ctx.font=\"700 8px system-ui\";ctx.textAlign=\"center\";ctx.fillText(\"DCA\"+(g+1),fcx,y+fh+9);\n      uiBtn(x,y+fh+12,fw,15,state.dcaOn[g]?\"ON\":\"MUTE\",state.dcaOn[g],()=>{state.dcaOn[g]=!state.dcaOn[g];for(let i=0;i<24;i++)if(CH[i].dca[g])applyChanAudio(i);},\"#22c55e\");\n    }\n    let yy=top+gh+10;\n    ctx.fillStyle=ch.color;ctx.font=\"800 11px system-ui\";ctx.textAlign=\"left\";ctx.fillText(ch.name+\" → DCA assign\",12,yy); yy+=8;\n    const bw=(W-24-15*3)/16;\n    for(let g=0;g<16;g++){ uiBtn(12+g*(bw+3),yy,bw,20,\"\"+(g+1),ch.dca[g],()=>{ch.dca[g]=!ch.dca[g];applyChanAudio(ch.i);},\"#f59e0b\"); }\n    yy+=30;\n    ctx.fillStyle=\"#8ea0bd\";ctx.font=\"700 10px system-ui\";ctx.fillText(\"MUTE GROUPS 8 — botão vermelho: ativa o mute-master · abaixo: pertinência do canal\",12,yy); yy+=8;\n    const mw=(W-24-7*7)/8;\n    for(let g=0;g<8;g++){ const x=12+g*(mw+7);\n      uiBtn(x,yy,mw,20,\"MUTE \"+(g+1),state.muteActive[g],()=>{state.muteActive[g]=!state.muteActive[g];for(let i=0;i<24;i++)if(CH[i].mute[g])applyChanAudio(i);paintStrips();},\"#ef4444\");\n      uiBtn(x,yy+24,mw,17,ch.mute[g]?\"CH IN\":\"assign\",ch.mute[g],()=>{ch.mute[g]=!ch.mute[g];applyChanAudio(ch.i);},\"#8ea0bd\");\n    }\n  }\n\n  // ================= PÁGINA: FX (Reverb + Delay) =================\n  function drawFX(){\n    const ch=CH[state.sel];\n    const half=(W-24-10)/2;\n    uiPanel(12,10,half,H-20,\"RACK 1 · REVERB (Hall)\");\n    let yy=44;\n    uiParam(24,yy,half-24,\"MIX (return)\",state.fx.revMix,0,1,v=>Math.round(v*100)+\"%\",v=>{state.fx.revMix=v;applyFX();}); yy+=34;\n    uiParam(24,yy,half-24,\"SIZE (decay)\",state.fx.revSize,0.3,4,v=>v.toFixed(1)+\" s\",v=>{state.fx.revSize=v; if(fxRack)fxRack.conv.buffer=makeImpulse(v);}); yy+=42;\n    ctx.fillStyle=\"#8ea0bd\";ctx.font=\"700 9px system-ui\";ctx.textAlign=\"left\";ctx.fillText(ch.name+\" → REVERB send\",24,yy);\n    uiParam(24,yy+14,half-24,\"\",ch.fxRev,FMIN,FMAX,v=>faderTxt(v)+\" dB\",v=>{ch.fxRev=Math.round(v);applyChanAudio(ch.i);},{col:\"#22d3ee\"});\n    const dx=12+half+10;\n    uiPanel(dx,10,half,H-20,\"RACK 2 · DELAY\");\n    yy=44;\n    uiParam(dx+12,yy,half-24,\"TIME\",state.fx.dlyTime,0.05,1.2,v=>Math.round(v*1000)+\" ms\",v=>{state.fx.dlyTime=v;applyFX();}); yy+=34;\n    uiParam(dx+12,yy,half-24,\"FEEDBACK\",state.fx.dlyFb,0,0.85,v=>Math.round(v*100)+\"%\",v=>{state.fx.dlyFb=v;applyFX();}); yy+=34;\n    uiParam(dx+12,yy,half-24,\"MIX (return)\",state.fx.dlyMix,0,1,v=>Math.round(v*100)+\"%\",v=>{state.fx.dlyMix=v;applyFX();}); yy+=42;\n    ctx.fillStyle=\"#8ea0bd\";ctx.font=\"700 9px system-ui\";ctx.fillText(ch.name+\" → DELAY send\",dx+12,yy);\n    uiParam(dx+12,yy+14,half-24,\"\",ch.fxDly,FMIN,FMAX,v=>faderTxt(v)+\" dB\",v=>{ch.fxDly=Math.round(v);applyChanAudio(ch.i);},{col:\"#22d3ee\"});\n  }\n\n  // ================= PÁGINA: SCENES (STORE/RECALL) =================\n  function drawScenes(){\n    ctx.fillStyle=\"#8ea0bd\";ctx.font=\"700 10px system-ui\";ctx.textAlign=\"left\";ctx.fillText(\"SCENES — STORE/RECALL (snapshot completo do mixer). Console real: 300 cenas.\",12,15);\n    const cols=2, rows=5, top=24, gapx=12, gapy=8;\n    const cw=(W-24-gapx)/cols, rh=(H-top-8-gapy*(rows-1))/rows;\n    for(let s=0;s<10;s++){ const col=Math.floor(s/rows), row=s%rows;\n      const x=12+col*(cw+gapx), y=top+row*(rh+gapy), sc=scenes[s];\n      uiPanel(x,y,cw,rh,null);\n      ctx.fillStyle=sc?\"#e7ecf5\":\"#556685\";ctx.font=\"800 12px system-ui\";ctx.textAlign=\"left\";ctx.fillText(\"Cena \"+(s+1),x+12,y+rh/2-3);\n      ctx.fillStyle=sc?\"#22c55e\":\"#41527a\";ctx.font=\"700 9px system-ui\";ctx.fillText(sc?(\"armazenada \"+new Date(sc.ts).toLocaleTimeString().slice(0,5)):\"vazia\",x+12,y+rh/2+12);\n      uiBtn(x+cw-150,y+rh/2-14,68,28,\"STORE\",false,()=>{storeScene(s);},\"#f59e0b\");\n      uiBtn(x+cw-76,y+rh/2-14,64,28,\"RECALL\",false,()=>{recallScene(s);},\"#22c55e\");\n    }\n  }\n\n  // ================= PÁGINA: METER BRIDGE =================\n  function drawMeter(){\n    ctx.fillStyle=\"#8ea0bd\";ctx.font=\"700 10px system-ui\";ctx.textAlign=\"left\";ctx.fillText(\"METER BRIDGE — 24 canais + ST master (toque um medidor p/ selecionar)\",12,14);\n    const n=24, top=24, bot=H-24, gapx=4, bw=(W-24-40-(n-1)*gapx)/n;\n    for(let i=0;i<n;i++){ const ch=CH[i], x=12+i*(bw+gapx);\n      const db=(playing&&ch.hasAudio)?chLevelDb(i):(ch.hasAudio?ch.src+ch.gain+(ch.on?Math.min(0,ch.fader):-90):-90);\n      drawVMeter(x,top,bw,bot-top,db);\n      ctx.fillStyle=ch.i===state.sel?\"#f59e0b\":\"#5a6b88\";ctx.font=\"700 7px system-ui\";ctx.textAlign=\"center\";ctx.fillText(\"\"+(i+1),x+bw/2,bot+9);\n      reg({x:x,y:top,w:bw,h:bot-top,onDown:()=>{selectChannel(i);}});\n    }\n    const mx=W-32; drawVMeter(mx,top,12,bot-top, playing?masterLevelDb():-20);\n    ctx.fillStyle=\"#f59e0b\";ctx.font=\"700 8px system-ui\";ctx.textAlign=\"center\";ctx.fillText(\"ST\",mx+6,bot+9);\n  }\n\n  // Pointer no canvas -> despacha para as regiões desenhadas (touch + mouse, com pointer capture)\n  cv.addEventListener(\"pointerdown\",e=>{ const p=evtPos(e);\n    for(let i=hitRegions.length-1;i>=0;i--){ const r=hitRegions[i]; if(inRegion(r,p)){\n      if(r.onDown) r.onDown(p);\n      if(r.onDrag){ activeRegion=r; cv.setPointerCapture(e.pointerId); r.onDrag(p); }\n      drawScreen(); e.preventDefault(); return; } } });\n  cv.addEventListener(\"pointermove\",e=>{ if(!activeRegion)return; activeRegion.onDrag(evtPos(e)); drawScreen(); e.preventDefault(); });\n  const cvUp=()=>{ activeRegion=null; };\n  cv.addEventListener(\"pointerup\",cvUp); cv.addEventListener(\"pointercancel\",cvUp);\n  function evtPos(e){ const r=cv.getBoundingClientRect(); return {x:e.clientX-r.left,y:e.clientY-r.top}; }\n\n  // ---------------- TABS / BANK / SOF ----------------\n  document.querySelectorAll(\".tab[data-mode]\").forEach(t=>t.onclick=()=>{\n    document.querySelectorAll(\".tab[data-mode]\").forEach(x=>x.classList.remove(\"active\"));\n    t.classList.add(\"active\"); state.mode=t.dataset.mode; drawScreen(); });\n  document.querySelectorAll(\".tab[data-bank]\").forEach(t=>t.onclick=()=>{\n    document.querySelectorAll(\".tab[data-bank]\").forEach(x=>x.classList.remove(\"active\"));\n    t.classList.add(\"active\"); state.bank=+t.dataset.bank; paintStrips(); checkMissions(); });\n  const sofBtn=$(\"#sofBtn\");\n  sofBtn.onclick=()=>{ state.sof = state.sof>=0? -1 : 0; updateSof(); };\n  function updateSof(){\n    const on=state.sof>=0;\n    sofBtn.classList.toggle(\"active\",on);\n    sofBtn.textContent=\"SENDS ON FADER: \"+(on? \"MIX \"+(state.sofMix+1) : \"OFF\");\n    $(\"#sofLbl\").style.display=on?\"inline\":\"none\";\n    if(on){ $(\"#sofMix\").textContent=MIX_NAMES[state.sofMix]; }\n    paintStrips();\n  }\n  // clique direito no botão troca a MIX de destino (1..24)\n  sofBtn.addEventListener(\"contextmenu\",e=>{e.preventDefault(); if(state.sof>=0){ state.sofMix=(state.sofMix+1)%N_MIX; updateSof(); }});\n\n  // ---------------- MISSIONS ----------------\n  const missions=[\n    { t:''<b>Gain staging:</b> selecione o <b>Lead Voc</b> (CH13) e ajuste o <b>GAIN</b> para o medidor de entrada picar perto de <b>−18 dBFS</b> (linha branca).'',\n      ok:()=>{ const ch=CH[12]; const inDb=ch.src+ch.gain; return state.sel===12 && Math.abs(inDb+18)<=2.5; } },\n    { t:''<b>Limpeza:</b> ative o <b>HPF</b> do Lead Voc e ajuste para ~<b>100 Hz</b> para tirar o ronco de palco.'',\n      ok:()=>{ const ch=CH[12]; return ch.hpfOn && Math.abs(ch.hpf-100)<=25; } },\n    { t:''<b>EQ:</b> na aba <b>EQ</b> (ou Selected), dê um <b>realce de brilho</b> — puxe a banda <b>HIGH</b> para cima (+3 dB ou mais).'',\n      ok:()=>{ const ch=CH[12]; return ch.eq[3].g>=3; } },\n    { t:''<b>Dinâmica:</b> ative o <b>COMP</b> e coloque o threshold em torno de <b>−18 dB</b> para segurar a voz.'',\n      ok:()=>{ const ch=CH[12]; return ch.compOn && Math.abs(ch.compThr+18)<=4; } },\n    { t:''<b>Monitor:</b> ligue <b>SENDS ON FADER</b> (botão azul) e mande o Lead Voc para o <b>MIX 1</b> em cerca de <b>−6 dB</b>. <small>(clique direito no botão troca o MIX)</small>'',\n      ok:()=>{ const ch=CH[12]; return state.sof>=0 && state.sofMix===0 && ch.sendOn[0] && Math.abs(ch.sends[0]+6)<=3; } },\n  ];\n  let mi=0;\n  function paintMission(){ if(mi>=missions.length){ $(\"#mIdx\").textContent=\"CONCLUÍDO\"; $(\"#mTxt\").innerHTML=\"🎓 <b>Parabéns!</b> Você fez o fluxo básico de canal na CL5: gain → HPF → EQ → dinâmica → monitor.\";\n      $(\"#mSkip\").style.display=\"none\"; return; }\n    $(\"#mIdx\").textContent=\"MISSÃO \"+(mi+1)+\"/\"+missions.length; $(\"#mTxt\").innerHTML=missions[mi].t; }\n  function checkMissions(){ if(mi>=missions.length)return; try{ if(missions[mi].ok()){ mi++; toast(mi>=missions.length?\"Todas as missões concluídas! 🎓\":\"Missão concluída! ✔\"); paintMission(); } }catch(e){} }\n  $(\"#mSkip\").onclick=()=>{ if(mi<missions.length){ mi++; paintMission(); } };\n  let toastT; function toast(msg){ const el=$(\"#toast\"); el.innerHTML=msg; el.classList.add(\"show\"); clearTimeout(toastT); toastT=setTimeout(()=>el.classList.remove(\"show\"),1800); }\n\n  // ---------------- METERS / LOOP ----------------\n  let t0=0; function perf(){ return (typeof performance!==\"undefined\"?performance.now():t0+=16); }\n  function loop(){\n    const now=perf();\n    processGates();\n    for(let s=0;s<8;s++){ const ch=chOf(s), o=stripEls[s]; let t;\n      if(playing && ch.hasAudio){ const db=chLevelDb(ch.i)+ (ch.on?0:-90); t=clamp((db+48)/48,0,1); }\n      else if(playing){ t=0; }\n      else { const env=0.5+0.5*Math.sin(now/ (260+ch.i*23) + ch.i)*Math.abs(Math.sin(now/900+ch.i));\n        let post = ch.src+ch.gain + (ch.on? (ch.fader<=FMIN?-90:ch.fader) : -90) + env*8 - 4;\n        if(ch.compOn && (ch.src+ch.gain)>ch.compThr) post -= (ch.src+ch.gain-ch.compThr)*(1-1/ch.compRatio);\n        t=clamp((post+50)/50,0,1); }\n      o.meter.style.height=(t*100)+\"%\";\n      o.meter.style.background = t>0.9? \"linear-gradient(0deg,#22c55e,#f59e0b 78%,#ef4444)\":\"linear-gradient(0deg,#22c55e,#22c55e 70%,#f59e0b)\";\n    }\n    // master meters\n    if(masterEl){ let t;\n      if(playing){ t=clamp((masterLevelDb()+42)/42,0,1); }\n      else { let sum=0; CH.forEach(ch=>{ if(ch.on&&ch.fader>FMIN){ sum+=Math.pow(10,(ch.src+ch.gain+ch.fader)/20); } });\n        t=clamp((20*Math.log10(sum+1e-6)+state.master+30)/40,0,1); }\n      masterEl.meters.forEach((m,idx)=>{ m.style.height=(clamp(t+(idx?-.03:.03),0,1)*100)+\"%\"; }); }\n    // Redesenha as páginas dinâmicas (medidores/GR ao vivo) ou quando tocando\n    if(playing || state.mode!==\"overview\") drawScreen();\n    requestAnimationFrame(loop);\n  }\n\n  // ================= ÁUDIO REAL (bases do Drive, já no Storage) =================\n  const SB=\"https://pshynylvvkhhohftouoe.supabase.co/storage/v1/object/public/media/\";\n  const sg=(n,c,f,p,h)=>({n,c,f,p,h});\n  const SONGS=[\n    {label:\"Pagodão — Tá Sozinha\", folder:\"mix-pagodao-tasozinha\", stems:[\n      sg(\"Bumbo\",\"#ef4444\",\"BB.mp3\",0,false),sg(\"Caixa\",\"#f97316\",\"CX.mp3\",0,true),sg(\"Surdo 1\",\"#f59e0b\",\"SD_1.mp3\",-8,false),sg(\"Surdo 2\",\"#eab308\",\"SD_2.mp3\",8,false),\n      sg(\"Chimbal\",\"#84cc16\",\"HH.mp3\",-15,true),sg(\"Repique\",\"#22c55e\",\"REP.mp3\",12,true),sg(\"Rototom\",\"#14b8a6\",\"ROTANTAN.mp3\",-10,true),sg(\"Timbau\",\"#06b6d4\",\"TIMBAL.mp3\",10,true),\n      sg(\"Tom 1\",\"#3b82f6\",\"TOM1.mp3\",-6,true),sg(\"Tom 2\",\"#6366f1\",\"TOM2.mp3\",0,true),sg(\"Tom 3\",\"#8b5cf6\",\"TOM3.mp3\",6,true),sg(\"Conga Hi\",\"#a855f7\",\"CONGA_HI.mp3\",18,true),\n      sg(\"Conga Low\",\"#c084fc\",\"CONGA_LOW.mp3\",-18,true),sg(\"Baixo\",\"#22c55e\",\"BASS-02.mp3\",0,false),sg(\"Guitarra\",\"#14b8a6\",\"GT-03.mp3\",-20,true),sg(\"Teclado 1\",\"#6366f1\",\"KEY_1-04.mp3\",15,false),\n      sg(\"Teclado 2\",\"#818cf8\",\"KEY_2-03.mp3\",-15,false)]},\n    {label:\"Forró — Thullio (c/ voz)\", folder:\"mix-forro-thullio\", stems:[\n      sg(\"Bumbo\",\"#ef4444\",\"1-KICK-glued.mp3\",0,false),sg(\"Caixa\",\"#f97316\",\"2-CX-glued.mp3\",0,true),sg(\"Esteira\",\"#f59e0b\",\"3-ESTEIRA-glued.mp3\",-10,true),sg(\"Caixa FX\",\"#eab308\",\"4-CX_FX-glued.mp3\",10,true),\n      sg(\"Chimbal\",\"#84cc16\",\"5-HH-glued.mp3\",-14,true),sg(\"Rototom\",\"#22c55e\",\"6-RTT6-glued.mp3\",-8,true),sg(\"Tom 8\",\"#14b8a6\",\"7-TOM_8-glued.mp3\",-6,true),sg(\"Tom 10\",\"#06b6d4\",\"8-TOM_10-glued.mp3\",0,true),\n      sg(\"Tom 12\",\"#3b82f6\",\"9-TOM_12-glued.mp3\",6,true),sg(\"Surdo 14\",\"#6366f1\",\"10-SD14-glued.mp3\",-12,false),sg(\"Surdo 16\",\"#8b5cf6\",\"11-SD_16-glued.mp3\",12,false),sg(\"OH L\",\"#a855f7\"