se,false),\n      chR(\"cg1\",\"Conga 1\",\"#06b6d4\",0,\"7-CG1.mp3\",54,-16,true,false),\n      chR(\"cg2\",\"Conga 2\",\"#3b82f6\",0,\"8-CG2.mp3\",54,16,true,false),\n      chR(\"bass\",\"Baixo\",\"#22c55e\",1,\"9-BASS.mp3\",64,0,false,true),\n      chR(\"gt\",\"Guitarra\",\"#14b8a6\",1,\"10-GT.mp3\",56,-20,true,false),\n      chR(\"ac\",\"Sanfona\",\"#f59e0b\",1,\"11-AC.mp3\",56,20,true,false),\n      chR(\"key\",\"Teclado\",\"#6366f1\",1,\"12-KEY.mp3\",54,-10,false,false),\n      chR(\"sax\",\"Sax\",\"#fbbf24\",1,\"13-SAX.mp3\",56,10,true,false),\n      chR(\"voz\",\"Voz\",\"#ec4899\",2,\"14-VOZ.mp3\",66,0,true,true),\n    ]},\n  };\n  const GKEYS=[\"pagodaoreal\",\"forroreal\",\"lambadareal\",\"avinehreal\",\"samvibereal\",\"vaneiraoreal\",\"forrorecordarreal\",\"rock\",\"samba\",\"pagode\",\"pagodao\"];\n  let genre=\"pagodaoreal\", CH=GEN[genre].ch(), DCA=GEN[genre].dca.map(d=>Object.assign({gain:80},d));\n  const FX={rev:{ret:70},dly:{ret:60,time:0.30,fb:0.32}};\n  const master={fader:80};\n  const by=id=>CH.find(c=>c.id===id);\n\n  // ---------------- WEB AUDIO ----------------\n  let ac=null,masterGain,masterAn,revConv,revRet,dly,dlyFb,dlyRet; let N={};\n  const faderToGain=f=>f<=1?0:dbToLin(-40+(f/100)*46);\n  function makeIR(sec){const rate=ac.sampleRate,len=Math.floor(rate*sec),b=ac.createBuffer(2,len,rate);for(let ch=0;ch<2;ch++){const d=b.getChannelData(ch);for(let i=0;i<len;i++)d[i]=(Math.random()*2-1)*Math.pow(1-i/len,2.5);}return b;}\n  function buildMaster(){\n    masterGain=ac.createGain();masterGain.gain.value=faderToGain(master.fader);\n    masterAn=ac.createAnalyser();masterAn.fftSize=256;\n    const lim=ac.createDynamicsCompressor();lim.threshold.value=-6;lim.ratio.value=12;lim.attack.value=0.003;lim.release.value=0.15;\n    masterGain.connect(lim);lim.connect(masterAn);lim.connect(ac.destination);\n    revConv=ac.createConvolver();revConv.buffer=makeIR(1.7);revRet=ac.createGain();revRet.gain.value=FX.rev.ret/100;revConv.connect(revRet);revRet.connect(masterGain);\n    dly=ac.createDelay(1.0);dly.delayTime.value=FX.dly.time;dlyFb=ac.createGain();dlyFb.gain.value=FX.dly.fb;dlyRet=ac.createGain();dlyRet.gain.value=FX.dly.ret/100;dly.connect(dlyFb);dlyFb.connect(dly);dly.connect(dlyRet);dlyRet.connect(masterGain);\n  }\n  function buildChannels(){\n    Object.values(N).forEach(n=>{try{n.trim.disconnect();n.fader.disconnect();n.pan.disconnect();}catch(e){}});\n    N={};\n    CH.forEach(c=>{\n      const trim=ac.createGain();trim.gain.value=dbToLin(c.gain);\n      const hpf=ac.createBiquadFilter();hpf.type=\"highpass\";hpf.frequency.value=c.eq.hpfOn?c.eq.hpf:20;\n      const low=ac.createBiquadFilter();low.type=\"lowshelf\";low.frequency.value=c.eq.low.f;low.gain.value=c.eq.low.g;\n      const lm=ac.createBiquadFilter();lm.type=\"peaking\";lm.frequency.value=c.eq.loMid.f;lm.Q.value=c.eq.loMid.q;lm.gain.value=c.eq.loMid.g;\n      const hm=ac.createBiquadFilter();hm.type=\"peaking\";hm.frequency.value=c.eq.hiMid.f;hm.Q.value=c.eq.hiMid.q;hm.gain.value=c.eq.hiMid.g;\n      const high=ac.createBiquadFilter();high.type=\"highshelf\";high.frequency.value=c.eq.high.f;high.gain.value=c.eq.high.g;\n      const cmp=ac.createDynamicsCompressor();setComp(cmp,c);\n      const fader=ac.createGain();fader.gain.value=0;\n      const pan=ac.createStereoPanner();pan.pan.value=c.pan/63;\n      const an=ac.createAnalyser();an.fftSize=256;\n      const sendR=ac.createGain();sendR.gain.value=c.rev/100;const sendD=ac.createGain();sendD.gain.value=c.dly/100;\n      trim.connect(hpf);hpf.connect(low);low.connect(lm);lm.connect(hm);hm.connect(high);high.connect(cmp);cmp.connect(fader);\n      fader.connect(pan);pan.connect(masterGain);fader.connect(an);fader.connect(sendR);sendR.connect(revConv);fader.connect(sendD);sendD.connect(dly);\n      N[c.id]={trim,hpf,low,lm,hm,high,cmp,fader,pan,an,sendR,sendD};\n    });\n    applyGains();\n  }\n  function setComp(cmp,c){cmp.threshold.value=c.cmp?c.compThr:0;cmp.ratio.value=c.cmp?3:1;cmp.attack.value=0.005;cmp.release.value=0.12;}\n  function applyGains(){if(!ac)return;const anySolo=CH.some(c=>c.solo);CH.forEach(c=>{const n=N[c.id];if(!n)return;const aud=anySolo?c.solo:!c.mute;n.fader.gain.setTargetAtTime(faderToGain(c.fader)*(DCA[c.dca].gain/80)*(aud?1:0),ac.currentTime,0.02);});}\n  function applyChannel(c){if(!ac)return;const n=N[c.id];if(!n)return;n.trim.gain.setTargetAtTime(dbToLin(c.gain),ac.currentTime,0.02);\n    n.hpf.frequency.value=c.eq.hpfOn?c.eq.hpf:20;n.low.frequency.value=c.eq.low.f;n.low.gain.value=c.eq.low.g;n.lm.frequency.value=c.eq.loMid.f;n.lm.gain.value=c.eq.loMid.g;\n    n.hm.frequency.value=c.eq.hiMid.f;n.hm.gain.value=c.eq.hiMid.g;n.high.frequency.value=c.eq.high.f;n.high.gain.value=c.eq.high.g;n.pan.pan.value=c.pan/63;setComp(n.cmp,c);n.sendR.gain.value=c.rev/100;n.sendD.gain.value=c.dly/100;}\n\n  // ---------- vozes por família ----------\n  function env(g,t,a,d,pk){g.gain.setValueAtTime(0.0001,t);g.gain.linearRampToValueAtTime(pk,t+a);g.gain.exponentialRampToValueAtTime(0.0008,t+a+d);}\n  function noise(dur){const n=Math.floor(ac.sampleRate*dur),b=ac.createBuffer(1,n,ac.sampleRate),d=b.getChannelData(0);for(let i=0;i<n;i++)d[i]=Math.random()*2-1;const s=ac.createBufferSource();s.buffer=b;return s;}\n  const ROOTS=[110,87.31,130.81,98];const triad=r=>[r,r*1.1892,r*1.4983];\n  function trigger(c,dest,t,bar){const p=c.p||{},g=ac.createGain();g.connect(dest);const root=ROOTS[bar%4];\n    switch(c.fam){\n      case\"drumlow\":{const o=ac.createOscillator();o.type=\"sine\";o.frequency.setValueAtTime(p.f||110,t);o.frequency.exponentialRampToValueAtTime(p.to||45,t+0.12);o.connect(g);env(g,t,0.002,0.2,1);o.start(t);o.stop(t+0.3);break;}\n      case\"drummid\":{const o=ac.createOscillator();o.type=\"triangle\";o.frequency.setValueAtTime(p.f||150,t);o.frequency.exponentialRampToValueAtTime((p.f||150)*0.6,t+0.12);o.connect(g);env(g,t,0.002,0.18,0.7);o.start(t);o.stop(t+0.25);break;}\n      case\"snare\":{const s=noise(0.2),bp=ac.createBiquadFilter();bp.type=\"bandpass\";bp.frequency.value=p.bp||1800;s.connect(bp);bp.connect(g);env(g,t,0.001,0.15,0.7);s.start(t);s.stop(t+0.2);break;}\n      case\"hat\":{const s=noise(0.05),hp=ac.createBiquadFilter();hp.type=\"highpass\";hp.frequency.value=p.hp||7000;s.connect(hp);hp.connect(g);env(g,t,0.001,0.04,0.32);s.start(t);s.stop(t+0.06);break;}\n      case\"cymbal\":{const s=noise(0.5),hp=ac.createBiquadFilter();hp.type=\"highpass\";hp.frequency.value=p.hp||5000;s.connect(hp);hp.connect(g);env(g,t,0.002,0.45,0.4);s.start(t);s.stop(t+0.5);break;}\n      case\"shaker\":{const s=noise(0.08),hp=ac.createBiquadFilter();hp.type=\"highpass\";hp.frequency.value=p.hp||3500;s.connect(hp);hp.connect(g);env(g,t,0.001,0.06,0.3);s.start(t);s.stop(t+0.09);break;}\n      case\"cuica\":{const o=ac.createOscillator();o.type=\"sawtooth\";o.frequency.setValueAtTime(300,t);o.frequency.linearRampToValueAtTime(600,t+0.12);o.frequency.linearRampToValueAtTime(320,t+0.24);const bp=ac.createBiquadFilter();bp.type=\"bandpass\";bp.frequency.value=500;bp.Q.value=6;o.connect(bp);bp.connect(g);env(g,t,0.01,0.22,0.4);o.start(t);o.stop(t+0.26);break;}\n      case\"bass\":{const o=ac.createOscillator();o.type=\"sawtooth\";o.frequency.value=root/2;const lp=ac.createBiquadFilter();lp.type=\"lowpass\";lp.frequency.value=500;o.connect(lp);lp.connect(g);env(g,t,0.004,0.28,0.6);o.start(t);o.stop(t+0.32);break;}\n      case\"pluck\":{triad(root).forEach(f=>{const o=ac.createOscillator();o.type=\"sawtooth\";o.frequency.value=f*(p.m||2);const lp=ac.createBiquadFilter();lp.type=\"lowpass\";lp.frequency.value=p.lp||2500;o.connect(lp);const gg=ac.createGain();lp.connect(gg);gg.connect(dest);env(gg,t,0.005,0.3,0.16);o.start(t);o.stop(t+0.35);});break;}\n      case\"pad\":{triad(root).forEach(f=>{const o=ac.createOscillator();o.type=\"triangle\";o.frequency.value=f*(p.m||2);o.detune.value=Math.random()*6-3;const gg=ac.createGain();o.connect(gg);gg.connect(dest);env(gg,t,0.05,1.6,0.13);o.start(t);o.stop(t+1.7);});break;}\n      case\"lead\":{ // VOZ: síntese de formantes (vogal \"ah\") + vibrato, registro de voz\n        const mel=[root*2,root*2.5,root*3,root*2.25];const base=mel[bar%4];\n        const o=ac.createOscillator();o.type=\"sawtooth\";o.frequency.value=base;\n        const lfo=ac.createOscillator();lfo.type=\"sine\";lfo.frequency.value=5.5;const lg=ac.createGain();lg.gain.value=base*0.013;lfo.connect(lg);lg.connect(o.frequency);lfo.start(t);lfo.stop(t+0.75);\n        const F=[[700,9,1],[1150,10,0.7],[2750,11,0.35]];const mix=ac.createGain();\n        F.forEach(([f,q,a])=>{const bp=ac.createBiquadFilter();bp.type=\"bandpass\";bp.frequency.value=f;bp.Q.value=q;const fg=ac.createGain();fg.gain.value=a;o.connect(bp);bp.connect(fg);fg.connect(mix);});\n        mix.connect(g);env(g,t,0.05,0.55,0.55);o.start(t);o.stop(t+0.65);break;}\n      case\"harm\":{ // CORO: formantes suaves em terça acima, mais velado\n        const base=root*2.5;const o=ac.createOscillator();o.type=\"sawtooth\";o.frequency.value=base;\n        const mix=ac.createGain();[[600,8,1],[1000,9,0.6]].forEach(([f,q,a])=>{const bp=ac.createBiquadFilter();bp.type=\"bandpass\";bp.frequency.value=f;bp.Q.value=q;const fg=ac.createGain();fg.gain.value=a;o.connect(bp);bp.connect(fg);fg.connect(mix);});\n        mix.connect(g);env(g,t,0.07,0.6,0.28);o.start(t);o.stop(t+0.7);break;}\n    }\n  }\n  let step=0,bar=0,nextTime=0,timer=null,playing=false;const BPM=100,stepDur=60/BPM/4;\n  function scheduler(){while(nextTime<ac.currentTime+0.12){CH.forEach(c=>{if(c.pat&&c.pat[step])trigger(c,N[c.id].trim,nextTime,bar);});step++;if(step>=16){step=0;bar++;}nextTime+=stepDur;}timer=setTimeout(scheduler,25);}\n  // ---------- ÁUDIO REAL (stems) ----------\n  const bufCache={}; let realSources=[];\n  async function loadBuf(url){ if(bufCache[url]) return bufCache[url]; const r=await fetch(url); if(!r.ok) throw new Error(\"HTTP \"+r.status); const ab=await r.arrayBuffer(); const b=await ac.decodeAudioData(ab); bufCache[url]=b; return b; }\n  async function playRealStart(){\n    const g=GEN[genre], base=SB+g.folder+\"/\";\n    $(\"play\").textContent=\"carregando áudio…\"; $(\"play\").disabled=true; $(\"srcTag\").textContent=\"baixando \"+CH.length+\" pistas…\";\n    try{\n      const bufs=await Promise.all(CH.map(c=>loadBuf(base+encodeURIComponent(c.url))));\n      const t0=ac.currentTime+0.12; realSources=[];\n      CH.forEach((c,i)=>{ const s=ac.createBufferSource(); s.buffer=bufs[i]; s.loop=true; s.connect(N[c.id].trim); s.start(t0); realSources.push(s); });\n      playing=true; $(\"play\").textContent=\"■ Parar\"; $(\"play\").classList.add(\"stop\"); $(\"srcTag\").textContent=\"áudio real: \"+g.label.replace(/🎵 /,\"\");\n    }catch(e){ $(\"srcTag\").textContent=\"erro ao carregar áudio\"; toast(\"Erro no áudio: \"+e.message); $(\"play\").textContent=\"▶ Tocar\"; }\n    $(\"play\").disabled=false;\n  }\n  function playRealStop(){ realSources.forEach(s=>{try{s.stop();}catch(e){}}); realSources=[]; playing=false; $(\"play\").textContent=\"▶ Tocar\"; $(\"play\").classList.remove(\"stop\"); }\n  $(\"play\").onclick=async()=>{if(ac.state===\"suspended\")await ac.resume();\n    if(GEN[genre].real){ if(!playing) playRealStart(); else playRealStop(); return; }\n    if(!playing){playing=true;$(\"play\").textContent=\"■ Parar\";$(\"play\").classList.add(\"stop\");step=0;bar=0;nextTime=ac.currentTime+0.06;scheduler();}\n    else{playing=false;$(\"play\").textContent=\"▶ Tocar\";$(\"play\").classList.remove(\"stop\");clearTimeout(timer);}};\n\n  // ---------- genre selector ----------\n  function renderGenres(){const g=$(\"genres\");g.innerHTML=\"\";GKEYS.forEach(k=>{const b=document.createElement(\"button\");b.className=\"gbtn\"+(k===genre?\" on\":\"\");b.textContent=GEN[k].label;b.onclick=()=>switchGenre(k);g.appendChild(b);});}\n  function switchGenre(k){if(k===genre)return;\n    if(playing){ if(GEN[genre].real)playRealStop(); else {playing=false;clearTimeout(timer);} $(\"play\").textContent=\"▶ Tocar\";$(\"play\").classList.remove(\"stop\"); }\n    genre=k;CH=GEN[k].ch();DCA=GEN[k].dca.map(d=>Object.assign({gain:80},d));selId=null;$(\"selpanel\").classList.remove(\"show\");\n    if(ac)buildChannels();renderGenres();render();mi=0;paintM();toast(\"Gênero: \"+GEN[k].label);}\n\n  // ---------- selected channel EQ ----------\n  let selId=null;const cv=$(\"eqcanvas\"),cx=cv.getContext(\"2d\");\n  const fx=f=>{const mn=Math.log10(20),mx=Math.log10(20000);return (Math.log10(f)-mn)/(mx-mn);};\n  const xf=(x,w)=>{const mn=Math.log10(20),mx=Math.log10(20000);return Math.pow(10,mn+(x/w)*(mx-mn));};\n  let handles=[];\n  // Redraw coalescing (iPad): dragging an EQ handle / gate / comp encoder fires many pointermove\n  // events; each drawEQ() reallocates and repaints the canvas. Doing that per event starves the\n  // main thread on iPad so controls lag. drawEQ() now coalesces to one repaint per animation frame\n  // (rAF), with a setTimeout safety-net in case requestAnimationFrame is throttled.\n  let _eqReq=0,_eqTo=0;\n  function _flushEQ(){ if(_eqReq){cancelAnimationFrame(_eqReq);_eqReq=0;} if(_eqTo){clearTimeout(_eqTo);_eqTo=0;} renderEQ(); }\n  function drawEQ(){ if(_eqReq||_eqTo)return; _eqReq=requestAnimationFrame(_flushEQ); _eqTo=setTimeout(_flushEQ,60); }\n  function renderEQ(){if(!selId)return;const c=by(selId),n=N[selId];if(!n)return;const rr=cv.getBoundingClientRect(),w=rr.width,h=rr.height;if(w<2)return;cv.width=w*2;cv.height=h*2;cx.setTransform(2,0,0,2,0,0);cx.clearRect(0,0,w,h);\n    cx.strokeStyle=\"#182339\";cx.fillStyle=\"#4a5a78\";cx.font=\"9px system-ui\";cx.textAlign=\"center\";[30,100,300,1000,3000,10000].forEach(f=>{const x=fx(f)*w;cx.beginPath();cx.moveTo(x,0);cx.lineTo(x,h);cx.stroke();cx.fillText(f>=1000?f/1000+\"k\":f,x,h-2);});\n    for(let d=-15;d<=15;d+=5){const y=h/2-d/18*h/2;cx.strokeStyle=d===0?\"#2a3a58\":\"#141e30\";cx.beginPath();cx.moveTo(0,y);cx.lineTo(w,y);cx.stroke();cx.fillStyle=\"#3a4a66\";cx.textAlign=\"left\";cx.fillText((d>0?\"+\":\"\")+d,2,y-2);}\n    const NP=160,freqs=new Float32Array(NP);for(let i=0;i<NP;i++)freqs[i]=xf((i/(NP-1))*w,w);const total=new Float32Array(NP).fill(1),mag=new Float32Array(NP),ph=new Float32Array(NP);\n    [n.hpf,n.low,n.lm,n.hm,n.high].forEach(b=>{b.getFrequencyResponse(freqs,mag,ph);for(let i=0;i<NP;i++)total[i]*=mag[i];});\n    cx.beginPath();for(let i=0;i<NP;i++){const x=(i/(NP-1))*w,db=20*Math.log10(total[i]||0.0001),y=h/2-clamp(db,-18,18)/18*h/2;i?cx.lineTo(x,y):cx.moveTo(x,y);}cx.strokeStyle=c.color;cx.lineWidth=2.4;cx.stroke();cx.lineTo(w,h/2);cx.lineTo(0,h/2);cx.closePath();cx.fillStyle=c.color+\"18\";cx.fill();\n    handles=[];const hpt=(f,gv,key,lbl,col)=>{const x=fx(f)*w,y=h/2-clamp(gv,-18,18)/18*h/2;cx.fillStyle=col;cx.beginPath();cx.arc(x,y,7,0,7);cx.fill();cx.fillStyle=\"#0b0f17\";cx.font=\"700 8px system-ui\";cx.textAlign=\"center\";cx.fillText(lbl,x,y+3);handles.push({x,y,key,w,h});};\n    if(c.eq.hpfOn)hpt(c.eq.hpf,-6,\"hpf\",\"H\",\"#f59e0b\");hpt(c.eq.low.f,c.eq.low.g,\"low\",\"L\",\"#22c55e\");hpt(c.eq.loMid.f,c.eq.loMid.g,\"loMid\",\"1\",\"#22d3ee\");hpt(c.eq.hiMid.f,c.eq.hiMid.g,\"hiMid\",\"2\",\"#3b82f6\");hpt(c.eq.high.f,c.eq.high.g,\"high\",\"H\",\"#a855f7\");}\n  let eqDrag=null;\n  const eqPos=e=>{const r=cv.getBoundingClientRect();return{x:(e.touches?e.touches[0].clientX:e.clientX)-r.left,y:(e.touches?e.touches[0].clientY:e.clientY)-r.top};};\n  cv.addEventListener(\"mousedown\",e=>eqDown(e));cv.addEventListener(\"touchstart\",e=>eqDown(e),{passive:false});\n  function eqDown(e){const p=eqPos(e);for(const h of handles){if(Math.hypot(p.x-h.x,p.y-h.y)<13){eqDrag=h;e.preventDefault();return;}}}\n  window.addEventListener(\"mousemove\",e=>eqMove(e));window.addEventListener(\"touchmove\",e=>eqMove(e),{passive:false});window.addEventListener(\"mouseup\",()=>eqDrag=null);window.addEventListener(\"touchend\",()=>eqDrag=null);\n  function eqMove(e){if(!eqDrag||!selId)return;const c=by(selId),p=eqPos(e);const f=clamp(xf(clamp(p.x,0,eqDrag.w),eqDrag.w),20,20000),g=clamp((eqDrag.h/2-p.y)/(eqDrag.h/2)*18,-15,15);\n    if(eqDrag.key===\"hpf\")c.eq.hpf=clamp(f,20,400);else if(eqDrag.key===\"low\"){c.eq.low.f=clamp(f,40,400);c.eq.low.g=g;}else if(eqDrag.key===\"loMid\"){c.eq.loMid.f=clamp(f,100,2000);c.eq.loMid.g=g;}else if(eqDrag.key===\"hiMid\"){c.eq.hiMid.f=clamp(f,800,8000);c.eq.hiMid.g=g;}else if(eqDrag.key===\"high\"){c.eq.high.f=clamp(f,2000,16000);c.eq.high.g=g;}\n    applyChannel(c);drawEQ();syncStripKnobs(c);check();e.preventDefault();}\n  function openSel(id){selId=id;const c=by(id);$(\"selpanel\").classList.add(\"show\");$(\"selChip\").style.background=c.color;$(\"selName\").textContent=c.nm;\n    $(\"tHpf\").classList.toggle(\"on\",c.eq.hpfOn);$(\"tHpf\").classList.toggle(\"amber\",c.eq.hpfOn);$(\"tGate\").classList.toggle(\"on\",c.gateOn);$(\"tComp\").classList.toggle(\"on\",c.cmp);\n    $(\"sGain\").value=c.gain;$(\"vGain\").textContent=c.gain+\" dB\";$(\"sGate\").value=c.gateThr;$(\"vGate\").textContent=c.gateThr;$(\"sComp\").value=c.compThr;$(\"vComp\").textContent=c.compThr;$(\"sRev\").value=c.rev;$(\"vRev\").textContent=c.rev;$(\"sDly\").value=c.dly;$(\"vDly\").textContent=c.dly;\n    CH.forEach(x=>{const s=document.querySelector(''.strip[data-id=\"''+x.id+''\"]'');if(s)s.classList.toggle(\"sel\",x.id===id);});drawEQ();}\n  $(\"selClose\").onclick=()=>{$(\"selpanel\").classList.remove(\"show\");selId=null;CH.forEach(x=>{const s=document.querySelector(''.strip[data-id=\"''+x.id+''\"]'');if(s)s.classList.remove(\"sel\");});};\n  $(\"tHpf\").onclick=()=>{const c=by(selId);c.eq.hpfOn=!c.eq.hpfOn;$(\"tHpf\").classList.toggle(\"on\",c.eq.hpfOn);$(\"tHpf\").classList.toggle(\"amber\",c.eq.hpfOn);applyChannel(c);drawEQ();check();};\n  $(\"tGate\").onclick=()=>{const c=by(selId);c.gateOn=!c.gateOn;$(\"tGate\").classList.toggle(\"on\",c.gateOn);check();};\n  $(\"tComp\").onclick=()=>{const c=by(selId);c.cmp=!c.cmp;$(\"tComp\").classList.toggle(\"on\",c.cmp);applyChannel(c);syncStripKnobs(c);check();};\n  const bindR=(idr,idv,set,suf)=>{$(idr).oninput=()=>{const c=by(selId);set(c,+$(idr).value);$(idv).textContent=$(idr).value+(suf||\"\");applyChannel(c);syncStripKnobs(c);check();};};\n  bindR(\"sGain\",\"vGain\",(c,v)=>c.gain=v,\" dB\");bindR(\"sGate\",\"vGate\",(c,v)=>c.gateThr=v);bindR(\"sComp\",\"vComp\",(c,v)=>c.compThr=v);bindR(\"sRev\",\"vRev\",(c,v)=>c.rev=v);bindR(\"sDly\",\"vDly\",(c,v)=>c.dly=v);\n\n  // ---------- board ----------\n  const KN={gain:{min:-12,max:24},hi:{min:-15,max:15},mid:{min:-15,max:15},lo:{min:-15,max:15},pan:{min:-63,max:63},fx:{min:0,max:100}};\n  const rotOf=(k,v)=>{const d=KN[k];return -140+(v-d.min)/(d.max-d.min)*280;};\n  const board=$(\"board\");\n  const quickVal=(c,k)=>({gain:c.gain,hi:c.eq.high.g,mid:c.eq.hiMid.g,lo:c.eq.low.g,pan:c.pan,fx:c.rev})[k];\n  function quickSet(c,k,v){if(k===\"gain\")c.gain=v;else if(k===\"hi\")c.eq.high.g=v;else if(k===\"mid\")c.eq.hiMid.g=v;else if(k===\"lo\")c.eq.low.g=v;else if(k===\"pan\")c.pan=v;else if(k===\"fx\")c.rev=v;}\n  function syncStripKnobs(c){[\"gain\",\"hi\",\"mid\",\"lo\",\"pan\",\"fx\"].forEach(k=>{const el=board.querySelector(''.dial[data-ch=\"''+c.id+''\"][data-k=\"''+k+''\"]'');if(el)el.style.setProperty(\"--rot\",rotOf(k,quickVal(c,k))+\"deg\");});}\n  const knob=(c,k,cls)=>`<div class=\"knob\"><div class=\"dial ${cls||''''}\" data-ch=\"${c.id}\" data-k=\"${k}\"></div><div class=\"kl\">${({gain:\"GAIN\",hi:\"HI\",mid:\"MID\",lo:\"LO\",pan:\"PAN\",fx:\"REV\"})[k]}</div></div>`;\n  function stripEl(c){const d=document.createElement(\"div\");d.className=\"strip\";d.dataset.id=c.id;\n    d.innerHTML=`<div class=\"cname\" style=\"background:${c.color}\">${c.nm}</div>${knob(c,\"gain\",\"g\")}<div class=\"rowk\">${knob(c,\"hi\",\"eq\")}${knob(c,\"mid\",\"eq\")}${knob(c,\"lo\",\"eq\")}</div><div class=\"rowk\">${knob(c,\"pan\")}${knob(c,\"fx\",\"fx\")}</div>\n      <button class=\"mini sel\" data-sel=\"${c.id}\">SEL ▸ EQ</button>\n      <div class=\"faderwrap\"><div class=\"meter\"><i id=\"m-${c.id}\"></i></div><div class=\"fader\" data-f=\"${c.id}\"><div class=\"u\"></div><div class=\"cap\" id=\"cap-${c.id}\"></div></div></div>\n      <div class=\"fdb\" id=\"fdb-${c.id}\">${c.fader}</div>\n      <div class=\"btnrow\"><button class=\"sb solo ${c.solo?''on'':''''}\" data-solo=\"${c.id}\">S</button><button class=\"sb mute ${c.mute?''on'':''''}\" data-mute=\"${c.id}\">M</button></div>\n      <div class=\"assign\">DCA ${DCA[c.dca].nm}</div>`;return d;}\n  function fxEl(){const d=document.createElement(\"div\");d.className=\"strip fx\";d.innerHTML=`<div class=\"cname\" style=\"background:#a855f7\">FX RACK</div><div class=\"assign\">Reverb / Delay</div>\n    <div style=\"font-size:8px;color:var(--muted)\">REVERB</div><div class=\"faderwrap\"><div class=\"fader\" data-fx=\"rev\"><div class=\"u\"></div><div class=\"cap\" id=\"cap-fxrev\"></div></div></div><div class=\"fdb\" id=\"fdb-fxrev\">${FX.rev.ret}</div>\n    <div style=\"font-size:8px;color:var(--muted)\">DELAY</div><div class=\"faderwrap\"><div class=\"fader\" data-fx=\"dly\"><div class=\"u\"></div><div class=\"cap\" id=\"cap-fxdly\"></div></div></div><div class=\"fdb\" id=\"fdb-fxdly\">${FX.dly.ret}</div>`;return d;}\n  function dcaEl(d0,i){const el=document.createElement(\"div\");el.className=\"strip dca\";el.innerHTML=`<div class=\"cname\" style=\"background:${d0.color}\">${d0.nm}</div><div class=\"assign\">GRUPO/DCA</div><div style=\"flex:1\"></div><div class=\"faderwrap\"><div class=\"fader\" data-dca=\"${i}\"><div class=\"u\"></div><div class=\"cap\" id=\"cap-dca${i}\"></div></div></div><div class=\"fdb\" id=\"fdb-dca${i}\">${d0.gain}</div>`;return el;}\n  function masterEl(){const el=document.createElement(\"div\");el.className=\"strip master\";el.innerHTML=`<div class=\"cname\" style=\"background:var(--amber)\">MASTER</div><div class=\"assign\">saída L/R</div><div style=\"flex:1\"></div><div class=\"faderwrap\"><div class=\"meter\"><i id=\"m-main\"></i></div><div class=\"fader\" data-master=\"1\"><div class=\"u\"></div><div class=\"cap\" id=\"cap-main\"></div></div></div><div class=\"fdb\" id=\"fdb-main\">${master.fader}</div>`;return el;}\n  function render(){board.innerHTML=\"\";CH.forEach(c=>board.appendChild(stripEl(c)));board.appendChild(fxEl());DCA.forEach((d,i)=>board.appendChild(dcaEl(d,i)));board.appendChild(masterEl());placeCaps();}\n  function placeCaps(){CH.forEach(c=>{const cap=$(\"cap-\"+c.id);if(cap)cap.style.bottom=\"calc(\"+c.fader+\"% - 8px)\";syncStripKnobs(c);});DCA.forEach((d,i)=>{const cap=$(\"cap-dca\"+i);if(cap)cap.style.bottom=\"calc(\"+d.gain+\"% - 8px)\";});[\"rev\",\"dly\"].forEach(k=>{const cap=$(\"cap-fx\"+k);if(cap)cap.style.bottom=\"calc(\"+FX[k].ret+\"% - 8px)\";});const cm=$(\"cap-main\");if(cm)cm.style.bottom=\"calc(\"+master.fader+\"% - 8px)\";}\n  // Interação unificada (mouse + toque) por Pointer Events + delegação no board.\n  // Registrada UMA vez (setupBoard) — render() só reconstrói o visual, sem re-registrar listeners.\n  let knobDrag=null,faderDrag=null,lastY=0;\n  function faderSet(f,clientY){const r=f.getBoundingClientRect(),v=Math.round(clamp(1-(clientY-r.top)/r.height,0,1)*100);\n    if(f.dataset.f){const c=by(f.dataset.f);c.fader=v;$(\"fdb-\"+c.id).textContent=v;$(\"cap-\"+c.id).style.bottom=\"calc(\"+v+\"% - 8px)\";applyGains();}\n    else if(f.dataset.dca!==undefined){const i=+f.dataset.dca;DCA[i].gain=v;$(\"fdb-dca\"+i).textContent=v;$(\"cap-dca\"+i).style.bottom=\"calc(\"+v+\"% - 8px)\";applyGains();}\n    else if(f.dataset.fx){const k=f.dataset.fx;FX[k].ret=v;$(\"fdb-fx\"+k).textContent=v;$(\"cap-fx\"+k).style.bottom=\"calc(\"+v+\"% - 8px)\";if(ac)(k===\"rev\"?revRet:dlyRet).gain.value=v/100;}\n    else{master.fader=v;$(\"fdb-main\").textContent=v;$(\"cap-main\").style.bottom=\"calc(\"+v+\"% - 8px)\";if(ac)masterGain.gain.setTargetAtTime(faderToGain(v),ac.currentTime,0.02);}check();}\n  function setupBoard(){\n    board.addEventListener(\"pointerdown\",e=>{\n      const dial=e.target.closest(\".dial\");\n      if(dial){knobDrag={el:dial,chid:dial.dataset.ch,k:dial.dataset.k};lastY=e.clientY;board.setPointerCapture(e.pointerId);e.preventDefault();return;}\n      const f=e.target.closest(\".fader\");\n      if(f){faderDrag=f;board.setPointerCapture(e.pointerId);faderSet(f,e.clientY);e.preventDefault();return;}\n    });\n    board.addEventListener(\"pointermove\",e=>{\n      if(knobDrag){const dy=lastY-e.clientY;lastY=e.clientY;const c=by(knobDrag.chid),d=KN[knobDrag.k];if(!c)return;\n        quickSet(c,knobDrag.k,clamp(quickVal(c,knobDrag.k)+dy*(d.max-d.min)/150,d.min,d.max));\n        knobDrag.el.style.setProperty(\"--rot\",rotOf(knobDrag.k,quickVal(c,knobDrag.k))+\"deg\");applyChannel(c);if(selId===knobDrag.chid)drawEQ();check();e.preventDefault();}\n      else if(faderDrag){faderSet(faderDrag,e.clientY);e.preventDefault();}\n    });\n    const end=()=>{knobDrag=null;faderDrag=null;};\n    board.addEventListener(\"pointerup\",end);board.addEventListener(\"pointercancel\",end);\n    board.addEventListener(\"click\",e=>{\n      const s=e.target.closest(\"[data-sel]\");if(s){openSel(s.dataset.sel);return;}\n      const so=e.target.closest(\"[data-solo]\");if(so){const c=by(so.dataset.solo);c.solo=!c.solo;so.classList.toggle(\"on\",c.solo);applyGains();check();return;}\n      const mu=e.target.closest(\"[data-mute]\");if(mu){const c=by(mu.dataset.mute);c.mute=!c.mute;mu.classList.toggle(\"on\",c.mute);applyGains();check();return;}\n    });\n  }\n  function rms(an){if(!an)return 0;const a=new Uint8Array(an.fftSize);an.getByteTimeDomainData(a);let s=0;for(let i=0;i<a.length;i++){const v=(a[i]-128)/128;s+=v*v;}return Math.sqrt(s/a.length);}\n  function loop(){if(ac){CH.forEach(c=>{const el=$(\"m-\"+c.id);if(el&&N[c.id])el.style.height=clamp(rms(N[c.id].an)*180,0,100)+\"%\";});const mel=$(\"m-main\"),mb=$(\"mainMeter\"),mr=rms(masterAn);if(mel)mel.style.height=clamp(mr*180,0,100)+\"%\";if(mb)mb.style.width=clamp(mr*180,0,100)+\"%\";}requestAnimationFrame(loop);}\n\n  const bassCh=()=>by(\"bass\")||by(\"baixo\")||by(\"violao7\");\n  const M=[\n    {t:''Dê o play e <b>equilibre a base</b>: deixe o <b>1º fader</b> (bumbo/surdo) forte (~75+) e o <b>baixo</b> firme.'',ok:()=>CH[0].fader>=72&&bassCh()&&bassCh().fader>=68},\n    {t:''Trabalhe o <b>EQ</b>: abra o <b>SEL</b> de um canal, ligue o <b>HPF</b> e dê <b>brilho</b> (banda High acima de +3).'',ok:()=>CH.some(c=>c.eq.hpfOn&&c.eq.high.g>=3)},\n    {t:''<b>Efeito</b>: mande algum canal para o <b>Reverb</b> (knob REV ou fader Reverb no SEL acima de 30).'',ok:()=>CH.some(c=>c.rev>=30)},\n    {t:''<b>Panorama</b>: espalhe instrumentos nos lados (pan de algum canal &gt; 30 para cada lado).'',ok:()=>CH.some(c=>Math.abs(c.pan)>=30)},\n    {t:''<b>Grupo</b>: baixe o <b>1º DCA</b> abaixo de 70 e veja o grupo descer junto.'',ok:()=>DCA[0].gain<70},\n  ];\n  let mi=0;\n  function paintM(){const idx=$(\"mIdx\"),txt=$(\"mTxt\");if(mi>=M.length){idx.textContent=\"🎓\";txt.innerHTML=\"<b>Mix completa!</b> Gain, EQ paramétrico, efeitos, grupos e panorama — a experiência completa do console, em \"+GEN[genre].label+\".\";$(\"mSkip\").style.display=\"none\";return;}idx.textContent=\"MISSÃO \"+(mi+1)+\"/\"+M.length;txt.innerHTML=M[mi].t;}\n  function check(){if(mi>=M.length)return;try{if(M[mi].ok()){mi++;toast(mi>=M.length?\"Mix completa! 🎓\":\"Boa! ✔\");paintM();}}catch(e){}}\n  let tt;function toast(m){const el=$(\"toast\");el.innerHTML=m;el.classList.add(\"show\");clearTimeout(tt);tt=setTimeout(()=>el.classList.remove(\"show\"),1500);}\n  $(\"mSkip\").onclick=()=>{if(mi<M.length){mi++;paintM();}};\n\n  ac=new (window.AudioContext||window.webkitAudioContext)();buildMaster();buildChannels();\n  setupBoard();renderGenres();render();paintM();requestAnimationFrame(loop);\n\n  // ---- FIT: escala a mesa inteira para caber na tela (sem scroll horizontal no desktop/tablet) ----\n  function fitConsole(){\n    const el=document.querySelector(\".fit\"); if(!el) return;\n    const IW=window.innerWidth, IH=window.innerHeight;\n    if(IW<760){ el.style.width=\"100%\"; el.style.zoom=\"\"; document.body.style.justifyContent=\"flex-start\"; }\n    else{\n      el.style.width=\"max-content\"; el.style.zoom=\"\";\n      const DW=el.offsetWidth, DH=el.offsetHeight;\n      // Em fullscreen o iframe 16:9 do player fica MAIS ALTO que a tela real. Usamos screen.height\n      // (altura real), não window.innerHeight (altura inflada do iframe), e alinhamos ao topo.\n      const scrH=(window.screen&&screen.height)||IH;\n      const iframeTaller=IH>scrH+8;\n      const visH=Math.min(IH,scrH);\n      const headerAllow=iframeTaller?84:(IH>700?40:6);\n      const effVh=Math.max(240, visH-headerAllow);\n      document.body.style.justifyContent=(iframeTaller||IH>700)?\"flex-start\":\"center\";\n      let s=Math.min((IW-18)/DW, effVh/DH); s=Math.max(0.35, Math.min(s, 2.2));\n      el.style.zoom=s;\n    }\n    try{ drawEQ(); }catch(e){}\n  }\n  window.addEventListener(\"resize\", fitConsole);\n  setTimeout(fitConsole, 50);\n})();\n</script>\n</body>\n</html>\n"}]'::jsonb, updated_at = now() where lesson_id = '5504c000-5011-4a00-9000-0000000000b2' and tipo = 'interactive';

-- pleno-ah-sq (Allen & Heath SQ)  <-  simuladores/som/allen-heath-sq.html  (24.8 KB)
update public.ai_animations set urls = '[{"html":"<!doctype html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>Simulador — Console Allen &amp; Heath SQ (SMU)</title>\n<style>\n  :root{--bg:#0a0d13;--panel:#141922;--panel2:#0d1119;--line:#232c3a;--ink:#e9edf4;--muted:#8b97a8;\n    --sq:#00b3d7;--amber:#f5a623;--green:#39d353;--red:#ff4d4d;--purple:#a855f7;--strip:#10151e}\n  *{box-sizing:border-box}html,body{margin:0}\n  body{background:var(--bg);color:var(--ink);font-family:\"Space Grotesk\",system-ui,-apple-system,\"Segoe UI\",Roboto,sans-serif;\n    -webkit-font-smoothing:antialiased;padding:6px;user-select:none;overflow-x:hidden;\n    min-height:100vh;display:flex;flex-direction:column;align-items:center;justify-content:center}\n  .fit{width:1400px;flex:0 0 auto}\n  @media(max-width:760px){ body{justify-content:flex-start} .fit{width:100%} }\n  /* iOS/iPad: trava o pan (arraste não vira gesto de sair da tela cheia) em tablet/desktop */\n  @media(min-width:760px){ body,.fit{touch-action:none} }\n  .brandbar{display:flex;align-items:center;gap:12px;background:linear-gradient(180deg,#11161f,#0b0f16);border:1px solid var(--line);border-radius:10px;padding:8px 14px;margin-bottom:8px}\n  .logo{font-weight:800;font-size:16px;letter-spacing:.5px}.logo b{color:var(--sq)}\n  .model{font-size:11px;color:var(--muted);letter-spacing:2px;border:1px solid var(--line);border-radius:5px;padding:3px 8px}\n  .spacer{flex:1}\n  .mission{display:flex;gap:9px;align-items:center;background:#0c1119;border:1px solid var(--line);border-radius:8px;padding:6px 10px;max-width:56%}\n  .mission .idx{font-size:9.5px;color:var(--sq);font-weight:800;white-space:nowrap}.mission .txt{font-size:11px;line-height:1.2}.mission .txt b{color:var(--sq)}\n  .mission button{font:inherit;font-size:10px;color:var(--muted);background:transparent;border:1px solid var(--line);border-radius:6px;padding:4px 7px;cursor:pointer}\n\n  .console{display:grid;grid-template-columns:1fr 360px;gap:8px}\n  @media(max-width:900px){.console{grid-template-columns:1fr}}\n  .card{background:linear-gradient(180deg,var(--panel),var(--panel2));border:1px solid var(--line);border-radius:11px;padding:9px}\n\n  /* fader bay */\n  .layers{display:flex;gap:5px;flex-wrap:wrap;margin-bottom:8px}\n  .lyr{font:inherit;font-size:10px;font-weight:700;padding:6px 9px;border-radius:7px;border:1px solid var(--line);background:#0c1119;color:var(--muted);cursor:pointer}\n  .lyr.on{background:var(--sq);border-color:var(--sq);color:#04121a}\n  .bay{display:flex;gap:4px;overflow-x:auto}\n  .strip{flex:0 0 66px;background:linear-gradient(180deg,var(--strip),#0c121b);border:1px solid var(--line);border-radius:8px;padding:5px 4px;display:flex;flex-direction:column;align-items:center;gap:4px}\n  .strip.sel{border-color:var(--sq);box-shadow:0 0 0 1px var(--sq) inset}\n  .strip.master{flex-basis:72px;border-color:var(--amber)}\n  .cn{width:100%;height:16px;border-radius:3px;color:#04121a;font-size:8.5px;font-weight:800;display:flex;align-items:center;justify-content:center;white-space:nowrap;overflow:hidden}\n  .cnum{font-size:7px;color:var(--muted)}\n  .selbtn{font:inherit;font-size:8px;font-weight:800;width:100%;padding:3px 0;border-radius:4px;border:1px solid var(--line);background:#0c1119;color:var(--muted);cursor:pointer}\n  .selbtn.on{background:var(--sq);border-color:var(--sq);color:#04121a}\n  .fw{display:flex;gap:3px;height:120px;align-items:stretch}\n  .mtr{width:5px;border-radius:2px;background:#05070d;border:1px solid #1a2333;position:relative;overflow:hidden}\n  .mtr i{position:absolute;left:0;right:0;bottom:0;height:0%;background:linear-gradient(0deg,var(--green),var(--green) 62%,var(--amber) 85%,var(--red))}\n  .fdr{width:22px;position:relative;background:linear-gradient(90deg,#090d14,#0c111a,#090d14);border-radius:4px;border:1px solid #1a2333;cursor:ns-resize;touch-action:none}\n  .fdr .u{position:absolute;left:0;right:0;top:24%;height:1px;background:#39455c}\n  .cap{position:absolute;left:-4px;right:-4px;height:16px;border-radius:3px;background:linear-gradient(180deg,#eef1f6,#aab4c6 46%,#5a6982 54%,#8391a6);border:1px solid #0006;cursor:grab}\n  .cap::after{content:\"\";position:absolute;left:3px;right:3px;top:50%;height:2px;transform:translateY(-50%);background:#05070d;border-radius:2px}\n  .fdb{font-size:8px;color:var(--muted);font-weight:700}\n  .row2{display:flex;gap:3px;width:100%}\n  .kb{flex:1;font:inherit;font-size:8px;font-weight:800;padding:3px 0;border-radius:4px;border:1px solid var(--line);background:#0c1119;color:var(--muted);cursor:pointer}\n  .kb.pafl.on{background:var(--green);border-color:var(--green);color:#04121a}\n  .kb.mute.on{background:var(--red);border-color:var(--red);color:#fff}\n\n  /* right: screen + superstrip + softkeys */\n  .screenwrap{display:flex;flex-direction:column;gap:8px}\n  .scr{background:#05080d;border:1px solid #1a2333;border-radius:9px;padding:8px}\n  .scrhead{display:flex;align-items:center;gap:8px;margin-bottom:6px}\n  .scrhead .chip{width:9px;height:18px;border-radius:2px;background:var(--sq)}\n  .scrhead .nm{font-size:13px;font-weight:800}.scrhead .sub{font-size:9px;color:var(--muted)}\n  #eq{width:100%;height:120px;background:#03060b;border:1px solid #16202e;border-radius:6px;display:block;touch-action:none}\n  .dynrow{display:flex;gap:8px;margin-top:6px}\n  .dyncell{flex:1;background:#0a0f17;border:1px solid #16202e;border-radius:6px;padding:5px 7px}\n  .dyncell .t{font-size:8.5px;color:var(--muted);letter-spacing:.5px}\n  .dyncell .grbar{height:7px;border-radius:3px;background:#05070d;margin-top:3px;overflow:hidden}.dyncell .grbar i{display:block;height:100%;width:0%;background:var(--sq)}\n\n  .superstrip{background:linear-gradient(180deg,#12171f,#0c1119);border:1px solid var(--line);border-radius:9px;padding:8px}\n  .sslabel{font-size:9px;color:var(--muted);letter-spacing:1.5px;text-transform:uppercase;margin-bottom:6px}\n  .ssgrid{display:grid;grid-template-columns:repeat(5,1fr);gap:8px 4px}\n  .enc{display:flex;flex-direction:column;align-items:center;gap:2px}\n  .dial{width:40px;height:40px;border-radius:50%;position:relative;cursor:ns-resize;touch-action:none;background:radial-gradient(circle at 50% 30%,#2b3a52,#141b26 72%);border:2px solid var(--sq);box-shadow:0 0 6px #00b3d766}\n  .dial.eq{border-color:var(--amber);box-shadow:0 0 6px #f5a62366}\n  .dial.dyn{border-color:var(--purple);box-shadow:0 0 6px #a855f766}\n  .dial::after{content:\"\";position:absolute;left:50%;top:4px;width:2.5px;height:13px;border-radius:2px;background:#eaf6ff;transform-origin:50% 16px;transform:translateX(-50%) rotate(var(--rot,0deg))}\n  .el{font-size:8px;color:var(--muted);text-align:center}.ev{font-size:8.5px;font-weight:800}\n  .ssbtns{display:flex;gap:5px;margin-top:8px;flex-wrap:wrap}\n  .ssb{font:inherit;font-size:9px;font-weight:800;padding:6px 9px;border-radius:6px;border:1px solid var(--line);background:#0c1119;color:var(--muted);cursor:pointer}\n  .ssb.on{background:var(--sq);border-color:var(--sq);color:#04121a}\n\n  .softkeys{background:linear-gradient(180deg,#12171f,#0c1119);border:1px solid var(--line);border-radius:9px;padding:8px}\n  .skgrid{display:grid;grid-template-columns:repeat(8,1fr);gap:4px}\n  .sk{font:inherit;font-size:8px;font-weight:700;padding:6px 2px;border-radius:5px;border:1px solid var(--line);background:#0c1119;color:var(--muted);cursor:pointer;text-align:center;line-height:1}\n  .sk.on{color:#04121a}\n  .toast{position:fixed;left:50%;bottom:14px;transform:translateX(-50%) translateY(20px);background:#0c1119;border:1px solid var(--sq);color:var(--ink);padding:9px 15px;border-radius:9px;font-size:12px;opacity:0;transition:.25s;pointer-events:none;z-index:50}\n  .toast.show{opacity:1;transform:translateX(-50%) translateY(0)}.toast b{color:var(--sq)}\n</style>\n</head>\n<body>\n <div class=\"fit\">\n  <div class=\"brandbar\">\n    <div class=\"logo\">ALLEN &amp; <b>HEATH</b></div>\n    <div class=\"model\">SQ-6 · SIMULADOR SMU</div>\n    <div class=\"spacer\"></div>\n    <div class=\"mission\"><span class=\"idx\" id=\"mIdx\">MISSÃO</span><span class=\"txt\" id=\"mTxt\">—</span><button id=\"mSkip\">Pular</button></div>\n  </div>\n\n  <div class=\"console\">\n    <!-- FADER BAY -->\n    <div class=\"card\">\n      <div class=\"layers\" id=\"layers\"></div>\n      <div class=\"bay\" id=\"bay\"></div>\n    </div>\n\n    <!-- SCREEN + SUPERSTRIP + SOFTKEYS -->\n    <div class=\"screenwrap\">\n      <div class=\"scr\">\n        <div class=\"scrhead\"><span class=\"chip\" id=\"scrChip\"></span><div><div class=\"nm\" id=\"scrName\">—</div><div class=\"sub\" id=\"scrSub\">Processing · PEQ 4 bandas</div></div></div>\n        <canvas id=\"eq\"></canvas>\n        <div class=\"dynrow\">\n          <div class=\"dyncell\"><div class=\"t\">GATE</div><div class=\"grbar\"><i id=\"gateBar\"></i></div></div>\n          <div class=\"dyncell\"><div class=\"t\">COMP · GR</div><div class=\"grbar\"><i id=\"compBar\"></i></div></div>\n        </div>\n      </div>\n\n      <div class=\"superstrip\">\n        <div class=\"sslabel\">SuperStrip — canal selecionado</div>\n        <div class=\"ssgrid\" id=\"ssgrid\"></div>\n        <div class=\"ssbtns\">\n          <button class=\"ssb\" id=\"bPol\">Ø POL</button>\n          <button class=\"ssb\" id=\"bHpf\">HPF</button>\n          <button class=\"ssb\" id=\"bGate\">GATE</button>\n          <button class=\"ssb\" id=\"bComp\">COMP</button>\n        </div>\n      </div>\n\n      <div class=\"softkeys\">\n        <div class=\"sslabel\">16 SoftKeys</div>\n        <div class=\"skgrid\" id=\"skgrid\"></div>\n      </div>\n    </div>\n  </div>\n </div>\n  <div class=\"toast\" id=\"toast\"></div>\n\n<script>\n\"use strict\";\n(function(){\n  const $=id=>document.getElementById(id);\n  const clamp=(v,a,b)=>Math.max(a,Math.min(b,v));\n  // ---- canais (nomes de banda p/ casar com o áudio depois) ----\n  const NAMES=[\"Kick\",\"Snare\",\"Hi-Hat\",\"OH L\",\"OH R\",\"Bass\",\"Gtr L\",\"Gtr R\",\"Keys L\",\"Keys R\",\"Lead Voc\",\"Voc 2\",\"Sax\",\"Trumpet\",\"Perc\",\"Playback\",\"Amb L\",\"Amb R\",\"Talk\",\"Click\",\"Spare 1\",\"Spare 2\",\"Spare 3\",\"Spare 4\"];\n  const COLS=[\"#ff4d4d\",\"#f97316\",\"#f5a623\",\"#eab308\",\"#84cc16\",\"#39d353\",\"#14b8a6\",\"#00b3d7\",\"#3b82f6\",\"#6366f1\",\"#a855f7\",\"#ec4899\",\"#f43f5e\",\"#fb7185\",\"#22d3ee\",\"#4ade80\",\"#60a5fa\",\"#818cf8\",\"#c084fc\",\"#f472b6\",\"#94a3b8\",\"#94a3b8\",\"#94a3b8\",\"#94a3b8\"];\n  const CH=NAMES.map((nm,i)=>({i,nm,color:COLS[i],trim:28,hpfOn:i>3,hpf:100,gateOn:false,gate:-40,comp:false,compThr:-22,pol:false,pan:0,\n    peq:[{f:120,g:0,q:1,type:\"lowshelf\"},{f:450,g:0,q:1.2,type:\"peaking\"},{f:2500,g:0,q:1.2,type:\"peaking\"},{f:8000,g:0,q:1,type:\"highshelf\"}],\n    fader:70,pafl:false,mute:false}));\n  const MASTER={fader:78};\n  let sel=10; // Lead Voc\n  const LAYERS=[{k:\"a\",label:\"Ch 1–12\",range:[0,12]},{k:\"b\",label:\"Ch 13–24\",range:[12,24]},{k:\"mix\",label:\"Mixes\"},{k:\"fx\",label:\"FX\"},{k:\"dca\",label:\"DCA\"},{k:\"midi\",label:\"MIDI\"}];\n  let layer=\"a\";\n\n  // ---- SuperStrip encoders ----\n  const ENC=[\n    {k:\"trim\",label:\"TRIM\",cls:\"\",min:-5,max:60,fmt:v=>Math.round(v)},\n    {k:\"hpf\",label:\"HPF\",cls:\"\",min:20,max:400,log:true,fmt:v=>Math.round(v)+\"\"},\n    {k:\"peq0\",label:\"LF\",cls:\"eq\",min:-15,max:15,fmt:v=>(v>0?\"+\":\"\")+Math.round(v)},\n    {k:\"peq1\",label:\"LM\",cls:\"eq\",min:-15,max:15,fmt:v=>(v>0?\"+\":\"\")+Math.round(v)},\n    {k:\"peq2\",label:\"HM\",cls:\"eq\",min:-15,max:15,fmt:v=>(v>0?\"+\":\"\")+Math.round(v)},\n    {k:\"peq3\",label:\"HF\",cls:\"eq\",min:-15,max:15,fmt:v=>(v>0?\"+\":\"\")+Math.round(v)},\n    {k:\"gate\",label:\"GATE\",cls:\"dyn\",min:-70,max:0,fmt:v=>Math.round(v)},\n    {k:\"comp\",label:\"COMP\",cls:\"dyn\",min:-40,max:0,fmt:v=>Math.round(v)},\n    {k:\"pan\",label:\"PAN\",cls:\"\",min:-63,max:63,fmt:v=>Math.abs(v)<2?\"C\":(v<0?\"L\":\"R\")+Math.round(Math.abs(v))},\n    {k:\"dly\",label:\"DELAY\",cls:\"\",min:0,max:200,fmt:v=>Math.round(v)+\"ms\"},\n  ];\n  function encVal(c,k){return {trim:c.trim,hpf:c.hpf,peq0:c.peq[0].g,peq1:c.peq[1].g,peq2:c.peq[2].g,peq3:c.peq[3].g,gate:c.gate,comp:c.compThr,pan:c.pan,dly:c.dly||0}[k];}\n  function encSet(c,k,v){if(k===\"trim\")c.trim=v;else if(k===\"hpf\")c.hpf=Math.round(v);else if(k.startsWith(\"peq\"))c.peq[+k.slice(3)].g=v;else if(k===\"gate\")c.gate=Math.round(v);else if(k===\"comp\")c.compThr=Math.round(v);else if(k===\"pan\")c.pan=Math.round(v);else if(k===\"dly\")c.dly=Math.round(v);}\n  function encRot(e,v){let t;if(e.log){t=(Math.log(v)-Math.log(e.min))/(Math.log(e.max)-Math.log(e.min));}else t=(v-e.min)/(e.max-e.min);return -140+t*280;}\n\n  // ---- SOFTKEYS ----\n  const SK=[[\"Mute Bat\",\"mg0\"],[\"Mute Voz\",\"mg1\"],[\"Mute FX\",\"mg2\"],[\"Mute All\",\"mgA\"],[\"Scene ◀\",\"scL\"],[\"Scene ▶\",\"scR\"],[\"Store\",\"st\"],[\"Tap\",\"tap\"],\n            [\"PAFL Clr\",\"pc\"],[\"Copy\",\"cp\"],[\"Paste\",\"ps\"],[\"Reset\",\"rs\"],[\"Talk\",\"tk\"],[\"FX Mute\",\"fx\"],[\"View\",\"vw\"],[\"Home\",\"hm\"]];\n  const skState={};\n\n  // ---------- RENDER ----------\n  function renderLayers(){const el=$(\"layers\");el.innerHTML=\"\";LAYERS.forEach(l=>{const b=document.createElement(\"button\");b.className=\"lyr\"+(l.k===layer?\" on\":\"\");b.textContent=l.label;b.onclick=()=>{layer=l.k;renderLayers();renderBay();};el.appendChild(b);});}\n  function bayChannels(){const l=LAYERS.find(x=>x.k===layer);if(l&&l.range)return CH.slice(l.range[0],l.range[1]);\n    // camadas não-input: mostra rótulos genéricos reaproveitando a área\n    return CH.slice(0,12).map((c,i)=>({...c,nm:(layer===\"mix\"?\"Mix \"+(i+1):layer===\"fx\"?\"FX \"+(i+1):layer===\"dca\"?\"DCA \"+(i+1):\"MIDI \"+(i+1)),ghost:true,i:c.i}));}\n  function renderBay(){\n    const bay=$(\"bay\");bay.innerHTML=\"\";\n    bayChannels().forEach(c=>{\n      const d=document.createElement(\"div\");d.className=\"strip\"+(c.i===sel&&!c.ghost?\" sel\":\"\");d.dataset.i=c.i;\n      d.innerHTML=`<div class=\"cn\" style=\"background:${c.color}\">${c.nm}</div><div class=\"cnum\">CH ${c.i+1}</div>\n        <button class=\"selbtn ${c.i===sel&&!c.ghost?''on'':''''}\" data-sel=\"${c.i}\">SEL</button>\n        <div class=\"fw\"><div class=\"mtr\"><i id=\"m-${c.i}\"></i></div><div class=\"fdr\" data-f=\"${c.i}\"><div class=\"u\"></div><div class=\"cap\" id=\"cap-${c.i}\"></div></div></div>\n        <div class=\"fdb\" id=\"fdb-${c.i}\">${c.fader}</div>\n        <div class=\"row2\"><button class=\"kb pafl ${c.pafl?''on'':''''}\" data-pafl=\"${c.i}\">PAFL</button><button class=\"kb mute ${c.mute?''on'':''''}\" data-mute=\"${c.i}\">MUTE</button></div>`;\n      bay.appendChild(d);\n    });\n    // master\n    const m=document.createElement(\"div\");m.className=\"strip master\";\n    m.innerHTML=`<div class=\"cn\" style=\"background:var(--amber)\">LR MAIN</div><div class=\"cnum\">MASTER</div><div class=\"selbtn\">SEL</div>\n      <div class=\"fw\"><div class=\"mtr\"><i id=\"m-main\"></i></div><div class=\"fdr\" data-master=\"1\"><div class=\"u\"></div><div class=\"cap\" id=\"cap-main\"></div></div></div>\n      <div class=\"fdb\" id=\"fdb-main\">${MASTER.fader}</div><div class=\"row2\"><button class=\"kb pafl\">PAFL</button></div>`;\n    bay.appendChild(m);\n    placeCaps();\n  }\n  function placeCaps(){bayChannels().forEach(c=>{const cap=$(\"cap-\"+c.i);if(cap)cap.style.bottom=\"calc(\"+c.fader+\"% - 8px)\";});const cm=$(\"cap-main\");if(cm)cm.style.bottom=\"calc(\"+MASTER.fader+\"% - 8px)\";}\n  // Delegação (Pointer Events) na fader bay — registrada UMA vez, sem vazamento a cada renderBay().\n  let bayFaderDrag=null;\n  function bayFaderSet(f,clientY){const r=f.getBoundingClientRect(),v=Math.round(clamp(1-(clientY-r.top)/r.height,0,1)*100);\n    if(f.dataset.master){MASTER.fader=v;$(\"fdb-main\").textContent=v;$(\"cap-main\").style.bottom=\"calc(\"+v+\"% - 8px)\";}\n    else{const c=CH[+f.dataset.f];c.fader=v;$(\"fdb-\"+c.i).textContent=v;$(\"cap-\"+c.i).style.bottom=\"calc(\"+v+\"% - 8px)\";}check();}\n  function setupBay(){const bay=$(\"bay\");\n    bay.addEventListener(\"pointerdown\",e=>{const f=e.target.closest(\".fdr\");if(f){bayFaderDrag=f;bay.setPointerCapture(e.pointerId);bayFaderSet(f,e.clientY);e.preventDefault();}});\n    bay.addEventListener(\"pointermove\",e=>{if(bayFaderDrag){bayFaderSet(bayFaderDrag,e.clientY);e.preventDefault();}});\n    const end=()=>bayFaderDrag=null;bay.addEventListener(\"pointerup\",end);bay.addEventListener(\"pointercancel\",end);\n    bay.addEventListener(\"click\",e=>{\n      const s=e.target.closest(\"[data-sel]\");if(s){sel=+s.dataset.sel;renderBay();renderStrip();drawEQ();return;}\n      const p=e.target.closest(\"[data-pafl]\");if(p){const c=CH[+p.dataset.pafl];c.pafl=!c.pafl;p.classList.toggle(\"on\",c.pafl);return;}\n      const m=e.target.closest(\"[data-mute]\");if(m){const c=CH[+m.dataset.mute];c.mute=!c.mute;m.classList.toggle(\"on\",c.mute);check();return;}\n    });}\n\n  function renderStrip(){\n    const c=CH[sel];$(\"scrChip\").style.background=c.color;$(\"scrName\").textContent=c.nm+\"  ·  CH \"+(c.i+1);\n    const g=$(\"ssgrid\");g.innerHTML=\"\";\n    ENC.forEach(e=>{const el=document.createElement(\"div\");el.className=\"enc\";\n      el.innerHTML=`<div class=\"dial ${e.cls}\" data-k=\"${e.k}\"></div><div class=\"el\">${e.label}</div><div class=\"ev\" id=\"ev-${e.k}\"></div>`;g.appendChild(el);});\n    ENC.forEach(e=>{const d=g.querySelector(''.dial[data-k=\"''+e.k+''\"]'');d.style.setProperty(\"--rot\",encRot(e,clamp(encVal(c,e.k),e.min,e.max))+\"deg\");$(\"ev-\"+e.k).textContent=e.fmt(encVal(c,e.k));});\n    $(\"bPol\").classList.toggle(\"on\",c.pol);$(\"bHpf\").classList.toggle(\"on\",c.hpfOn);$(\"bGate\").classList.toggle(\"on\",c.gateOn);$(\"bComp\").classList.toggle(\"on\",c.comp);\n  }\n  // Delegação (Pointer Events) nos encoders do SuperStrip — registrada UMA vez, sem vazamento a cada renderStrip().\n  let strEncDrag=null,strLastY=0;\n  function setupStrip(){const g=$(\"ssgrid\");\n    g.addEventListener(\"pointerdown\",e=>{const d=e.target.closest(\".dial\");if(!d)return;const en=ENC.find(x=>x.k===d.dataset.k);if(!en)return;\n      strEncDrag={el:d,k:d.dataset.k,e:en};strLastY=e.clientY;g.setPointerCapture(e.pointerId);e.preventDefault();});\n    g.addEventListener(\"pointermove\",e=>{if(!strEncDrag)return;const dy=strLastY-e.clientY;strLastY=e.clientY;const c=CH[sel],en=strEncDrag.e,k=strEncDrag.k;\n      encSet(c,k,clamp(encVal(c,k)+dy*(en.max-en.min)/150,en.min,en.max));strEncDrag.el.style.setProperty(\"--rot\",encRot(en,encVal(c,k))+\"deg\");\n      const ev=$(\"ev-\"+k);if(ev)ev.textContent=en.fmt(encVal(c,k));drawEQ();check();e.preventDefault();});\n    const end=()=>strEncDrag=null;g.addEventListener(\"pointerup\",end);g.addEventListener(\"pointercancel\",end);}\n  $(\"bPol\").onclick=()=>{CH[sel].pol=!CH[sel].pol;$(\"bPol\").classList.toggle(\"on\",CH[sel].pol);};\n  $(\"bHpf\").onclick=()=>{CH[sel].hpfOn=!CH[sel].hpfOn;$(\"bHpf\").classList.toggle(\"on\",CH[sel].hpfOn);drawEQ();check();};\n  $(\"bGate\").onclick=()=>{CH[sel].gateOn=!CH[sel].gateOn;$(\"bGate\").classList.toggle(\"on\",CH[sel].gateOn);check();};\n  $(\"bComp\").onclick=()=>{CH[sel].comp=!CH[sel].comp;$(\"bComp\").classList.toggle(\"on\",CH[sel].comp);check();};\n\n  // ---- SoftKeys ----\n  function renderSK(){const g=$(\"skgrid\");g.innerHTML=\"\";SK.forEach(([lbl,k])=>{const b=document.createElement(\"button\");b.className=\"sk\"+(skState[k]?\" on\":\"\");if(skState[k])b.style.background=k.startsWith(\"mg\")?\"#ff4d4d\":\"#00b3d7\";b.textContent=lbl;\n    b.onclick=()=>{skState[k]=!skState[k];if(k===\"tap\")skState[k]=false;renderSK();if(k.startsWith(\"mg\"))toast(\"Mute group: \"+lbl);check();};g.appendChild(b);});}\n\n  // ---- EQ screen (PEQ 4 bandas) ----\n  const cv=$(\"eq\"),cx=cv.getContext(\"2d\");\n  const fx=f=>{const mn=Math.log10(20),mx=Math.log10(20000);return (Math.log10(f)-mn)/(mx-mn);};\n  const xf=(x,w)=>{const mn=Math.log10(20),mx=Math.log10(20000);return Math.pow(10,mn+(x/w)*(mx-mn));};\n  // resposta aproximada (sem AudioContext): soma de sinos/shelves\n  function bandDb(b,f){const rt=f/b.f;if(b.type===\"peaking\"){const bw=b.g/(1+Math.pow((Math.log2(Math.max(0.001,rt)))*b.q*2,2));return bw;}\n    if(b.type===\"lowshelf\")return b.g/(1+Math.pow(f/b.f,2));return b.g/(1+Math.pow(b.f/f,2));}\n  let handles=[];\n  // Redraw coalescing (iPad): dragging an EQ handle / gate / comp encoder fires many pointermove\n  // events; each drawEQ() reallocates and repaints the canvas. Doing that per event starves the\n  // main thread on iPad so controls lag. drawEQ() now coalesces to one repaint per animation frame\n  // (rAF), with a setTimeout safety-net in case requestAnimationFrame is throttled.\n  let _eqReq=0,_eqTo=0;\n  function _flushEQ(){ if(_eqReq){cancelAnimationFrame(_eqReq);_eqReq=0;} if(_eqTo){clearTimeout(_eqTo);_eqTo=0;} renderEQ(); }\n  function drawEQ(){ if(_eqReq||_eqTo)return; _eqReq=requestAnimationFrame(_flushEQ); _eqTo=setTimeout(_flushEQ,60); }\n  function renderEQ(){const c=CH[sel];const rr=cv.getBoundingClientRect();const w=rr.width,h=rr.height;if(w<2)return;cv.width=w*2;cv.height=h*2;cx.setTransform(2,0,0,2,0,0);cx.clearRect(0,0,w,h);\n    cx.strokeStyle=\"#12202e\";cx.fillStyle=\"#3a4a5e\";cx.font=\"8px system-ui\";cx.textAlign=\"center\";[100,1000,10000].forEach(f=>{const x=fx(f)*w;cx.beginPath();cx.moveTo(x,0);cx.lineTo(x,h);cx.stroke();cx.fillText(f>=1000?f/1000+\"k\":f,x,h-1);});\n    for(let d=-12;d<=12;d+=6){const y=h/2-d/16*h/2;cx.strokeStyle=d===0?\"#243447\":\"#101c28\";cx.beginPath();cx.moveTo(0,y);cx.lineTo(w,y);cx.stroke();}\n    cx.beginPath();for(let px=0;px<=w;px+=2){const f=xf(px,w);let db=0;if(c.hpfOn&&f<c.hpf)db+=-24*Math.log10(c.hpf/f);c.peq.forEach(b=>db+=bandDb(b,f));const y=h/2-clamp(db,-14,14)/16*h/2;px?cx.lineTo(px,y):cx.moveTo(px,y);}\n    cx.strokeStyle=c.color;cx.lineWidth=2;cx.stroke();cx.lineTo(w,h/2);cx.lineTo(0,h/2);cx.closePath();cx.fillStyle=c.color+\"18\";cx.fill();\n    handles=[];const HN=[\"LF\",\"LM\",\"HM\",\"HF\"];const HC=[\"#f5a623\",\"#f5a623\",\"#f5a623\",\"#f5a623\"];\n    c.peq.forEach((b,i)=>{const x=fx(b.f)*w,y=h/2-clamp(b.g,-14,14)/16*h/2;cx.fillStyle=HC[i];cx.beginPath();cx.arc(x,y,6,0,7);cx.fill();cx.fillStyle=\"#04121a\";cx.font=\"700 7px system-ui\";cx.fillText(HN[i],x,y+2);handles.push({x,y,i,w,h});});}\n  let drag=null;\n  const pos=e=>{const r=cv.getBoundingClientRect();return{x:e.clientX-r.left,y:e.clientY-r.top};};\n  // Alças do EQ via Pointer Events + pointer capture (mouse + toque unificados).\n  cv.addEventListener(\"pointerdown\",e=>{const p=pos(e);for(const h of handles){if(Math.hypot(p.x-h.x,p.y-h.y)<14){drag=h;cv.setPointerCapture(e.pointerId);e.preventDefault();return;}}});\n  cv.addEventListener(\"pointermove\",e=>{if(!drag)return;const c=CH[sel],b=c.peq[drag.i],p=pos(e);b.f=clamp(xf(clamp(p.x,0,drag.w),drag.w),20,20000);b.g=clamp((drag.h/2-p.y)/(drag.h/2)*16,-15,15);\n    renderStrip();drawEQ();check();e.preventDefault();});\n  const eqEnd=()=>drag=null;cv.addEventListener(\"pointerup\",eqEnd);cv.addEventListener(\"pointercancel\",eqEnd);\n\n  // meters (placeholder até stems)\n  let t=0;function loop(){t+=0.05;bayChannels().forEach(c=>{const el=$(\"m-\"+c.i);if(el){const base=c.mute?0:(c.fader/100)*(0.4+0.4*Math.abs(Math.sin(t*1.3+c.i)));el.style.height=clamp(base*120,0,100)+\"%\";}});\n    const mm=$(\"m-main\");if(mm){let s=0;CH.forEach(c=>{if(!c.mute)s+=c.fader/100;});mm.style.height=clamp(s/CH.length*(MASTER.fader/100)*160,0,100)+\"%\";}requestAnimationFrame(loop);}\n\n  // missões\n  const M=[\n    {t:''Selecione o <b>Lead Voc</b> (aperte SEL no canal) e ligue o <b>HPF</b> no SuperStrip.'',ok:()=>sel===10&&CH[10].hpfOn},\n    {t:''Na tela, dê <b>brilho na voz</b>: arraste a banda <b>HF</b> para cima (+3 ou mais).'',ok:()=>CH[10].peq[3].g>=3},\n    {t:''Ligue o <b>COMP</b> do Lead Voc (botão COMP) e ajuste o threshold para ~−18.'',ok:()=>CH[10].comp&&Math.abs(CH[10].compThr+18)<=5},\n    {t:''Troque para a camada <b>Ch 13–24</b> e volte — entenda as <b>camadas</b> de fader.'',ok:()=>window.__usedLayerB===true},\n    {t:''Use uma <b>SoftKey de Mute</b> (ex.: Mute Voz) e veja o LED acender.'',ok:()=>Object.keys(skState).some(k=>k.startsWith(\"mg\")&&skState[k])},\n  ];\n  let mi=0;\n  function paintM(){const idx=$(\"mIdx\"),txt=$(\"mTxt\");if(mi>=M.length){idx.textContent=\"🎓\";txt.innerHTML=\"<b>Boa!</b> Você operou a A&H SQ: SEL, SuperStrip, EQ na tela, dinâmica, camadas e SoftKeys. Com os stems, você mixa ouvindo.\";$(\"mSkip\").style.display=\"none\";return;}idx.textContent=\"MISSÃO \"+(mi+1)+\"/\"+M.length;txt.innerHTML=M[mi].t;}\n  function check(){if(layer===\"b\")window.__usedLayerB=true;if(mi>=M.length)return;try{if(M[mi].ok()){mi++;toast(mi>=M.length?\"Console dominado! 🎓\":\"✔\");paintM();}}catch(e){}}\n  let tt;function toast(m){const el=$(\"toast\");el.innerHTML=m;el.classList.add(\"show\");clearTimeout(tt);tt=setTimeout(()=>el.classList.remove(\"show\"),1500);}\n  $(\"mSkip\").onclick=()=>{if(mi<M.length){mi++;paintM();}};\n\n  setupBay();setupStrip();\n  renderLayers();renderBay();renderStrip();renderSK();drawEQ();paintM();requestAnimationFrame(loop);\n\n  // ---- FIT: escala o console para caber na tela (fullscreen e embed) ----\n  function fitConsole(){\n    const el=document.querySelector(\".fit\"); if(!el) return;\n    const vw=window.innerWidth, vh=window.innerHeight;\n    if(vw<760){ el.style.width=\"100%\"; el.style.zoom=\"\"; document.body.style.justifyContent=\"flex-start\"; }\n    else{\n      el.style.width=\"1400px\"; el.style.zoom=\"\";\n      const DW=el.offsetWidth, DH=el.offsetHeight;\n      // Em fullscreen o iframe 16:9 do player fica MAIS ALTO que a tela real. Usamos screen.height\n      // (altura real), não window.innerHeight (altura inflada do iframe), e alinhamos ao topo.\n      const scrH=(window.screen&&screen.height)||vh;\n      const iframeTaller=vh>scrH+8;\n      const visH=Math.min(vh,scrH);\n      const headerAllow=iframeTaller?84:(vh>700?40:6);\n      const effVh=Math.max(240, visH-headerAllow);\n      document.body.style.justifyContent=(iframeTaller||vh>700)?\"flex-start\":\"center\";\n      let s=Math.min((vw-18)/DW, effVh/DH); s=Math.max(0.4, Math.min(s, 2.2));\n      el.style.zoom=s;\n    }\n    try{ drawEQ(); }catch(e){}\n  }\n  window.addEventListener(\"resize\", fitConsole);\n  setTimeout(fitConsole, 50);\n})();\n</script>\n</body>\n</html>\n"}]'::jsonb, updated_at = now() where lesson_id = '5504c000-5011-4a00-9000-0000000000b3' and tipo = 'interactive';

-- pleno-digico (DiGiCo SD)  <-  simuladores/som/digico-sd.html  (27.4 KB)
update public.ai_animations set urls = '[{"html":"<!doctype html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>Simulador — Console DiGiCo SD / Quantum (SMU)</title>\n<style>\n  :root{--bg:#090b0f;--panel:#12151b;--panel2:#0c0f14;--line:#242a34;--ink:#e9edf4;--muted:#8792a3;\n    --dg:#00a0e3;--amber:#f5a623;--green:#39d353;--red:#ff4d4d;--purple:#a855f7;--strip:#0e1218}\n  *{box-sizing:border-box}html,body{margin:0}\n  body{background:var(--bg);color:var(--ink);font-family:\"Space Grotesk\",system-ui,-apple-system,\"Segoe UI\",Roboto,sans-serif;-webkit-font-smoothing:antialiased;padding:6px;user-select:none;overflow-x:hidden;\n    min-height:100vh;display:flex;flex-direction:column;align-items:center;justify-content:center}\n  .fit{width:1560px;flex:0 0 auto}\n  @media(max-width:760px){ body{justify-content:flex-start} .fit{width:100%} }\n  /* iOS/iPad: trava o pan (arraste não vira gesto de sair da tela cheia) em tablet/desktop */\n  @media(min-width:760px){ body,.fit{touch-action:none} }\n  .brandbar{display:flex;align-items:center;gap:12px;background:linear-gradient(180deg,#0f1319,#0a0d12);border:1px solid var(--line);border-radius:10px;padding:8px 14px;margin-bottom:8px}\n  .logo{font-weight:800;font-size:17px;letter-spacing:1px}.logo b{color:var(--dg)}\n  .model{font-size:11px;color:var(--muted);letter-spacing:2px;border:1px solid var(--line);border-radius:5px;padding:3px 8px}\n  .spacer{flex:1}\n  .mission{display:flex;gap:9px;align-items:center;background:#0c0f14;border:1px solid var(--line);border-radius:8px;padding:6px 10px;max-width:58%}\n  .mission .idx{font-size:9.5px;color:var(--dg);font-weight:800;white-space:nowrap}.mission .txt{font-size:11px;line-height:1.2}.mission .txt b{color:var(--dg)}\n  .mission button{font:inherit;font-size:10px;color:var(--muted);background:transparent;border:1px solid var(--line);border-radius:6px;padding:4px 7px;cursor:pointer}\n\n  .console{display:grid;grid-template-columns:150px 1fr;gap:8px}\n  @media(max-width:820px){.console{grid-template-columns:1fr}}\n  .card{background:linear-gradient(180deg,var(--panel),var(--panel2));border:1px solid var(--line);border-radius:11px;padding:9px}\n\n  /* fader bank (left) */\n  .lyr{display:flex;gap:4px;flex-wrap:wrap;margin-bottom:7px}\n  .lb{font:inherit;font-size:9px;font-weight:700;padding:5px 7px;border-radius:6px;border:1px solid var(--line);background:#0c0f14;color:var(--muted);cursor:pointer}\n  .lb.on{background:var(--dg);border-color:var(--dg);color:#02121a}\n  .bank{display:flex;gap:3px;overflow-x:auto}\n  .fst{flex:0 0 40px;display:flex;flex-direction:column;align-items:center;gap:3px}\n  .fnm{width:100%;height:14px;border-radius:2px;font-size:7px;font-weight:800;color:#02121a;display:flex;align-items:center;justify-content:center;overflow:hidden;white-space:nowrap}\n  .fw{display:flex;gap:2px;height:150px}\n  .mt{width:4px;border-radius:2px;background:#05070d;border:1px solid #1a2030;position:relative;overflow:hidden}\n  .mt i{position:absolute;left:0;right:0;bottom:0;height:0%;background:linear-gradient(0deg,var(--green),var(--green) 62%,var(--amber) 85%,var(--red))}\n  .fd{width:20px;position:relative;background:linear-gradient(90deg,#080b10,#0b0f15,#080b10);border-radius:4px;border:1px solid #1a2030;cursor:ns-resize;touch-action:none}\n  .fd .u{position:absolute;left:0;right:0;top:24%;height:1px;background:#333c4a}\n  .cap{position:absolute;left:-3px;right:-3px;height:15px;border-radius:3px;background:linear-gradient(180deg,#eef1f6,#a7b1c2 46%,#586475 54%,#828fa2);border:1px solid #0006;cursor:grab}\n  .cap::after{content:\"\";position:absolute;left:3px;right:3px;top:50%;height:2px;transform:translateY(-50%);background:#05070d;border-radius:2px}\n  .fsel{font:inherit;font-size:7px;font-weight:800;width:100%;padding:2px 0;border-radius:3px;border:1px solid var(--line);background:#0c0f14;color:var(--muted);cursor:pointer}\n  .fsel.on{background:var(--dg);border-color:var(--dg);color:#02121a}\n  .mute{font:inherit;font-size:7px;font-weight:800;width:100%;padding:2px 0;border-radius:3px;border:1px solid var(--line);background:#0c0f14;color:var(--muted);cursor:pointer}\n  .mute.on{background:var(--red);border-color:var(--red);color:#fff}\n  .fdb2{font-size:7px;color:var(--muted)}\n\n  /* main: touchscreen */\n  .screen{background:#04070d;border:1px solid #1a2233;border-radius:10px;padding:8px}\n  .tabs{display:flex;gap:5px;margin-bottom:7px;flex-wrap:wrap}\n  .tab{font:inherit;font-size:10px;font-weight:700;padding:5px 10px;border-radius:6px;border:1px solid var(--line);background:#0a0e14;color:var(--muted);cursor:pointer}\n  .tab.on{background:var(--dg);border-color:var(--dg);color:#02121a}\n  .ov{display:flex;gap:4px;overflow-x:auto}\n  .ovs{flex:0 0 92px;background:#0a0f17;border:1px solid #1a2233;border-radius:7px;padding:5px;cursor:pointer}\n  .ovs.sel{border-color:var(--dg);box-shadow:0 0 0 1px var(--dg) inset}\n  .ovh{height:15px;border-radius:3px;font-size:8.5px;font-weight:800;color:#02121a;display:flex;align-items:center;justify-content:center;white-space:nowrap;overflow:hidden}\n  .ovc{width:100%;height:44px;display:block;margin-top:3px;background:#05090f;border-radius:3px}\n  .ovmeta{display:flex;justify-content:space-between;font-size:7.5px;color:var(--muted);margin-top:3px}\n  .ovdyn{display:flex;gap:3px;margin-top:3px}\n  .ovdyn span{flex:1;font-size:6.5px;text-align:center;padding:2px 0;border-radius:2px;border:1px solid var(--line);color:#3a4658}\n  .ovdyn span.on{color:#02121a}\n  .ovaux{font-size:6.5px;color:var(--muted);margin-top:2px;line-height:1.2}\n\n  /* selected channel */\n  .selrow{display:flex;gap:10px;flex-wrap:wrap;margin-top:8px}\n  .eqbox{flex:1 1 380px;min-width:280px}\n  .selhd{display:flex;align-items:center;gap:8px;margin-bottom:5px}\n  .selhd .chip{width:9px;height:18px;border-radius:2px}.selhd .nm{font-size:13px;font-weight:800}\n  #eq{width:100%;height:150px;background:#03060b;border:1px solid #16202e;border-radius:7px;display:block;touch-action:none}\n  .dyncol{flex:1 1 200px;display:flex;flex-direction:column;gap:7px}\n  .drow{display:flex;gap:8px;align-items:center}.drow label{font-size:10.5px;color:var(--muted);width:70px}\n  .drow input[type=range]{flex:1;accent-color:var(--dg);height:20px}.drow .v{font-size:10px;font-weight:700;width:48px;text-align:right}\n  .tgs{display:flex;gap:5px;flex-wrap:wrap}\n  .tg{font:inherit;font-size:10px;font-weight:800;padding:6px 9px;border-radius:7px;border:1px solid var(--line);background:#0a0e14;color:var(--muted);cursor:pointer}\n  .tg.on{background:var(--green);border-color:var(--green);color:#02120a}.tg.on.eq{background:var(--dg);border-color:var(--dg);color:#02121a}\n\n  /* encoders + macros */\n  .strip2{display:flex;gap:8px;margin-top:8px;flex-wrap:wrap}\n  .encs,.macros{flex:1 1 300px;background:linear-gradient(180deg,#12151b,#0c0f14);border:1px solid var(--line);border-radius:9px;padding:8px}\n  .lbl{font-size:9px;color:var(--muted);letter-spacing:1.4px;text-transform:uppercase;margin-bottom:6px}\n  .encgrid{display:grid;grid-template-columns:repeat(6,1fr);gap:6px}\n  .enc{display:flex;flex-direction:column;align-items:center;gap:2px}\n  .dial{width:34px;height:34px;border-radius:50%;position:relative;cursor:ns-resize;touch-action:none;background:radial-gradient(circle at 50% 30%,#28323f,#12161d 72%);border:2px solid var(--dg);box-shadow:0 0 5px #00a0e355}\n  .dial::after{content:\"\";position:absolute;left:50%;top:3px;width:2px;height:11px;border-radius:2px;background:#eaf6ff;transform-origin:50% 14px;transform:translateX(-50%) rotate(var(--rot,0deg))}\n  .el{font-size:7.5px;color:var(--muted)}.ev{font-size:8px;font-weight:800}\n  .mgrid{display:grid;grid-template-columns:repeat(4,1fr);gap:5px}\n  .mac{font:inherit;font-size:8.5px;font-weight:700;padding:8px 2px;border-radius:6px;border:1px solid var(--line);background:#0a0e14;color:var(--muted);cursor:pointer;text-align:center;line-height:1.1}\n  .mac.on{color:#02121a}\n  .toast{position:fixed;left:50%;bottom:14px;transform:translateX(-50%) translateY(20px);background:#0c0f14;border:1px solid var(--dg);color:var(--ink);padding:9px 15px;border-radius:9px;font-size:12px;opacity:0;transition:.25s;pointer-events:none;z-index:50}\n  .toast.show{opacity:1;transform:translateX(-50%) translateY(0)}.toast b{color:var(--dg)}\n</style>\n</head>\n<body>\n <div class=\"fit\">\n  <div class=\"brandbar\">\n    <div class=\"logo\">Di<b>Gi</b>Co</div>\n    <div class=\"model\">SD / QUANTUM · SIMULADOR SMU</div>\n    <div class=\"spacer\"></div>\n    <div class=\"mission\"><span class=\"idx\" id=\"mIdx\">MISSÃO</span><span class=\"txt\" id=\"mTxt\">—</span><button id=\"mSkip\">Pular</button></div>\n  </div>\n\n  <div class=\"console\">\n    <div class=\"card\">\n      <div class=\"lyr\" id=\"lyr\"></div>\n      <div class=\"bank\" id=\"bank\"></div>\n    </div>\n    <div class=\"card\">\n      <div class=\"screen\">\n        <div class=\"tabs\">\n          <button class=\"tab on\" data-mode=\"overview\">Channel Overview</button>\n          <button class=\"tab\" data-mode=\"channel\">Canal Selecionado</button>\n          <span class=\"spacer\" style=\"flex:1\"></span>\n          <span style=\"font-size:9.5px;color:var(--muted)\" id=\"hint\">toque um canal na tela para selecionar</span>\n        </div>\n        <div id=\"stage\"></div>\n      </div>\n      <div class=\"strip2\">\n        <div class=\"encs\"><div class=\"lbl\">Encoders atribuíveis (canal selecionado)</div><div class=\"encgrid\" id=\"encgrid\"></div></div>\n        <div class=\"macros\"><div class=\"lbl\">Macros / Snapshots</div><div class=\"mgrid\" id=\"mgrid\"></div></div>\n      </div>\n    </div>\n  </div>\n </div>\n  <div class=\"toast\" id=\"toast\"></div>\n\n<script>\n\"use strict\";\n(function(){\n  const $=id=>document.getElementById(id);\n  const clamp=(v,a,b)=>Math.max(a,Math.min(b,v));\n  const NAMES=[\"Kick\",\"Snare\",\"Hats\",\"Tom 1\",\"Tom 2\",\"OH L\",\"OH R\",\"Bass\",\"Gtr\",\"Keys L\",\"Keys R\",\"Lead Vox\",\"Vox 2\",\"BV 1\",\"BV 2\",\"Perc\",\"Sax\",\"Playbk\",\"FX Ret\",\"Talk\",\"Amb L\",\"Amb R\",\"Spare\",\"Spare\"];\n  const COLS=[\"#ff4d4d\",\"#f97316\",\"#f5a623\",\"#eab308\",\"#84cc16\",\"#39d353\",\"#14b8a6\",\"#00a0e3\",\"#3b82f6\",\"#6366f1\",\"#818cf8\",\"#a855f7\",\"#c084fc\",\"#d946ef\",\"#ec4899\",\"#f43f5e\",\"#fb7185\",\"#22d3ee\",\"#4ade80\",\"#60a5fa\",\"#a5b4fc\",\"#c4b5fd\",\"#94a3b8\",\"#94a3b8\"];\n  const CH=NAMES.map((nm,i)=>({i,nm,color:COLS[i],gain:30,hpfOn:i>4,hpf:80,gate:false,gateThr:-40,comp:i===11||i===7,compThr:-20,pan:0,\n    peq:[{f:100,g:0,q:1},{f:400,g:0,q:1.4},{f:2500,g:0,q:1.4},{f:8000,g:0,q:1}],aux1:0,fader:72,mute:false}));\n  const MASTER={fader:78};\n  let sel=11, mode=\"overview\";\n  const LAYERS=[{k:\"in1\",label:\"IN 1-12\",r:[0,12]},{k:\"in2\",label:\"IN 13-24\",r:[12,24]},{k:\"bus\",label:\"BUSSES\"},{k:\"vca\",label:\"VCAs\"}];\n  let layer=\"in1\";\n  const ENC=[{k:\"gain\",label:\"GAIN\",min:-5,max:60,fmt:v=>Math.round(v)},{k:\"hpf\",label:\"HPF\",min:20,max:400,log:true,fmt:v=>Math.round(v)},\n    {k:\"peq0\",label:\"LF\",min:-18,max:18,fmt:v=>(v>0?\"+\":\"\")+Math.round(v)},{k:\"peq1\",label:\"LM\",min:-18,max:18,fmt:v=>(v>0?\"+\":\"\")+Math.round(v)},\n    {k:\"peq2\",label:\"HM\",min:-18,max:18,fmt:v=>(v>0?\"+\":\"\")+Math.round(v)},{k:\"peq3\",label:\"HF\",min:-18,max:18,fmt:v=>(v>0?\"+\":\"\")+Math.round(v)},\n    {k:\"gate\",label:\"GATE\",min:-70,max:0,fmt:v=>Math.round(v)},{k:\"comp\",label:\"COMP\",min:-40,max:0,fmt:v=>Math.round(v)},\n    {k:\"aux1\",label:\"AUX 1\",min:0,max:100,fmt:v=>Math.round(v)},{k:\"pan\",label:\"PAN\",min:-63,max:63,fmt:v=>Math.abs(v)<2?\"C\":(v<0?\"L\":\"R\")+Math.round(Math.abs(v))}];\n  const MAC=[[\"Snapshot ◀\",\"<\"],[\"Snapshot ▶\",\">\"],[\"Store Snap\",\"st\"],[\"Mute Grp 1\",\"mg1\"],[\"Mute Grp 2\",\"mg2\"],[\"Tap Tempo\",\"tap\"],[\"Solo Clr\",\"sc\"],[\"Copy\",\"cp\"],[\"Paste\",\"ps\"],[\"A/B EQ\",\"ab\"],[\"Clear\",\"cl\"],[\"Home\",\"hm\"]];\n  const macState={};\n\n  function encVal(c,k){return{gain:c.gain,hpf:c.hpf,peq0:c.peq[0].g,peq1:c.peq[1].g,peq2:c.peq[2].g,peq3:c.peq[3].g,gate:c.gateThr,comp:c.compThr,aux1:c.aux1,pan:c.pan}[k];}\n  function encSet(c,k,v){if(k===\"gain\")c.gain=v;else if(k===\"hpf\")c.hpf=Math.round(v);else if(k.startsWith(\"peq\"))c.peq[+k.slice(3)].g=v;else if(k===\"gate\")c.gateThr=Math.round(v);else if(k===\"comp\")c.compThr=Math.round(v);else if(k===\"aux1\")c.aux1=Math.round(v);else if(k===\"pan\")c.pan=Math.round(v);}\n  function encRot(e,v){let t;if(e.log)t=(Math.log(v)-Math.log(e.min))/(Math.log(e.max)-Math.log(e.min));else t=(v-e.min)/(e.max-e.min);return -140+t*280;}\n\n  // ---- layers/faders ----\n  function renderLayers(){const el=$(\"lyr\");el.innerHTML=\"\";LAYERS.forEach(l=>{const b=document.createElement(\"button\");b.className=\"lb\"+(l.k===layer?\" on\":\"\");b.textContent=l.label;b.onclick=()=>{layer=l.k;window.__usedLayer=window.__usedLayer||l.k!==\"in1\";renderLayers();renderBank();};el.appendChild(b);});}\n  function bankChans(){const l=LAYERS.find(x=>x.k===layer);if(l&&l.r)return CH.slice(l.r[0],l.r[1]);return CH.slice(0,12).map((c,i)=>({...c,nm:(layer===\"bus\"?\"Bus \"+(i+1):\"VCA \"+(i+1)),ghost:true,i:c.i}));}\n  function renderBank(){const b=$(\"bank\");b.innerHTML=\"\";\n    bankChans().forEach(c=>{const d=document.createElement(\"div\");d.className=\"fst\";\n      d.innerHTML=`<div class=\"fnm\" style=\"background:${c.color}\">${c.nm}</div>\n        <button class=\"fsel ${c.i===sel&&!c.ghost?''on'':''''}\" data-sel=\"${c.i}\">SEL</button>\n        <div class=\"fw\"><div class=\"mt\"><i id=\"m-${c.i}\"></i></div><div class=\"fd\" data-f=\"${c.i}\"><div class=\"u\"></div><div class=\"cap\" id=\"cap-${c.i}\"></div></div></div>\n        <div class=\"fdb2\" id=\"fdb-${c.i}\">${c.fader}</div>\n        <button class=\"mute ${c.mute?''on'':''''}\" data-mute=\"${c.i}\">MUTE</button>`;\n      b.appendChild(d);});\n    const m=document.createElement(\"div\");m.className=\"fst\";\n    m.innerHTML=`<div class=\"fnm\" style=\"background:var(--amber)\">MASTER</div><button class=\"fsel\">SEL</button>\n      <div class=\"fw\"><div class=\"mt\"><i id=\"m-main\"></i></div><div class=\"fd\" data-master=\"1\"><div class=\"u\"></div><div class=\"cap\" id=\"cap-main\"></div></div></div>\n      <div class=\"fdb2\" id=\"fdb-main\">${MASTER.fader}</div><button class=\"mute\">MUTE</button>`;\n    b.appendChild(m);placeCaps();}\n  function placeCaps(){bankChans().forEach(c=>{const cap=$(\"cap-\"+c.i);if(cap)cap.style.bottom=\"calc(\"+c.fader+\"% - 7px)\";});const cm=$(\"cap-main\");if(cm)cm.style.bottom=\"calc(\"+MASTER.fader+\"% - 7px)\";}\n  // Delegação (Pointer Events) no banco de faders — registrada UMA vez, sem vazamento a cada renderBank().\n  let bankFaderDrag=null;\n  function bankFaderSet(f,clientY){const r=f.getBoundingClientRect(),v=Math.round(clamp(1-(clientY-r.top)/r.height,0,1)*100);\n    if(f.dataset.master){MASTER.fader=v;$(\"fdb-main\").textContent=v;$(\"cap-main\").style.bottom=\"calc(\"+v+\"% - 7px)\";}\n    else{const c=CH[+f.dataset.f];c.fader=v;$(\"fdb-\"+c.i).textContent=v;$(\"cap-\"+c.i).style.bottom=\"calc(\"+v+\"% - 7px)\";}check();}\n  function setupBank(){const bank=$(\"bank\");\n    bank.addEventListener(\"pointerdown\",e=>{const f=e.target.closest(\".fd\");if(f){bankFaderDrag=f;bank.setPointerCapture(e.pointerId);bankFaderSet(f,e.clientY);e.preventDefault();}});\n    bank.addEventListener(\"pointermove\",e=>{if(bankFaderDrag){bankFaderSet(bankFaderDrag,e.clientY);e.preventDefault();}});\n    const end=()=>bankFaderDrag=null;bank.addEventListener(\"pointerup\",end);bank.addEventListener(\"pointercancel\",end);\n    bank.addEventListener(\"click\",e=>{\n      const s=e.target.closest(\"[data-sel]\");if(s){sel=+s.dataset.sel;mode=\"channel\";setTab();renderBank();renderStage();renderEncs();return;}\n      const m=e.target.closest(\"[data-mute]\");if(m){const c=CH[+m.dataset.mute];c.mute=!c.mute;m.classList.toggle(\"on\",c.mute);check();return;}\n    });}\n\n  // ---- EQ math ----\n  function bandDb(b,f){const rt=f/b.f;if(b.type===\"hpf\")return f<b.f?-24*Math.log10(b.f/f):0;const bw=b.g/(1+Math.pow((Math.log2(Math.max(0.001,rt)))*b.q*2,2));return bw;}\n  function chDb(c,f){let db=0;if(c.hpfOn&&f<c.hpf)db+=-24*Math.log10(c.hpf/f);c.peq.forEach(b=>db+=bandDb(b,f));return db;}\n  function fx(f,w){const mn=Math.log10(20),mx=Math.log10(20000);return (Math.log10(f)-mn)/(mx-mn)*w;}\n  function xf(x,w){const mn=Math.log10(20),mx=Math.log10(20000);return Math.pow(10,mn+(x/w)*(mx-mn));}\n\n  // ---- stage (overview / channel) ----\n  function renderStage(){const s=$(\"stage\");if(mode===\"overview\"){s.innerHTML=''<div class=\"ov\" id=\"ov\"></div>'';renderOverview();}else{renderChannel();}}\n  function renderOverview(){const ov=$(\"ov\");ov.innerHTML=\"\";\n    CH.slice(0,12).forEach(c=>{const d=document.createElement(\"div\");d.className=\"ovs\"+(c.i===sel?\" sel\":\"\");d.dataset.i=c.i;\n      d.innerHTML=`<div class=\"ovh\" style=\"background:${c.color}\">${c.nm}</div><canvas class=\"ovc\" id=\"ovc-${c.i}\"></canvas>\n        <div class=\"ovmeta\"><span>G ${Math.round(c.gain)}</span><span>${c.pan===0?\"C\":(c.pan<0?\"L\":\"R\")+Math.abs(c.pan)}</span></div>\n        <div class=\"ovdyn\"><span class=\"${c.hpfOn?''on'':''''}\" style=\"${c.hpfOn?''background:var(--amber)'':''''}\">HPF</span><span class=\"${c.gate?''on'':''''}\" style=\"${c.gate?''background:var(--green)'':''''}\">GT</span><span class=\"${c.comp?''on'':''''}\" style=\"${c.comp?''background:var(--dg)'':''''}\">CP</span></div>\n        <div class=\"ovaux\">Aux1: ${c.aux1}</div>`;\n      ov.appendChild(d);});\n    ov.querySelectorAll(\".ovs\").forEach(el=>el.onclick=()=>{sel=+el.dataset.i;renderOverview();renderEncs();drawOVcurves();});\n    drawOVcurves();\n  }\n  function drawOVcurves(){CH.slice(0,12).forEach(c=>{const cv=$(\"ovc-\"+c.i);if(!cv)return;const w=cv.clientWidth,h=cv.clientHeight;cv.width=w*2;cv.height=h*2;const x=cv.getContext(\"2d\");x.setTransform(2,0,0,2,0,0);x.clearRect(0,0,w,h);\n    x.strokeStyle=\"#16202e\";x.beginPath();x.moveTo(0,h/2);x.lineTo(w,h/2);x.stroke();\n    x.beginPath();for(let px=0;px<=w;px+=2){const db=chDb(c,xf(px,w));const y=h/2-clamp(db,-15,15)/15*h/2;px?x.lineTo(px,y):x.moveTo(px,y);}x.strokeStyle=c.color;x.lineWidth=1.6;x.stroke();});}\n\n  // selected channel EQ\n  let handles=[],drag=null;\n  function renderChannel(){const c=CH[sel];const s=$(\"stage\");\n    s.innerHTML=`<div class=\"selrow\"><div class=\"eqbox\"><div class=\"selhd\"><span class=\"chip\" style=\"background:${c.color}\"></span><span class=\"nm\">${c.nm}</span><span style=\"font-size:9.5px;color:var(--muted);margin-left:6px\">EQ 4 bandas — arraste as bolinhas</span></div><canvas id=\"eq\"></canvas></div>\n      <div class=\"dyncol\">\n        <div class=\"tgs\"><button class=\"tg eq\" id=\"tHpf\">HPF</button><button class=\"tg\" id=\"tGate\">GATE</button><button class=\"tg\" id=\"tComp\">COMP</button></div>\n        <div class=\"drow\"><label>Gain</label><input type=\"range\" id=\"sGain\" min=\"-5\" max=\"60\" value=\"${c.gain}\"><span class=\"v\" id=\"vGain\">${Math.round(c.gain)}</span></div>\n        <div class=\"drow\"><label>Gate thr</label><input type=\"range\" id=\"sGate\" min=\"-70\" max=\"0\" value=\"${c.gateThr}\"><span class=\"v\" id=\"vGate\">${c.gateThr}</span></div>\n        <div class=\"drow\"><label>Comp thr</label><input type=\"range\" id=\"sComp\" min=\"-40\" max=\"0\" value=\"${c.compThr}\"><span class=\"v\" id=\"vComp\">${c.compThr}</span></div>\n        <div class=\"drow\"><label>Aux 1</label><input type=\"range\" id=\"sAux\" min=\"0\" max=\"100\" value=\"${c.aux1}\"><span class=\"v\" id=\"vAux\">${c.aux1}</span></div>\n        <div class=\"drow\"><label>Pan</label><input type=\"range\" id=\"sPan\" min=\"-63\" max=\"63\" value=\"${c.pan}\"><span class=\"v\" id=\"vPan\">${c.pan}</span></div>\n      </div></div>`;\n    $(\"tHpf\").classList.toggle(\"on\",c.hpfOn);$(\"tGate\").classList.toggle(\"on\",c.gate);$(\"tComp\").classList.toggle(\"on\",c.comp);\n    $(\"tHpf\").onclick=()=>{c.hpfOn=!c.hpfOn;$(\"tHpf\").classList.toggle(\"on\",c.hpfOn);drawEQ();renderEncs();check();};\n    $(\"tGate\").onclick=()=>{c.gate=!c.gate;$(\"tGate\").classList.toggle(\"on\",c.gate);check();};\n    $(\"tComp\").onclick=()=>{c.comp=!c.comp;$(\"tComp\").classList.toggle(\"on\",c.comp);check();};\n    const bind=(idr,idv,set,suf)=>{$(idr).oninput=()=>{set(c,+$(idr).value);$(idv).textContent=$(idr).value+(suf||\"\");drawEQ();renderEncs();check();};};\n    bind(\"sGain\",\"vGain\",(c,v)=>c.gain=v);bind(\"sGate\",\"vGate\",(c,v)=>c.gateThr=v);bind(\"sComp\",\"vComp\",(c,v)=>c.compThr=v);bind(\"sAux\",\"vAux\",(c,v)=>c.aux1=v);bind(\"sPan\",\"vPan\",(c,v)=>c.pan=v);\n    setupEQ();drawEQ();\n  }\n  let cv2,cx2;\n  // O canvas #eq é recriado a cada renderChannel; setupEQ só atualiza as refs.\n  function setupEQ(){cv2=$(\"eq\");cx2=cv2.getContext(\"2d\");}\n  function eqPosP(el,e){const r=el.getBoundingClientRect();return{x:e.clientX-r.left,y:e.clientY-r.top};}\n  // Delegação (Pointer Events) no #stage — registrada UMA vez. As alças do EQ funcionam em mouse e toque.\n  function setupStageEQ(){const stage=$(\"stage\");\n    stage.addEventListener(\"pointerdown\",e=>{if(mode!==\"channel\"||!cv2)return;if(!e.target.closest(\"#eq\"))return;const p=eqPosP(cv2,e);\n      for(const h of handles){if(Math.hypot(p.x-h.x,p.y-h.y)<15){drag=h;stage.setPointerCapture(e.pointerId);e.preventDefault();return;}}});\n    stage.addEventListener(\"pointermove\",e=>{if(!drag||mode!==\"channel\"||!cv2)return;const c=CH[sel],b=c.peq[drag.i],p=eqPosP(cv2,e);\n      b.f=clamp(xf(clamp(p.x,0,drag.w),drag.w),20,20000);b.g=clamp((drag.h/2-p.y)/(drag.h/2)*18,-18,18);drawEQ();renderEncs();check();e.preventDefault();});\n    const end=()=>drag=null;stage.addEventListener(\"pointerup\",end);stage.addEventListener(\"pointercancel\",end);}\n  // Redraw coalescing (iPad): dragging an EQ handle / gate / comp encoder fires many pointermove\n  // events; each drawEQ() reallocates and repaints the canvas. Doing that per event starves the\n  // main thread on iPad so controls lag. drawEQ() now coalesces to one repaint per animation frame\n  // (rAF), with a setTimeout safety-net in case requestAnimationFrame is throttled.\n  let _eqReq=0,_eqTo=0;\n  function _flushEQ(){ if(_eqReq){cancelAnimationFrame(_eqReq);_eqReq=0;} if(_eqTo){clearTimeout(_eqTo);_eqTo=0;} renderEQ(); }\n  function drawEQ(){ if(_eqReq||_eqTo)return; _eqReq=requestAnimationFrame(_flushEQ); _eqTo=setTimeout(_flushEQ,60); }\n  function renderEQ(){if(!cv2)return;const c=CH[sel],rr=cv2.getBoundingClientRect(),w=rr.width,h=rr.height;if(w<2)return;cv2.width=w*2;cv2.height=h*2;cx2.setTransform(2,0,0,2,0,0);cx2.clearRect(0,0,w,h);\n    cx2.strokeStyle=\"#12202e\";cx2.fillStyle=\"#3a4a5e\";cx2.font=\"9px system-ui\";cx2.textAlign=\"center\";[100,1000,10000].forEach(f=>{const x=fx(f,w);cx2.beginPath();cx2.moveTo(x,0);cx2.lineTo(x,h);cx2.stroke();cx2.fillText(f>=1000?f/1000+\"k\":f,x,h-1);});\n    for(let d=-12;d<=12;d+=6){const y=h/2-d/18*h/2;cx2.strokeStyle=d===0?\"#243447\":\"#101c28\";cx2.beginPath();cx2.moveTo(0,y);cx2.lineTo(w,y);cx2.stroke();}\n    cx2.beginPath();for(let px=0;px<=w;px+=2){const y=h/2-clamp(chDb(c,xf(px,w)),-16,16)/18*h/2;px?cx2.lineTo(px,y):cx2.moveTo(px,y);}cx2.strokeStyle=c.color;cx2.lineWidth=2.2;cx2.stroke();cx2.lineTo(w,h/2);cx2.lineTo(0,h/2);cx2.closePath();cx2.fillStyle=c.color+\"16\";cx2.fill();\n    handles=[];const HN=[\"LF\",\"LM\",\"HM\",\"HF\"];c.peq.forEach((b,i)=>{const x=fx(b.f,w),y=h/2-clamp(b.g,-16,16)/18*h/2;cx2.fillStyle=\"#00a0e3\";cx2.beginPath();cx2.arc(x,y,6,0,7);cx2.fill();cx2.fillStyle=\"#02121a\";cx2.font=\"700 7px system-ui\";cx2.fillText(HN[i],x,y+2);handles.push({x,y,i,w,h});});}\n\n  // encoders + macros\n  function renderEncs(){const g=$(\"encgrid\");g.innerHTML=\"\";const c=CH[sel];\n    ENC.forEach(e=>{const el=document.createElement(\"div\");el.className=\"enc\";el.innerHTML=`<div class=\"dial\" data-k=\"${e.k}\"></div><div class=\"el\">${e.label}</div><div class=\"ev\" id=\"ev-${e.k}\"></div>`;g.appendChild(el);});\n    ENC.forEach(e=>{const d=g.querySelector(''.dial[data-k=\"''+e.k+''\"]'');d.style.setProperty(\"--rot\",encRot(e,clamp(encVal(c,e.k),e.min,e.max))+\"deg\");$(\"ev-\"+e.k).textContent=e.fmt(encVal(c,e.k));});\n  }\n  // Delegação (Pointer Events) nos encoders — registrada UMA vez, sem vazamento a cada renderEncs().\n  let encDrag=null,encLastY=0;\n  function setupEncs(){const g=$(\"encgrid\");\n    g.addEventListener(\"pointerdown\",e=>{const d=e.target.closest(\".dial\");if(!d)return;const en=ENC.find(x=>x.k===d.dataset.k);if(!en)return;\n      encDrag={el:d,k:d.dataset.k,e:en};encLastY=e.clientY;g.setPointerCapture(e.pointerId);e.preventDefault();});\n    g.addEventListener(\"pointermove\",e=>{if(!encDrag)return;const dy=encLastY-e.clientY;encLastY=e.clientY;const cc=CH[sel],en=encDrag.e,k=encDrag.k;\n      encSet(cc,k,clamp(encVal(cc,k)+dy*(en.max-en.min)/150,en.min,en.max));encDrag.el.style.setProperty(\"--rot\",encRot(en,encVal(cc,k))+\"deg\");\n      const ev=$(\"ev-\"+k);if(ev)ev.textContent=en.fmt(encVal(cc,k));if(mode===\"channel\")drawEQ();check();e.preventDefault();});\n    const end=()=>encDrag=null;g.addEventListener(\"pointerup\",end);g.addEventListener(\"pointercancel\",end);}\n  function renderMacros(){const g=$(\"mgrid\");g.innerHTML=\"\";MAC.forEach(([lbl,k])=>{const b=document.createElement(\"button\");b.className=\"mac\"+(macState[k]?\" on\":\"\");if(macState[k])b.style.background=k.startsWith(\"mg\")?\"#ff4d4d\":\"#00a0e3\";b.textContent=lbl;b.onclick=()=>{macState[k]=!macState[k];if(k===\"tap\")macState[k]=false;renderMacros();if(k.startsWith(\"mg\"))toast(\"Mute Group \"+lbl);check();};g.appendChild(b);});}\n\n  document.querySelectorAll(\".tab[data-mode]\").forEach(t=>t.onclick=()=>{mode=t.dataset.mode;setTab();renderStage();});\n  function setTab(){document.querySelectorAll(\".tab[data-mode]\").forEach(t=>t.classList.toggle(\"on\",t.dataset.mode===mode));}\n\n  // meters\n  let t=0;function loop(){t+=0.05;bankChans().forEach(c=>{const el=$(\"m-\"+c.i);if(el){const b=c.mute?0:(c.fader/100)*(0.4+0.4*Math.abs(Math.sin(t*1.3+c.i)));el.style.height=clamp(b*120,0,100)+\"%\";}});\n    const mm=$(\"m-main\");if(mm){let s=0;CH.forEach(c=>{if(!c.mute)s+=c.fader/100;});mm.style.height=clamp(s/CH.length*(MASTER.fader/100)*160,0,100)+\"%\";}requestAnimationFrame(loop);}\n\n  const M=[\n    {t:''Toque o canal <b>Lead Vox</b> na tela (Channel Overview) para selecioná-lo.'',ok:()=>sel===11&&mode===\"channel\"},\n    {t:''Na tela do canal, ligue o <b>HPF</b> e dê <b>brilho</b> (arraste a banda HF acima de +3).'',ok:()=>CH[11].hpfOn&&CH[11].peq[3].g>=3},\n    {t:''Ligue o <b>COMP</b> do Lead Vox e ajuste o threshold para ~−18.'',ok:()=>CH[11].comp&&Math.abs(CH[11].compThr+18)<=5},\n    {t:''Mande o Lead Vox para o <b>AUX 1</b> (monitor) acima de 30.'',ok:()=>CH[11].aux1>=30},\n    {t:''Troque de <b>camada</b> (ex.: IN 13-24) para entender os bancos de fader.'',ok:()=>window.__usedLayer===true},\n  ];\n  let mi=0;\n  function paintM(){const idx=$(\"mIdx\"),txt=$(\"mTxt\");if(mi>=M.length){idx.textContent=\"🎓\";txt.innerHTML=\"<b>Boa!</b> Você operou a DiGiCo: overview, canal na tela, EQ, dinâmica, aux, encoders, camadas e macros.\";$(\"mSkip\").style.display=\"none\";return;}idx.textContent=\"MISSÃO \"+(mi+1)+\"/\"+M.length;txt.innerHTML=M[mi].t;}\n  function check(){if(mi>=M.length)return;try{if(M[mi].ok()){mi++;toast(mi>=M.length?\"Console dominado! 🎓\":\"✔\");paintM();}}catch(e){}}\n  let tt;function toast(m){const el=$(\"toast\");el.innerHTML=m;el.classList.add(\"show\");clearTimeout(tt);tt=setTimeout(()=>el.classList.remove(\"show\"),1500);}\n  $(\"mSkip\").onclick=()=>{if(mi<M.length){mi++;paintM();}};\n\n  setupBank();setupEncs();setupStageEQ();\n  renderLayers();renderBank();renderStage();renderEncs();renderMacros();paintM();requestAnimationFrame(loop);\n\n  // ---- FIT: escala o console para caber na tela (fullscreen e embed) ----\n  function fitConsole(){\n    const el=document.querySelector(\".fit\"); if(!el) return;\n    const vw=window.innerWidth, vh=window.innerHeight;\n    if(vw<760){ el.style.width=\"100%\"; el.style.zoom=\"\"; document.body.style.justifyContent=\"flex-start\"; }\n    else{\n      el.style.width=\"1560px\"; el.style.zoom=\"\";\n      const DW=el.offsetWidth, DH=el.offsetHeight;\n      // Em fullscreen o iframe 16:9 do player fica MAIS ALTO que a tela real. Usamos screen.height\n      // (altura real), não window.innerHeight (altura inflada do iframe), e alinhamos ao topo.\n      const scrH=(window.screen&&screen.height)||vh;\n      const iframeTaller=vh>scrH+8;\n      const visH=Math.min(vh,scrH);\n      const headerAllow=iframeTaller?84:(vh>700?40:6);\n      const effVh=Math.max(240, visH-headerAllow);\n      document.body.style.justifyContent=(iframeTaller||vh>700)?\"flex-start\":\"center\";\n      let s=Math.min((vw-18)/DW, effVh/DH); s=Math.max(0.4, Math.min(s, 2.2));\n      el.style.zoom=s;\n    }\n    try{ drawOVcurves(); }catch(e){}\n    try{ drawEQ(); }catch(e){}\n  }\n  window.addEventListener(\"resize\", fitConsole);\n  setTimeout(fitConsole, 50);\n})();\n</script>\n</body>\n</html>\n"}]'::jsonb, updated_at = now() where lesson_id = '5504c000-5011-4a00-9000-0000000000b4' and tipo = 'interactive';

